INSERT INTO `media` (`id`, `title`, `description`, `rating`, `image_url`, `genre_id`, `year_id`, `country_id`, `type_id`) VALUES
(2, 'Голодные игры', 'Будущее. Деспотичное государство ежегодно устраивает показательные игры на выживание, за которыми в прямом эфире следит весь мир. Жребий участвовать в Играх выпадает юной Китнисс и тайно влюбленному в нее Питу. Они знакомы с детства, но теперь должны стать врагами. Ведь по нерушимому закону Голодных игр победить может только один из 24 участников. Судьям не важно, кто выиграет, главное — зрелище. И на этот раз зрелище будет незабываемым.', 7.3, 'https://kinopoiskapiunofficial.tech/images/posters/kp/468581.jpg', 2, 2, 2, 1),
(3, 'Кентавр', 'Таксист Саша предпочитает работать по ночам, когда нет пробок и, как он считает, люди раскрываются с другой стороны. Очередная его клиентка — эскортница Лиза — проникается к парню симпатией и просит покатать её по делам. Ночь только начинается, и, кажется, обоим есть, что скрывать.', 7.5, 'https://kinopoiskapiunofficial.tech/images/posters/kp/5235968.jpg', 3, 1, 1, 1),
(4, 'Два, три, демон, приди!', 'Среди подростков небольшого австралийского городка набирает популярность необычное развлечение. Нужно зажечь свечу, пожать жутковатую керамическую руку, произнести «Поговори со мной» — и тогда можно увидеть призрака и даже ненадолго впустить его в себя. Несмотря на то что прежний владелец артефакта покончил с собой, ребята на вечеринках радостно балуются необычными способностями руки, пока одним из вызванных призраков не оказывается мама 17-летней Мии, умершая два года назад.', 6.5, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4948328.jpg', 4, 3, 3, 1),
(5, 'Казино', 'Никто не может сравниться с Сэмом Ротстином. Никто не умеет зарабатывать деньги, как он. Никто не умеет работать так самоотверженно и аккуратно, как трудяга Сэм. За свои неоспоримые достоинства Ротстин получил кличку Ас. И именно поэтому боссы мафии решили поручить Асу заправлять огромным шикарным казино в Лас-Вегасе. А чтобы Сэму никто не мешал работать, мафиози отправили вслед за Асом друга детства Ротстина - Никки Санторо, отпетого бандита и безжалостного головореза.', 8.1, 'https://kinopoiskapiunofficial.tech/images/posters/kp/2494.jpg', 5, 4, 4, 1),
(6, 'Человек-паук: Паутина вселенных', 'После воссоединения с Гвен Стейси дружелюбный сосед Человек-Паук попадает из Бруклина в Мультивселенную, где встречает команду Паучков, защищающих само её существование. Пытаясь справиться с новой угрозой, Майлз сталкивается с Пауками из других вселенных. Настаёт момент, когда ему необходимо решить, что значит быть героем, спасающим тех, кого любишь больше всего.', 8.5, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1219177.jpg', 6, 1, 2, 1),
(7, 'Капитан Марвел 2', 'Кэрол Дэнверс обретает свою отнятую тиранами Крии личность и мстит Высшему Разуму. Это приводят к тому, что Кэрол взваливает на свои плечи бремя дестабилизированной Вселенной. Когда она проходит через червоточину, которая должна вывести её на революционера из числа Крии, её силы переплетаются со способностями Камалы Хан, известной как Мисс Марвел, а также с племянницей Моникой Рамбо. Девушкам придётся научиться работать в команде, чтобы спасти Вселенную.', 5.6, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1287544.jpg', 7, 1, 2, 1),
(8, 'Интерстеллар', 'Когда засуха, пыльные бури и вымирание растений приводят человечество к продовольственному кризису, коллектив исследователей и учёных отправляется сквозь червоточину (которая предположительно соединяет области пространства-времени через большое расстояние) в путешествие, чтобы превзойти прежние ограничения для космических путешествий человека и найти планету с подходящими для человечества условиями.', 8.6, 'https://kinopoiskapiunofficial.tech/images/posters/kp/258687.jpg', 8, 5, 5, 1),
(9, 'Жанна Дюбарри', 'Жанна Вобернье, женщина из низшего сословия, выбивается из нищеты при помощи женских чар. Ее покровитель, граф Дюбарри, разбогатевший благодаря любовным интригам Жанны, желает представить ее королю и организует свидание через влиятельного герцога де Ришелье. Встреча выходит далеко за рамки его ожиданий — Жанна влюбляет в себя Людовика XV с первого взгляда своей непосредственностью. \nПосле знакомства с куртизанкой у короля вновь пробуждается вкус к жизни — настолько сильно, что он больше не может жить без Жанны и делает её своей официальной фавориткой. Однако, никто не желает видеть во главе двора простолюдинку, правящую королем.', 7.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4833824.jpg', 9, 1, 6, 1),
(10, 'Фаворитка', 'Начало XVIII века. Идет война Англии с Францией. Тем не менее, жизнь в королевстве продолжается. Трон занимает болезненная королева Анна, и страной фактически руководит её близкая подруга леди Сара Мальборо. Когда во дворце появляется девушка Эбигейл, родственница леди Сары, та сначала определяет её работать на кухне. Но вскоре новенькая удачно находит лекарство для больной подагрой королевы, тогда Сара решает сделать её своей служанкой. Для Эбигейл это — шанс вернуться к своим аристократическим корням, и лучше не вставать у неё на пути.', 7.3, 'https://kinopoiskapiunofficial.tech/images/posters/kp/938644.jpg', 10, 6, 7, 1),
(11, '1+1', 'Пострадав в результате несчастного случая, богатый аристократ Филипп нанимает в помощники человека, который менее всего подходит для этой работы, – молодого жителя предместья Дрисса, только что освободившегося из тюрьмы. Несмотря на то, что Филипп прикован к инвалидному креслу, Дриссу удается привнести в размеренную жизнь аристократа дух приключений.', 8.8, 'https://kinopoiskapiunofficial.tech/images/posters/kp/535341.jpg', 11, 7, 6, 1),
(12, 'Барби', 'Самая обыкновенная стереотипная Барби живёт в великолепном розовом Барбиленде, и каждый её день идеален. Она меняет наряды, загорает на пляже, проводит время с другими Барби, день заканчивается шумной вечеринкой с танцами, и в этой позитивной кутерьме с блёстками влюблённый Кен — всего лишь приложение к Барби. Однажды куклу посещают мысли о смерти, и её сделанные под туфли с каблуками ноги вдруг становятся плоскими. Чтобы разобраться в происходящем и вернуть привычный пластмассовый мир, Барби придётся отправиться в мир реальный и найти там свою девочку-хозяйку. За ней увязывается не мыслящий жизни без своего кумира Кен.', 6.6, 'https://kinopoiskapiunofficial.tech/images/posters/kp/478052.jpg', 12, 1, 8, 1),
(14, 'Джентльмены', 'Один ушлый американец ещё со студенческих лет приторговывал наркотиками, а теперь придумал схему нелегального обогащения с использованием поместий обедневшей английской аристократии и очень неплохо на этом разбогател. Другой пронырливый журналист приходит к Рэю, правой руке американца, и предлагает тому купить киносценарий, в котором подробно описаны преступления его босса при участии других представителей лондонского криминального мира — партнёра-еврея, китайской диаспоры, чернокожих спортсменов и даже русского олигарха.', 8.6, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1143242.jpg', 14, 8, 8, 1),
(16, 'Отпуск по обмену', 'Айрис Симпкинс, автор популярной свадебной колонки в лондонской «Daily Telegraph», живет в очаровательном коттедже в английской провинции. Она влюблена в мужчину, который любит другую. Далеко от нее в Южной Калифорнии живет Аманда Вудс, владелица процветающего рекламного агентства, занимающегося созданием роликов для фильмов. Она вдруг обнаруживает, что любимый человек ей изменяет.\n\nДве незнакомые друг с другом женщины, живущие на расстоянии 10 000 километров друг от друга, оказываются в схожей ситуации. И они находят друг друга. В Интернете, на сайте обмена жильем на время отпуска. Перед Рождеством Айрис и Аманда решают отдохнуть от своих проблем, договорившись поменяться континентами и пожить друг у друга в течение двух недель. Айрис переезжает в дом Аманды в солнечной Калифорнии, а Аманда приезжает в засыпанную снегом английскую провинцию…', 7.8, 'https://kinopoiskapiunofficial.tech/images/posters/kp/104927.jpg', 16, 9, 2, 1),
(17, 'Элементарно', 'В Элемент-Сити обитатели огня, воды, земли и воздуха живут вместе. У сильной и вспыльчивой Эмбер завязывается дружба с расслабленным, плывущим по течению Уэйдом — дружба, которая бросит вызов её представлениям о мире вокруг.', 7.7, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4889667.jpg', 17, 1, 2, 1),
(18, 'Призраки в Венеции', 'Венеция. Вышедший на пенсию Эркюль Пуаро неохотно посещает спиритический сеанс, во время которого один из гостей оказывается убит. Бывший детектив берется за расследование.', 6.7, 'https://kinopoiskapiunofficial.tech/images/posters/kp/5135249.jpg', 18, 1, 10, 1),
(19, '57 секунд', 'Техноблогер Франклин случайно предотвращает покушение на известного визионера и инновационного гуру, достигшего невероятных успехов в сфере медицины. Подобрав оброненное им кольцо, молодой человек обнаруживает, что оно дает своему носителю возможность переноситься в прошлое на 57 секунд. Франклин решает воспользоваться находкой и с помощью чудо-кольца отомстить тем, кого он считает виновными в смерти своей сестры.', 6.7, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4946926.jpg', 19, 1, 2, 1),
(20, 'Хранители', 'Действие картины разворачивается в параллельной реальности, в Америке 1985 года. В этом мире супергерои стали частью повседневной жизни общества, а Часы Судного Дня, застыв в пяти минутах от полуночи, отсчитывают время до столкновения ведущих мировых держав. После убийства одного из своих прежних коллег Роршах – супергерой, никогда не снимающий маски, -  полон решимости свершить суд Линча. \n\nОн начинает расследование заговора, призванного уничтожить или дискредитировать всех супергероев прошлого и настоящего. Он собирает своих соратников – отставной легион борцов с преступностью, но лишь один из них обладает подлинной силой. Постепенно Роршах осознает пугающий масштаб заговора, связанного с общим прошлым героев и сулящего катастрофические последствия в будущем. Они хранят наш покой, но кто охранит нас от Хранителей?', 7.7, 'https://kinopoiskapiunofficial.tech/images/posters/kp/252641.jpg', 20, 10, 2, 1),
(23, 'По щучьему велению', 'Если ты идешь на рыбалку — будь готов к тому, что вытянешь рыбу своей мечты, волшебную Щуку, которая может исполнить три любых твоих желания. Только Емеля спустил два желания на ветер, а третье решил приберечь. Поэтому, чтобы добиться руки царской дочери Анфисы, придется ему действовать без волшебной силы, самому. А помогать ему будет Щука, которая без своей шкурки предстает обычной девушкой Василисой. Вместе им предстоит найти скатерть-самобранку, встретиться с Котом Баюном, отправиться в мрачное царство Кощея и понять, что настоящее чудо — это быть с тем, кого любишь.', 7.3, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4959134.jpg', 22, 1, 1, 1),
(24, 'Оппенгеймер', 'История жизни американского физика Роберта Оппенгеймера, который стоял во главе первых разработок ядерного оружия.', 8.5, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4664634.jpg', 9, 1, 8, 1),
(25, 'Голодные игры: Баллада о змеях и певчих птицах', 'До того, как стать деспотичным президентом Панэма, молодой Кориолан Сноу был последней надеждой для своего увядающего рода — некогда великой династии, впавшей в немилость послевоенного Капитолия. Накануне десятых ежегодных Голодных игр Сноу назначают наставником Люси Грей Бэйрд — трибута дистрикта 12. Постепенно девушка привлекает все больше внимание Панэма, становясь фавориткой грядущего соревнования. Готовый на все, чтобы вернуть своей семье былое величие, Сноу решает обратить ситуацию с Люси в свою пользу. Начинается гонка со временем, которая покажет, кто певчая птица, а кто — змея.', 7.4, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1289334.jpg', 23, 1, 2, 1),
(27, 'Повелитель ветра', 'Знаменитый российский путешественник Федор Конюхов, за плечами которого покорение земных полюсов, океанов и высочайших вершин, отправляется в новое, свое самое опасное путешествие. Ему предстоит обогнуть Землю на воздушном шаре в полном одиночестве. Полет готовит целая команда, но нельзя предвидеть все опасности, которые ждут путешественника в экстремальных условиях. Конюхов попадает в ураган — без связи, без сна, почти без воздуха он должен идти только вперед, чтобы вернуться к тем, кого любит.', 7.3, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1253841.jpg', 25, 1, 1, 1),
(30, 'Убийцы цветочной луны', 'Вскоре после Первой мировой Эрнест Беркхарт, отслуживший во Франции поваром, приезжает искать удачи в Оклахому, где находится крупная резервация индейцев племени осейдж. В тех краях живет его дядя Уильям Хэйл, который носит прозвище Король — он землевладелец, скотопромышленник, друг индейцев и большой человек. Король убеждает Эрнеста посвататься к Молли Кайл, молодой женщине из зажиточной индейской семьи. Идея состоит в том, чтобы земельные права этой семьи со временем перешли к Беркхарту (читай к Хэйлу), а для этого всего лишь должны умереть мама Молли, её сёстры и она сама.', 7.4, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1077781.jpg', 28, 1, 2, 1),
(31, 'Баба Яга спасает мир', 'Любопытный школьник Сенька каким-то чудом попадает в сказочный древний лес. Он скрыт от людских глаз мощным заклятием Бабы Яги, призванным защитить людей и весь мир от дремлющих там темных сил. В лесу явно творится что-то неладное. Тревожные сигналы возвещают, что заклятие больше не действует, и пробуждение зловещего волшебства и давно поверженных врагов — лишь вопрос времени. Чтобы наложить заклятие снова, Яга вынуждена отправиться в современный город на поиск мощнейшего оружия волшебников, дивноцвета. Там ее ожидает встреча с множеством причуд современного мира, а в темном подземелье уже тысячу лет прячется жаждущий мести Кощей Бессмертный, ведь именно Яга помогла одолеть его много веков назад.', 7.3, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4536580.jpg', 29, 1, 1, 1),
(32, 'Гарри Поттер и философский камень', 'Жизнь десятилетнего Гарри Поттера нельзя назвать сладкой: родители умерли, едва ему исполнился год, а от дяди и тёти, взявших сироту на воспитание, достаются лишь тычки да подзатыльники. Но в одиннадцатый день рождения Гарри всё меняется. Странный гость, неожиданно появившийся на пороге, приносит письмо, из которого мальчик узнаёт, что на самом деле он - волшебник и зачислен в школу магии под названием Хогвартс. А уже через пару недель Гарри будет мчаться в поезде Хогвартс-экспресс навстречу новой жизни, где его ждут невероятные приключения, верные друзья и самое главное — ключ к разгадке тайны смерти его родителей.', 8.3, 'https://kinopoiskapiunofficial.tech/images/posters/kp/689.jpg', 30, 11, 8, 1),
(33, 'Телохранитель на фрилансе', 'Бывший спецназовец променял полную экшна жизнь на серые будни в офисе. С неохотой он все-таки соглашается на простую, но высокооплачиваемую подработку — сопровождать журналистку в командировке, пока та берет интервью у обаятельного диктатора. Однако на месте они внезапно попадают в эпицентр полномасштабного переворота. Теперь, чтобы спасти всех, телохранителю на фрилансе пригодятся все его боевые навыки, ведь предоплата уже внесена.', 6.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4850165.jpg', 31, 1, 2, 1),
(34, 'Пять ночей с Фредди', 'Пытаясь сохранить опекунство над сестрёнкой, Майк Шмидт устраивается работать ночным охранником в «Freddy Fazbear’s» — некогда популярный, но ныне закрытый семейный развлекательный центр. Несколько лет назад, когда Майк был ещё ребёнком, его младшего брата похитил неизвестный, и к этому событию парень снова и снова возвращается во сне, пытаясь вспомнить лицо похитителя. На новой работе в его снах появляются новые подробности — кажется, это место хранит зловещие тайны.', 5.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/952158.jpg', 32, 1, 2, 1),
(36, 'Один дома', 'Американское семейство отправляется из Чикаго в Европу, но в спешке сборов бестолковые родители забывают дома... одного из своих детей. Юное создание, однако, не теряется и демонстрирует чудеса изобретательности. И когда в дом залезают грабители, им приходится не раз пожалеть о встрече с милым крошкой.', 8.3, 'https://kinopoiskapiunofficial.tech/images/posters/kp/8124.jpg', 34, 12, 2, 1),
(39, 'Создатель', 'Повсеместное применение искусственного интеллекта привело к тому, что в Лос-Анджелесе произошёл ядерный взрыв. С тех пор коллективный Запад во главе с США ведёт непримиримую войну на уничтожение ИИ, но блок стран Юго-Восточной Азии — Новая Азия — живёт в гармонии с роботами и сдаваться не собирается. В 2065 году спецназовец Джошуа находился в тылу врага, с целью отыскать главного создателя ИИ, известного под именем Нирмата, и втёрся в доверие настолько, что женился на учёной Майе и с нетерпением ждал рождения ребёнка. Но во время нападения американцев и ракетного удара главной надежды Запада на победу — военной орбитальной станции NOMAD — его жена погибла.\nПять лет спустя Джошуа вынужден вернуться в Новую Азию, чтобы помочь отряду военных найти Нирмату и его лабораторию, где, по данным разведки, разработано новейшее оружие, способное уничтожить NOMAD.', 6.6, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4499408.jpg', 36, 1, 2, 1),
(41, 'Голодные игры: Сойка-пересмешница. Часть II', 'Китнисс Эвердин и своенравный Пит Мелларк пытаются выиграть гражданскую войну между самодержавным Капитолием и истерзанными войной районами Панема...', 6.6, 'https://kinopoiskapiunofficial.tech/images/posters/kp/663715.jpg', 2, 13, 12, 1),
(42, 'Вызов', 'Торакальный хирург Женя Беляева за месяц должна подготовиться к космическому полету, чтобы отправиться на МКС и спасти заболевшего космонавта. Ей придётся преодолеть неуверенность и страхи, а также провести сложнейшую операцию в условиях невесомости, от которой зависят шансы космонавта вернуться на Землю живым.', 7.5, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4448519.jpg', 13, 1, 1, 1),
(44, 'Тебе стоило уйти', 'Уже немолодой банкир на пенсии Тэо Конрой женат на востребованной актрисе Сюзанне, и из-за её занятости супруги проводят вместе не так много времени. Когда у Сюзанны выдаётся перерыв в съёмках, они вместе с шестилетней дочкой отправляются отдохнуть в снятый через интернет дизайнерский особняк в уэльской глуши. Но ожидаемого расслабления не происходит: всему семейству снятся кошмары, ревность к молодой жене усиливается, и Тэо кажется, что с этим домом что-то не так.', 5.6, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1139531.jpg', 39, 14, 8, 1),
(45, 'Джон Уик 4', 'Оставляя за собой горы трупов, Джон Уик продолжает скрываться от всевозможных наёмных убийц, и теперь охоту на него возглавляет молодой и честолюбивый член Правления по имени Маркиз. Два управляющих отелями «Континенталь» в Нью-Йорке и Осаке, решившие по старой дружбе помочь своенравному киллеру, уже жестоко за это поплатились, но внезапно Джон узнаёт способ выбраться из этой, казалось бы, безвыходной ситуации.', 7.6, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1267348.jpg', 35, 1, 13, 1),
(46, 'Гринч', 'Любой бы на месте Гринча позеленел и взбесился. Как порядочный интроверт он живёт в тёмной пещере на самой вершине горы подальше ото всех, но эти «все» готовят грандиознейшее празднование нового года. Они шумят, всё украшают и дико бесят. Кто бы отказал себе в удовольствии испортить праздник? Гринч решает украсть Новый год.', 7.6, 'https://kinopoiskapiunofficial.tech/images/posters/kp/738499.jpg', 40, 6, 4, 1),
(47, 'Реальная любовь', 'Любовь поистине правит всеми вокруг — от премьер-министра, влюбившегося в сотрудницу своего аппарата, до писателя, сбежавшего на юг Франции, чтобы склеить свое разбитое сердце.', 7.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/6144.jpg', 41, 15, 14, 1),
(48, '1993', '1993 год, дни больших надежд и грозных потрясений. Семья оказывается расколотой надвое — любящие супруги оказываются по разные стороны баррикад в самом центре Москвы.', 7.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/5088866.jpg', 13, 1, 1, 1),
(49, 'Бегущий по лезвию 2049', 'В недалеком будущем мир населен людьми и репликантами, созданными выполнять самую тяжелую работу. Работа офицера полиции Кей — держать репликантов под контролем в условиях нарастающего напряжения. Он случайно становится обладателем секретной информации, которая ставит под угрозу существование всего человечества. Желая найти ключ к разгадке, Кей решает разыскать Рика Декарда — бывшего офицера специального подразделения полиции Лос-Анджелеса, который бесследно исчез много лет назад.', 7.8, 'https://kinopoiskapiunofficial.tech/images/posters/kp/589290.jpg', 42, 16, 15, 1),
(50, 'Стражи Галактики. Часть 3', 'Едва Стражи Галактики обосновываются на Забвении, на них нападает Адам Уорлок, обладающее сверхспособностями существо, созданное своей «матерью» и Верховной Жрицей суверенов Аишей. В бою Небуле удаётся победить Адама, но Ракета получает серьёзные травмы, а Стражи не могут его вылечить из-за встроенного чипа смерти, созданного компанией «Оргокорп». Они отправляются в главный штаб компании на поиски кода отмены.', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1044280.jpg', 43, 1, 16, 1),
(51, 'Голодные игры: И вспыхнет пламя', 'Сумев выжить на безжалостных Голодных играх, Китнисс Эвердин и Пит Мелларк возвращаются домой. Но теперь они в еще большей опасности, так как своим отказом играть по правилам на Арене бросили вызов Капитолию. По традиции следующие, юбилейные, Голодные игры должны стать особенными, и в этот раз в них участвуют только победители прошлых лет. Китнисс и Пит вынуждены вновь выйти на Арену, где будут соперничать с сильнейшими. Правила игры меняются. Арена еще опасней, масштаб еще больше, ставки еще выше!', 7.5, 'https://kinopoiskapiunofficial.tech/images/posters/kp/602373.jpg', 2, 17, 2, 1),
(53, 'Начало', 'Кобб – талантливый вор, лучший из лучших в опасном искусстве извлечения: он крадет ценные секреты из глубин подсознания во время сна, когда человеческий разум наиболее уязвим. Редкие способности Кобба сделали его ценным игроком в привычном к предательству мире промышленного шпионажа, но они же превратили его в извечного беглеца и лишили всего, что он когда-либо любил. \n\nИ вот у Кобба появляется шанс исправить ошибки. Его последнее дело может вернуть все назад, но для этого ему нужно совершить невозможное – инициацию. Вместо идеальной кражи Кобб и его команда спецов должны будут провернуть обратное. Теперь их задача – не украсть идею, а внедрить ее. Если у них получится, это и станет идеальным преступлением. \n\nНо никакое планирование или мастерство не могут подготовить команду к встрече с опасным противником, который, кажется, предугадывает каждый их ход. Врагом, увидеть которого мог бы лишь Кобб.', 8.7, 'https://kinopoiskapiunofficial.tech/images/posters/kp/447301.jpg', 44, 19, 8, 1),
(54, 'Дочь болотного царя', 'Двенадцать лет Хелена прожила в изоляции под присмотром отца — тирана и убийцы, известного под прозвищем Болотный Царь. Когда его упрятали за решетку, девочка стала жить обычной жизнью. Прошло 20 лет, у Хелены своя семья, которая ничего не знает о её прошлом. Спустя много лет Болотный Царь сбегает из тюрьмы, и Хелена вынуждена помогать полиции ловить легендарного преступника, чтобы оградить близких от опасности. А для этого ей придется использовать навыки, которым ее обучил жестокий отец.', 6.3, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4397366.jpg', 45, 1, 2, 1),
(55, 'Переводчик', 'Афганистан, март 2018 года. Во время спецоперации по поиску оружия талибов отряд сержанта армии США Джона Кинли попадает в засаду. В живых остаются только сам Джон, получивший ранение, и местный переводчик Ахмед, который сотрудничает с американцами. Очнувшись на родине, Кинли не помнит, как ему удалось выжить, но понимает, что именно Ахмед спас ему жизнь, протащив на себе через опасную территорию. Теперь чувство вины не даёт Джону покоя, и он решает вернуться за Ахмедом и его семьёй, которых в Афганистане усиленно ищут талибы.', 7.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/927898.jpg', 46, 3, 18, 1),
(56, 'Подземелья и драконы: Честь среди воров', 'Бард и авантюрист Эдгин Дарвис вместе с боевой подругой Хольгой сбегает из тюрьмы и отправляется повидать дочку, которую последние годы опекал его бывший подельник Фордж. По прибытии выясняется, что тот при поддержке подозрительной колдуньи Софины не только сказочно разбогател и сделался губернатором, но и настроил дочь против отца, да и вообще — не против избавиться от Эдгина и Хольги. Умудрившись отбиться от палачей, отчаянная парочка планирует страшную месть, а для этого им придётся объединиться с рассеянным магом Саймоном, ловкой друидкой Дорик и отыскать считавшийся утерянным волшебный шлем.', 7.4, 'https://kinopoiskapiunofficial.tech/images/posters/kp/762646.jpg', 47, 1, 19, 1),
(57, 'Волк с Уолл-стрит', '1987 год. Джордан Белфорт становится брокером в успешном инвестиционном банке. Вскоре банк закрывается после внезапного обвала индекса Доу-Джонса. По совету жены Терезы Джордан устраивается в небольшое заведение, занимающееся мелкими акциями. Его настойчивый стиль общения с клиентами и врождённая харизма быстро даёт свои плоды. Он знакомится с соседом по дому Донни, торговцем, который сразу находит общий язык с Джорданом и решает открыть с ним собственную фирму. В качестве сотрудников они нанимают нескольких друзей Белфорта, его отца Макса и называют компанию «Стрэттон Оукмонт». В свободное от работы время Джордан прожигает жизнь: лавирует от одной вечеринки к другой, вступает в сексуальные отношения с проститутками, употребляет множество наркотических препаратов, в том числе кокаин и кваалюд. Однажды наступает момент, когда быстрым обогащением Белфорта начинает интересоваться агент ФБР...', 8.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/462682.jpg', 48, 17, 2, 1),
(58, 'Бойцовский клуб', 'Сотрудник страховой компании страдает хронической бессонницей и отчаянно пытается вырваться из мучительно скучной жизни. Однажды в очередной командировке он встречает некоего Тайлера Дёрдена — харизматического торговца мылом с извращенной философией. Тайлер уверен, что самосовершенствование — удел слабых, а единственное, ради чего стоит жить, — саморазрушение.\n\nПроходит немного времени, и вот уже новые друзья лупят друг друга почем зря на стоянке перед баром, и очищающий мордобой доставляет им высшее блаженство. Приобщая других мужчин к простым радостям физической жестокости, они основывают тайный Бойцовский клуб, который начинает пользоваться невероятной популярностью.', 8.7, 'https://kinopoiskapiunofficial.tech/images/posters/kp/361.jpg', 3, 20, 13, 1),
(61, 'Остров проклятых', 'Два американских судебных пристава отправляются на один из островов в штате Массачусетс, чтобы расследовать исчезновение пациентки клиники для умалишенных преступников. При проведении расследования им придется столкнуться с паутиной лжи, обрушившимся ураганом и смертельным бунтом обитателей клиники.', 8.5, 'https://kinopoiskapiunofficial.tech/images/posters/kp/397667.jpg', 50, 10, 2, 1),
(62, 'Достать ножи', 'На следующее утро после празднования 85-летия известного автора криминальных романов Харлана Тромби виновника торжества находят мёртвым. Налицо — явное самоубийство, но полиция по протоколу опрашивает всех присутствующих в особняке членов семьи, хотя, в этом деле больше заинтересован частный детектив Бенуа Блан. Тем же утром он получил конверт с наличными от неизвестного и заказ на расследование смерти Харлана. Не нужно быть опытным следователем, чтобы понять, что все приукрашивают свои отношения с почившим главой семейства, но Блану достаётся настоящий подарок — медсестра покойного, которая физически не выносит ложь.', 8.1, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1188529.jpg', 51, 8, 2, 1),
(63, 'Клаус', 'Владелец почтовой империи, чтобы научить ленивого отпрыска по имени Джеспер уму-разуму, отправляет его на крайний север в город Смиренсбург. Тот должен организовать там почтовое отделение и за год обработать не менее 6000 писем. Прибыв на место, парень оказывается в зоне боевых действий: два семейных клана, так уж исторически сложилось, питают взаимную ненависть и свято чтут многовековую традицию при любой возможности мутузить друг друга и делать пакости. Разумеется, в такой обстановке не до писем, и почтовое отделение давно превратилось в курятник. Уже практически отчаявшись, Джеспер посещает лесного отшельника по имени Клаус, и их знакомство положит начало удивительным событиям.', 8.7, 'https://kinopoiskapiunofficial.tech/images/posters/kp/957887.jpg', 52, 8, 18, 1),
(64, 'Человек-паук: Нет пути домой', 'Жизнь и репутация Питера Паркера оказываются под угрозой, поскольку Мистерио раскрыл всему миру тайну личности Человека-паука. Пытаясь исправить ситуацию, Питер обращается за помощью к Стивену Стрэнджу, но вскоре всё становится намного опаснее.', 7.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1309570.jpg', 53, 21, 2, 1),
(65, 'Шрэк', 'Жил да был в сказочном государстве большой зеленый великан по имени Шрэк. Жил он в гордом одиночестве в лесу, на болоте, которое считал своим. Но однажды злобный коротышка — лорд Фаркуад, правитель волшебного королевства, безжалостно согнал на Шрэково болото всех сказочных обитателей.\n\nИ беспечной жизни зеленого великана пришел конец. Но лорд Фаркуад пообещал вернуть Шрэку болото, если великан добудет ему прекрасную принцессу Фиону, которая томится в неприступной башне, охраняемой огнедышащим драконом.', 8.1, 'https://kinopoiskapiunofficial.tech/images/posters/kp/430.jpg', 54, 11, 21, 1),
(67, 'Зеленая книга', '1960-е годы. После закрытия нью-йоркского ночного клуба на ремонт вышибала Тони по прозвищу Болтун ищет подработку на пару месяцев. Как раз в это время Дон Ширли — утонченный светский лев, богатый и талантливый чернокожий музыкант, исполняющий классическую музыку — собирается в турне по южным штатам, где ещё сильны расистские убеждения и царит сегрегация. Он нанимает Тони в качестве водителя, телохранителя и человека, способного решать текущие проблемы. У этих двоих так мало общего, и эта поездка навсегда изменит жизнь обоих.', 8.4, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1108577.jpg', 11, 6, 23, 1),
(68, 'Одержимость', 'Эндрю мечтает стать великим. Казалось бы, вот-вот его мечта осуществится. Юношу замечает настоящий гений, дирижер лучшего в стране оркестра. Желание Эндрю добиться успеха быстро становится одержимостью, а безжалостный наставник продолжает подталкивать его все дальше и дальше – за пределы человеческих возможностей. Кто выйдет победителем из этой схватки?', 8.4, 'https://kinopoiskapiunofficial.tech/images/posters/kp/725190.jpg', 55, 17, 2, 1),
(69, 'Унесённые призраками', 'Тихиро с мамой и папой переезжает в новый дом. Заблудившись по дороге, они оказываются в странном пустынном городе, где их ждет великолепный пир. Родители с жадностью набрасываются на еду и к ужасу девочки превращаются в свиней, став пленниками злой колдуньи Юбабы. Теперь, оказавшись одна среди волшебных существ и загадочных видений, Тихиро должна придумать, как избавить своих родителей от чар коварной старухи.', 8.5, 'https://kinopoiskapiunofficial.tech/images/posters/kp/370.jpg', 56, 11, 9, 1),
(71, 'Дурные деньги', 'Говорят, что миром правят деньги. А деньгами распоряжается Уолл-Стрит. И если на самом верху решили, что небольшая сеть магазинов видеоигр должна обанкротиться, то под это можно брать кредит в банке. Но однажды обычные люди сказали «нет» и дали бой мировым биржам. Геймеры, тик-токеры, домохозяйки и мелкие инвесторы принялись скупать акции и «сломали» Уолл-Стрит, попутно заработав дурные деньги.', 7.3, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4917532.jpg', 11, 1, 2, 1),
(72, 'В никуда', 'Беременная женщина, бежавшая из тоталитарной страны, пытается выжить в дрейфующем в море контейнере грузового судна.', 6.4, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4783893.jpg', 57, 1, 24, 1),
(74, 'Чебурашка', 'На небольшой приморский городок обрушивается дождь из апельсинов, а вместе с фруктами с неба падает неизвестный науке мохнатый непоседливый зверёк. Одержимое апельсинами животное оказывается в домике нелюдимого старика-садовника Геннадия, который из вредности решает оставить его жить у себя, так как местная богачка жаждет заполучить необычного зверя для своей избалованной внучки. Также эта коварная женщина, владелица кондитерской фабрики, пытается выведать секрет шоколада у хозяйки маленького магазинчика — дочери Геннадия, много лет обиженной на отца.', 7.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4370148.jpg', 59, 3, 1, 1),
(75, 'Рождественская история', 'Это викторианская поучительная история о старом и ожесточившемся скупердяе Эбенезере Скрудже, который в течение одной ночи переживает испытание глубокого очищения. Мистер Скрудж — финансист/денежный меняла, который посвятил всю свою жизнь накоплению богатства. Он презирает всё, кроме денег, включая дружбу, любовь и рождественские праздники.', 7.8, 'https://kinopoiskapiunofficial.tech/images/posters/kp/391755.jpg', 60, 10, 2, 1),
(76, 'Быстрее пули', 'Наёмник под кодовым именем Божья Коровка отправляется на новую миссию: вместо заболевшего коллеги он должен сесть в скоростной поезд Токио — Киото, выкрасть чемоданчик и сойти на промежуточной станции. Но выполнение простого задания сильно осложняется, когда выясняется, что состав просто кишит всевозможными киллерами.', 7.7, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1392550.jpg', 31, 3, 2, 1),
(77, 'Зеленая миля', 'Пол Эджкомб — начальник блока смертников в тюрьме «Холодная гора», каждый из узников которого однажды проходит «зеленую милю» по пути к месту казни. Пол повидал много заключённых и надзирателей за время работы. Однако гигант Джон Коффи, обвинённый в страшном преступлении, стал одним из самых необычных обитателей блока.', 9.1, 'https://kinopoiskapiunofficial.tech/images/posters/kp/435.jpg', 61, 20, 2, 1),
(78, 'Миссия невыполнима: Смертельная расплата. Часть первая', 'Итан Хант и его команда противостоят системе искусственного интеллекта Entity, которая вышла из под контроля и стала угрозой человечества.', 7.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1229684.jpg', 62, 1, 2, 1),
(79, 'Аватар: Путь воды', 'После принятия образа аватара солдат Джейк Салли становится предводителем народа на\'ви и берет на себя миссию по защите новых друзей от корыстных бизнесменов с Земли. Теперь ему есть за кого бороться — с Джейком его прекрасная возлюбленная Нейтири. Когда на Пандору возвращаются до зубов вооруженные земляне, Джейк готов дать им отпор.', 7.8, 'https://kinopoiskapiunofficial.tech/images/posters/kp/505898.jpg', 53, 3, 2, 1),
(80, 'Серебряные коньки', '1899 год, рождественский Петербург. Яркая праздничная жизнь бурлит на скованных льдом реках и каналах столицы. Накануне нового столетия судьба сводит тех, кому, казалось бы, не суждено было встретиться. Люди из совершенно разных миров, Матвей — сын фонарщика, его единственное богатство — доставшиеся по наследству посеребренные коньки; Алиса — дочь крупного сановника, грезящая о науке. У каждого — своя непростая история, но, однажды столкнувшись, они устремляются к мечте вместе.', 7.6, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1225587.jpg', 63, 14, 1, 1),
(84, 'Вася не в себе', 'Василий Кузин — крайне успешный столичный бизнесмен: красивая девушка, крутая машина, большая квартира, строительная империя растет. Только одно омрачает его жизнь — приезжие рабочие, которых Василий ни в грош не ставит и постоянно «кидает» на деньги. Однажды Вася попадает в аварию, а, когда приходит в себя, к своему ужасу обнаруживает, что каким-то невероятным образом превратился в маленького упитанного героя анекдотов про гастарбайтеров. Теперь он должен сделать всё, чтобы вернуть своё прежнее тело.', 6.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/5257393.jpg', 66, 1, 1, 1),
(89, 'Гран туризмо', 'Заядлый геймер Янн Марденборо, несостоявшийся автогонщик Джейк Солтер и идейный маркетолог Дэнни Мур вместе рискнут всем, чтобы найти своё место в самом элитном виде спорта.', 7.6, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1044002.jpg', 69, 1, 30, 1),
(90, 'Семьянин', 'Судьба в облике чернокожего Санты ставит перед Джеком непростой выбор. Он может быть президентом инвестиционной компании, жить в роскошной квартире, раскатывать на последней модели «Феррари» и при этом оставаться холостяком. А может стать семьянином, но работать продавцом автопокрышек, покупать одежду в супермаркете и ездить на минивэне.', 7.8, 'https://kinopoiskapiunofficial.tech/images/posters/kp/664.jpg', 70, 22, 2, 1),
(91, 'Леди Баг и Супер-Кот: Пробуждение силы', 'В обыкновенной французской школе учатся девочка Маринетт и мальчик Адриан, в которого она влюблена. Казалось бы, классическая история первой любви, но эти ребята совсем не те, за кого себя выдают. Когда городу угрожает опасность, Маринетт превращается в супергероиню Леди Баг, а Адриан — в Супер-Кота. Их невероятные способности помогают бороться со злом, но при этом никто из них не знает, кто на самом деле скрывается под маской.', 7.7, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1395369.jpg', 71, 1, 6, 1),
(92, 'Властелин колец: Братство Кольца', 'Сказания о Средиземье — это хроника Великой войны за Кольцо, длившейся не одну тысячу лет. Тот, кто владел Кольцом, получал неограниченную власть, но был обязан служить злу. \n\nТихая деревня, где живут хоббиты. Придя на 111-й день рождения к своему старому другу Бильбо Бэггинсу, волшебник Гэндальф начинает вести разговор о кольце, которое Бильбо нашел много лет назад. Это кольцо принадлежало когда-то темному властителю Средиземья Саурону, и оно дает большую власть своему обладателю. Теперь Саурон хочет вернуть себе власть над Средиземьем. Бильбо отдает Кольцо племяннику Фродо, чтобы тот отнёс его к Роковой Горе и уничтожил.', 8.6, 'https://kinopoiskapiunofficial.tech/images/posters/kp/328.jpg', 72, 11, 31, 1),
(93, 'Анатомия падения', 'Жизнь успешной писательницы Сандры Войтер переворачивается после загадочной смерти мужа. Ей предъявляют обвинение в убийстве. Однако чем дальше ведется расследование, тем больше всплывает подозрительных обстоятельств. Что же произошло на самом деле в их уединенном шале во французских Альпах?', 7.4, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4910679.jpg', 3, 1, 6, 1),
(94, 'Звук свободы', 'Оперативник Министерства внутренней безопасности Тим Баллард разочаровался в системе — много лет он выслеживал и ловил педофилов, но не вызволил из лап работорговцев ни одного ребёнка. Тим втирается в доверие к недавно пойманному распространителю детского порно, убеждает его, что он «свой», и вот уже из Мексики ему везут восьмилетнего мальчика. Маленький Мигель становится первым освобождённым из множества детей, проданных в сексуальное рабство в Латинской Америке, и Тим решает во что бы то ни стало разыскать его сестрёнку.', 7.6, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1134493.jpg', 3, 1, 32, 1),
(95, 'Последняя дуэль', 'Франция, конец XIV века. Отношения между рыцарем Жаном де Карружем и его соратником и соседом Жаком Ле Гри постепенно портятся, и дело доходит до неразрешимого конфликта. Оскорблённый Карруж обращается за помощью к королю Франции Карлу VI, и тот постановляет — противники должны решить спор в смертельной дуэли.', 7.4, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1289738.jpg', 73, 21, 8, 1),
(96, 'Драйв', 'Великолепный водитель – при свете дня он выполняет каскадерские трюки на съёмочных площадках Голливуда, а по ночам ведет рискованную игру. Но один опасный контракт – и за его жизнь назначена награда. Теперь, чтобы остаться в живых и спасти свою очаровательную соседку, он должен делать то, что умеет лучше всего – виртуозно уходить от погони.', 7.3, 'https://kinopoiskapiunofficial.tech/images/posters/kp/276598.jpg', 3, 7, 2, 1),
(97, 'Ходячий замок', 'Злая ведьма заточила 18-летнюю Софи в тело старухи. Девушка-бабушка бежит из города куда глаза глядят и встречает удивительный дом на ножках, где знакомится с могущественным волшебником Хаулом и демоном Кальцифером. Кальцифер должен служить Хаулу по договору, условия которого он не может разглашать. Девушка и демон решают помочь друг другу избавиться от злых чар.', 8.3, 'https://kinopoiskapiunofficial.tech/images/posters/kp/49684.jpg', 74, 23, 9, 1),
(98, 'Прямой эфир', 'Блогер-миллионник Егор в погоне за контентом отправляется на съемки тест-драйва автомобиля в Кавказские горы. Все выходит из-под контроля в тот момент, когда сотрудник автокомпании Александр, помогающий Егору, случайно наступает на боевую мину, а Егор решает на этом хайпануть. Теперь, когда один борется за собственную жизнь, а второй за миллионные просмотры — каждый сам за себя. Но им вместе придется принять одно общее решение.', 6.8, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4400163.jpg', 57, 3, 1, 1),
(99, 'Пила 10', 'Надеясь излечиться от рака, Джон Крамер отправляется в Мексику на экспериментальное лечение. Операция проходит успешно, и доктор обещает ему начало новой жизни, но вскоре выясняется, что это было постановочное мошенничество и обман отчаявшихся больных. Теперь Джон наставит аферистов на путь истинный в своём фирменном стиле — при помощи хитроумных жестоких ловушек.', 6.6, 'https://kinopoiskapiunofficial.tech/images/posters/kp/5080630.jpg', 39, 1, 33, 1),
(100, 'Операция «Фортуна»: Искусство побеждать', 'Суперагент британской разведки Орсон Форчун наслаждался заслуженным отпуском, когда родине срочно понадобились его услуги. Из секретной лаборатории похищено предположительно смертельное оружие, поэтому, собрав команду из лучших оперативников, Орсон выходит на посредника в готовящейся сделке продажи — миллиардера и большого поклонника знаменитостей Грэга Симмондса. А чтобы подобраться к нему, в качестве прикрытия решает использовать известного голливудского актёра Дэнни Франческо.', 7.1, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1405508.jpg', 31, 3, 8, 1),
(101, 'Хранители снов', 'Когда злой дух Кромешник посягает на самое дорогое – детские мечты, Северянин, Ледяной Джек, Кролик, Зубная Фея и Песочный Человек впервые объединяются, чтобы создать команду Хранителей снов...', 8.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/466581.jpg', 75, 2, 34, 1),
(102, 'Неудержимые 4', 'Неудержимые несут потери: Барни Росс выбывает из строя, а Ли Кристмас отстранен от будущих операций. В команду набирают новых бойцов и отправляют возмещать ущерб. Но и они терпят поражение и попадают в плен. Теперь Ли Кристмас должен в одиночку пробраться в логово противника и освободить команду, попутно предотвратив глобальную катастрофу. Только так можно спасти мир и восстановить репутацию Неудержимых.', 5.3, 'https://kinopoiskapiunofficial.tech/images/posters/kp/806964.jpg', 37, 1, 2, 1),
(103, 'Уикенд с батей', 'Себастьян планирует провести уикенд со своей очаровательной невестой Элли и ее семьей в их роскошном фамильном поместье, где есть собственное поле для гольфа, шикарная яхта и даже ручной павлин. Отличный план на длинные выходные, но Элли настаивает, чтобы Себастьян также пригласил своего отца Сальво, эксцентричного парикмахера родом из Италии. Культурный шок ждет всех. Но ведь родственников не выбирают?', 7.1, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4477067.jpg', 1, 1, 2, 1),
(104, 'Отступники', 'Два лучших выпускника полицейской академии оказались по разные стороны баррикады: один из них – агент мафии в рядах правоохранительных органов, другой – «крот», внедрённый в мафию. Каждый считает своим долгом обнаружить и уничтожить противника, но постоянная жизнь в искажённых реалиях меняет внутренний мир героев.', 8.5, 'https://kinopoiskapiunofficial.tech/images/posters/kp/81314.jpg', 3, 9, 35, 1),
(105, 'Голодные игры: Сойка-пересмешница. Часть I', '75-ые Голодные игры изменили все. Китнисс нарушила правила, и непоколебимое до той поры деспотичное правление Капитолия пошатнулось. У людей появилась надежда, и ее символ – Сойка-пересмешница. Теперь, чтобы освободить захваченного в плен Пита и защитить своих близких, Китнисс придется  сражаться в настоящих битвах и стать еще сильнее, чем на арене игр.', 6.3, 'https://kinopoiskapiunofficial.tech/images/posters/kp/661911.jpg', 2, 5, 36, 1),
(106, 'После. Навсегда', 'Бестселлер об отношениях с Тессой принес Хардину деньги и успех, но оставил с разбитым сердцем. В попытках исправить ошибки давнего прошлого Хардин отправляется из Лондона в знойный Лиссабон, но попадает в новый водоворот страстей. Когда же судьба дарит Хардину и Тессе шанс на счастливый финал, только от них зависит, какой станет последняя глава их истории любви.', 6.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4542838.jpg', 76, 1, 2, 1),
(107, 'Гордость и предубеждение', 'Англия, конец XVIII века. Родители пятерых сестер Беннет озабочены тем, чтобы удачно выдать дочерей замуж. И потому размеренная жизнь солидного семейства переворачивается вверх дном, когда по соседству появляется молодой джентльмен - мистер Бингли... \r\n\r\nСамо собой, среди друзей нового соседа оказывается немало утонченных аристократов, которые не прочь поухаживать за очаровательными сестрами. Однако, все не так просто. Своевольная Элизабет знакомится с другом Бингли - красивым и высокомерным мистером Дарси, и между ними разгорается нешуточное противостояние, результатом которого может стать как любовь, так и ненависть...', 8.1, 'https://kinopoiskapiunofficial.tech/images/posters/kp/81733.jpg', 77, 24, 14, 1),
(108, 'Гарри Поттер и Тайная комната', 'Гарри Поттер переходит на второй курс Школы чародейства и волшебства Хогвартс. Эльф Добби предупреждает Гарри об опасности, которая поджидает его там, и просит больше не возвращаться в школу.\n\nЮный волшебник не следует совету эльфа и становится свидетелем таинственных событий, разворачивающихся в Хогвартсе. Вскоре Гарри и его друзья узнают о существовании Тайной Комнаты и сталкиваются с новыми приключениями, пытаясь победить темные силы.', 8.1, 'https://kinopoiskapiunofficial.tech/images/posters/kp/688.jpg', 30, 25, 8, 1),
(110, 'Список Шиндлера', 'Фильм рассказывает реальную историю загадочного Оскара Шиндлера, члена нацистской партии, преуспевающего фабриканта, спасшего во время Второй мировой войны почти 1200 евреев.', 8.8, 'https://kinopoiskapiunofficial.tech/images/posters/kp/329.jpg', 24, 26, 2, 1),
(111, 'Кунг-фу жеребец', 'Знаменитый мастер боевых искусств и его верный скакун врываются в мир, где любая уличная драка заслуживает тиктока. \nКруто разделавшись с бандой коллекторов, они тотчас становятся супергероями в сети. Но вместе с любовью фанатов их находят и могущественные враги.', 8.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4632862.jpg', 78, 1, 37, 1),
(112, 'Непослушная', 'Двадцатилетняя Эля — студентка и будущий эколог. Однажды в ее университет приезжает Матвей, глава строительной компании, чтобы рассказать о плане застройки на месте старинного лесопарка. Эля не стесняясь разносит его проект в пух и прах. Матвей заинтригован самоуверенностью девушки и применяет привычные ему способы воздействия — попросту пытается её «купить». Но Эле не нужен спонсор. Тогда Матвей, удивленный ее неприступностью, предлагает Эле пари: семь романтических дней по его правилам. Если после этого девушка всё же решит уйти, он откажется от строительства небоскрёба в лесопарке. Она соглашается, когда Матвей действительно приостанавливает проектные работы. Эля видит себя кем-то вроде героини фильма «Красотка», но Матвей оказывается совсем не тем человеком, которого она себе представляла.', 5.5, 'https://kinopoiskapiunofficial.tech/images/posters/kp/5189350.jpg', 76, 1, 1, 1),
(113, 'Всё везде и сразу', 'В жизни Эвелин царит бардак. Она никак не может составить налоговый отчёт, пожилой отец постоянно требует внимания, муж витает в облаках, а ещё и дочка привела свою девушку знакомиться с семьёй. Во время визита в налоговую всё запутывается ещё сильнее — оказывается, Эвелин может скакать по параллельным вселенным и получать доступ к воспоминаниям и навыкам других версий самой себя. И теперь, в полнейшем хаосе, женщине придётся противостоять загадочной злой сущности, которая решила разрушить не только этот мир, но и всю мультивселенную.', 7.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1322324.jpg', 79, 21, 2, 1),
(114, 'Дюна', 'Наследник знаменитого дома Атрейдесов Пол отправляется вместе с семьей на одну из самых опасных планет во Вселенной — Арракис. Здесь нет ничего, кроме песка, палящего солнца, гигантских чудовищ и основной причины межгалактических конфликтов — невероятно ценного ресурса, который называется меланж. В результате захвата власти Пол вынужден бежать и скрываться, и это становится началом его эпического путешествия. Враждебный мир Арракиса приготовил для него множество тяжелых испытаний, но только тот, кто готов взглянуть в глаза своему страху, достоин стать избранным.', 7.7, 'https://kinopoiskapiunofficial.tech/images/posters/kp/409424.jpg', 65, 21, 38, 1),
(115, 'Чемпион мира', 'История матча за звание чемпиона мира, который прошел на Филиппинах в 1978 году, между действующим чемпионом Анатолием Карповым и претендентом на этот титул — гроссмейстером Виктором Корчным, несколько лет назад эмигрировавшим из СССР.', 6.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1249233.jpg', 80, 21, 1, 1),
(116, 'Гнев человеческий', 'Грузовики лос-анджелесской инкассаторской компании Fortico Security часто подвергаются нападениям, и во время очередного ограбления погибают оба охранника. Через некоторое время в компанию устраивается крепкий немногословный британец Патрик Хилл. Он получает от босса прозвище Эйч и, впритык к необходимому минимуму пройдя тесты по фитнесу, стрельбе и вождению, отправляется на первое задание. Вскоре и его грузовик пытаются ограбить вооруженные налётчики, но Эйч в одиночку расправляется с целой бандой и становится героем. Кажется, слава и уважение коллег его совершенно не интересуют, ведь он преследует свои цели.', 7.6, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1318972.jpg', 81, 21, 8, 1);
INSERT INTO `media` (`id`, `title`, `description`, `rating`, `image_url`, `genre_id`, `year_id`, `country_id`, `type_id`) VALUES
(118, 'Побег из Шоушенка', 'Бухгалтер Энди Дюфрейн обвинён в убийстве собственной жены и её любовника. Оказавшись в тюрьме под названием Шоушенк, он сталкивается с жестокостью и беззаконием, царящими по обе стороны решётки. Каждый, кто попадает в эти стены, становится их рабом до конца жизни. Но Энди, обладающий живым умом и доброй душой, находит подход как к заключённым, так и к охранникам, добиваясь их особого к себе расположения.', 9.1, 'https://kinopoiskapiunofficial.tech/images/posters/kp/326.jpg', 13, 27, 2, 1),
(119, 'Форрест Гамп', 'Сидя на автобусной остановке, Форрест Гамп — не очень умный, но добрый и открытый парень — рассказывает случайным встречным историю своей необыкновенной жизни.\n\nС самого малолетства парень страдал от заболевания ног, соседские мальчишки дразнили его, но в один прекрасный день Форрест открыл в себе невероятные способности к бегу. Подруга детства Дженни всегда его поддерживала и защищала, но вскоре дороги их разошлись.', 8.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/448.jpg', 84, 27, 2, 1),
(120, 'Властелин колец: Возвращение короля', 'Повелитель сил тьмы Саурон направляет свою бесчисленную армию под стены Минас-Тирита, крепости Последней Надежды. Он предвкушает близкую победу, но именно это мешает ему заметить две крохотные фигурки — хоббитов, приближающихся к Роковой Горе, где им предстоит уничтожить Кольцо Всевластья.', 8.7, 'https://kinopoiskapiunofficial.tech/images/posters/kp/3498.jpg', 72, 15, 31, 1),
(121, 'Криминальное чтиво', 'Двое бандитов Винсент Вега и Джулс Винфилд ведут философские беседы в перерывах между разборками и решением проблем с должниками криминального босса Марселласа Уоллеса.\n\nВ первой истории Винсент проводит незабываемый вечер с женой Марселласа Мией. Во второй рассказывается о боксёре Бутче Кулидже, купленном Уоллесом, чтобы сдать бой. В третьей истории Винсент и Джулс по нелепой случайности попадают в неприятности.', 8.7, 'https://kinopoiskapiunofficial.tech/images/posters/kp/342.jpg', 5, 27, 2, 1),
(122, 'Тайна Коко', '12-летний Мигель живёт в мексиканской деревушке в семье сапожников и тайно мечтает стать музыкантом. Тайно, потому что в его семье музыка считается проклятием. Когда-то его прапрадед оставил жену, прапрабабку Мигеля, ради мечты, которая теперь не даёт спокойно жить и его праправнуку. С тех пор музыкальная тема в семье стала табу. Мигель обнаруживает, что между ним и его любимым певцом Эрнесто де ла Крусом, ныне покойным, существует некая связь. Паренёк отправляется к своему кумиру в Страну Мёртвых, где встречает души предков. Мигель знакомится там с духом-скелетом по имени Гектор, который становится его проводником. Вдвоём они отправляются на поиски де ла Круса.', 8.7, 'https://kinopoiskapiunofficial.tech/images/posters/kp/679486.jpg', 58, 16, 30, 1),
(123, 'Властелин колец: Две крепости', 'Братство распалось, но Кольцо Всевластья должно быть уничтожено. Фродо и Сэм вынуждены довериться Голлуму, который взялся провести их к вратам Мордора. Громадная армия Сарумана приближается: члены братства и их союзники готовы принять бой. Битва за Средиземье продолжается.', 8.6, 'https://kinopoiskapiunofficial.tech/images/posters/kp/312.jpg', 72, 25, 31, 1),
(124, 'Иван Васильевич меняет профессию', 'Инженер-изобретатель Тимофеев сконструировал машину времени, которая соединила его квартиру с далеким шестнадцатым веком - точнее, с палатами государя Ивана Грозного. Туда-то и попадают тезка царя пенсионер-общественник Иван Васильевич Бунша и квартирный вор Жорж Милославский.\n\nНа их место в двадцатом веке «переселяется» великий государь. Поломка машины приводит ко множеству неожиданных и забавных событий...', 8.8, 'https://kinopoiskapiunofficial.tech/images/posters/kp/42664.jpg', 85, 28, 40, 1),
(125, 'Приключения Шерлока Холмса и доктора Ватсона: Собака Баскервилей', 'Труп Чарльза Баскервиля обнаруживают неподалеку от его родового поместья. Выражение нечеловеческого ужаса на лице покойника и следы крупной собаки поблизости заставляют вспомнить старинную легенду о проклятии, тяготеющем над родом Баскервилей. Шерлоку Холмсу предстоит докопаться до истины.', 8.6, 'https://kinopoiskapiunofficial.tech/images/posters/kp/77263.jpg', 18, 29, 40, 1),
(126, 'Шерлок Холмс и доктор Ватсон: Знакомство', 'Молодой доктор по фамилии Ватсон возвратился из Афганистана в родной туманный Лондон. Ему нужно недорогое жилье. И вот, по совету друга, он поселяется в маленьком домике на Бейкер-стрит. Его хозяйка - милая чудаковатая старушка миссис Хадсон. Также там имеется сосед - некий мистер Шерлок Холмс. Это непонятная и таинственная личность - к нему в гости приходят оборванцы и бандиты, а иногда полицейские и лорды. Кто же он? Доктор в растерянности...', 8.6, 'https://kinopoiskapiunofficial.tech/images/posters/kp/77269.jpg', 18, 30, 40, 1),
(127, 'Король Лев', 'У величественного Короля-Льва Муфасы рождается наследник по имени Симба. Уже в детстве любознательный малыш становится жертвой интриг своего завистливого дяди Шрама, мечтающего о власти.\n\nСимба познаёт горе утраты, предательство и изгнание, но в конце концов обретает верных друзей и находит любимую. Закалённый испытаниями, он в нелёгкой борьбе отвоёвывает своё законное место в «Круге жизни», осознав, что значит быть настоящим Королём. ', 8.8, 'https://kinopoiskapiunofficial.tech/images/posters/kp/2360.jpg', 86, 27, 2, 1),
(128, 'Достучаться до небес', 'Волею судеб две абсолютные противоположности, тихоня Руди и разгильдяй Мартин, оказываются в одной больничной палате. Узнав неутешительные прогнозы, друзья решают использовать последние дни на полную катушку — угнать машину с деньгами, напиться текилы, и, конечно, увидеть море.', 8.6, 'https://kinopoiskapiunofficial.tech/images/posters/kp/32898.jpg', 87, 31, 41, 1),
(129, 'Терминатор 2: Судный день', 'Прошло более десяти лет с тех пор, как киборг из 2029 года пытался уничтожить Сару Коннор — женщину, чей будущий сын выиграет войну человечества против машин.\n\nТеперь у Сары родился сын Джон и время, когда он поведёт за собой выживших людей на борьбу с машинами, неумолимо приближается. Именно в этот момент из постапокалиптического будущего прибывает новый терминатор — практически неуязвимая модель T-1000, способная принимать любое обличье. Цель нового терминатора уже не Сара, а уничтожение молодого Джона Коннора.\n\nОднако шансы Джона на спасение существенно повышаются, когда на помощь приходит перепрограммированный сопротивлением терминатор предыдущего поколения. Оба киборга вступают в смертельный бой, от исхода которого зависит судьба человечества.', 8.4, 'https://kinopoiskapiunofficial.tech/images/posters/kp/444.jpg', 88, 32, 2, 1),
(130, 'Джентльмены удачи', 'Заведующему детсадом Трошкину фатально не повезло: он оказался как две капли воды похож на бандита по кличке «Доцент», похитившего уникальный шлем Александра Македонского.\n\nМилиция внедряет добряка Трошкина в воровскую среду - и ему ничего не остается, кроме как старательно изображать своего двойника-злодея, путая всех окружающих. Со временем он настолько блестяще входит в роль, что сам начинает порой приходить в ужас. Между тем, жизни его угрожает смертельная опасность...', 8.5, 'https://kinopoiskapiunofficial.tech/images/posters/kp/44386.jpg', 51, 33, 40, 1),
(131, 'Москва слезам не верит', 'Москва, 1950-е годы. Три молодые провинциалки приезжают в Москву в поисках того, что ищут люди во всех столицах мира — любви, счастья и достатка. Антонина выходит замуж, растит детей, любит мужа. Людмиле Москва представляется лотереей, в которой она должна выиграть свое особенное счастье. Катерина же отчаянно влюбляется, но избранник ее оставляет. Однако она не опускает руки, в одиночку растит дочь и к тому же успевает делать блестящую карьеру. В 40 лет судьба дарит ей неожиданную встречу.', 8.4, 'https://kinopoiskapiunofficial.tech/images/posters/kp/46708.jpg', 41, 30, 40, 1),
(132, 'Леон', 'Профессиональный убийца Леон неожиданно для себя самого решает помочь 12-летней соседке Матильде, семью которой убили коррумпированные полицейские.', 8.7, 'https://kinopoiskapiunofficial.tech/images/posters/kp/389.jpg', 89, 27, 4, 1),
(133, 'Операция «Ы» и другие приключения Шурика', 'Студент Шурик попадает в самые невероятные ситуации: сражается с хулиганом Верзилой, весьма оригинальным способом готовится к экзамену и предотвращает «ограбление века», на которое идёт троица бандитов — Балбес, Трус и Бывалый.', 8.7, 'https://kinopoiskapiunofficial.tech/images/posters/kp/42782.jpg', 90, 34, 40, 1),
(134, '...А зори здесь тихие', 'В прифронтовой полосе группа девушек-зенитчиц вынуждена вступить в неравный бой с вражескими десантниками. Эти девчонки мечтали о большой любви, нежности, семейном тепле - но на их долю выпала жестокая война, и они до конца выполнили свой воинский долг…', 8.5, 'https://kinopoiskapiunofficial.tech/images/posters/kp/43395.jpg', 91, 35, 40, 1),
(135, 'Назад в будущее', 'Подросток Марти с помощью машины времени, сооружённой его другом-профессором доком Брауном, попадает из 80-х в далекие 50-е. Там он встречается со своими будущими родителями, ещё подростками, и другом-профессором, совсем молодым.', 8.6, 'https://kinopoiskapiunofficial.tech/images/posters/kp/476.jpg', 85, 36, 2, 1),
(136, 'Гарри Поттер и узник Азкабана', 'В третьей части истории о юном волшебнике полюбившиеся всем герои — Гарри Поттер, Рон и Гермиона — возвращаются уже на третий курс школы чародейства и волшебства Хогвартс. На этот раз они должны раскрыть тайну узника, сбежавшего из зловещей тюрьмы Азкабан, чье пребывание на воле создает для Гарри смертельную опасность...', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/322.jpg', 30, 23, 8, 1),
(137, 'Темный рыцарь', 'Бэтмен поднимает ставки в войне с криминалом. С помощью лейтенанта Джима Гордона и прокурора Харви Дента он намерен очистить улицы Готэма от преступности. Сотрудничество оказывается эффективным, но скоро они обнаружат себя посреди хаоса, развязанного восходящим криминальным гением, известным напуганным горожанам под именем Джокер.', 8.5, 'https://kinopoiskapiunofficial.tech/images/posters/kp/111543.jpg', 92, 37, 8, 1),
(138, 'Девчата', 'В сибирский поселок приехала юная повариха Тося Кислицына — наивная и эксцентричная девчонка. Она сует свой нос во все дела, каждому стремится помочь. Местный красавец Илья на спор заводит с Тосей роман.', 8.4, 'https://kinopoiskapiunofficial.tech/images/posters/kp/44168.jpg', 16, 38, 40, 1),
(139, 'Они сражались за Родину', 'Июль 1942 года. На подступах к Сталинграду обескровленные, измотанные советские войска ведут тяжелые оборонительные бои, неся огромные потери... Фильм рассказывает о подвиге рядовых солдат, любви к родной земле, об истинной цене победы...', 8.5, 'https://kinopoiskapiunofficial.tech/images/posters/kp/42770.jpg', 93, 39, 40, 1),
(140, 'ВАЛЛ·И', 'Робот ВАЛЛ·И из года в год прилежно трудится на опустевшей Земле, очищая нашу планету от гор мусора, которые оставили после себя улетевшие в космос люди. Он и не представляет, что совсем скоро произойдут невероятные события, благодаря которым он встретит друзей, поднимется к звездам и даже сумеет изменить к лучшему своих бывших хозяев, совсем позабывших родную Землю.', 8.4, 'https://kinopoiskapiunofficial.tech/images/posters/kp/279102.jpg', 94, 37, 2, 1),
(141, 'Поймай меня, если сможешь', 'Фрэнк Эбегнейл успел поработать врачом, адвокатом и пилотом на пассажирской авиалинии – и все это до достижения полного совершеннолетия в 21 год. Мастер в обмане и жульничестве, он также обладал искусством подделки документов, что в конечном счете принесло ему миллионы долларов, которые он получил по фальшивым чекам.\n\nАгент ФБР Карл Хэнрэтти отдал бы все, чтобы схватить Фрэнка и привлечь к ответственности за свои деяния, но Фрэнк всегда опережает его на шаг, заставляя продолжать погоню.', 8.5, 'https://kinopoiskapiunofficial.tech/images/posters/kp/324.jpg', 95, 25, 19, 1),
(142, 'Как приручить дракона', 'Вы узнаете историю подростка Иккинга, которому не слишком близки традиции его героического племени, много лет ведущего войну с драконами. Мир Иккинга переворачивается с ног на голову, когда он неожиданно встречает дракона Беззубика, который поможет ему и другим викингам увидеть привычный мир с совершенно другой стороны…', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/280172.jpg', 96, 19, 4, 1),
(143, 'Шрэк 2', 'Шрэк и Фиона возвращаются после медового месяца и находят письмо от родителей Фионы с приглашением на ужин. Однако те не подозревают, что их дочь тоже стала огром! Вместе с Осликом счастливая пара отправляется в путешествие, полное неожиданностей, и попадает в круговорот событий, во время которых приобретает множество друзей…', 7.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/5273.jpg', 54, 23, 19, 1),
(144, 'Собачье сердце', 'Москва, 1924 год. В результате одного из сложнейших опытов профессор Филипп Филиппович Преображенский делает потрясающее открытие: после пересадки гипофиза человека пёс Шарик начинает приобретать человеческие черты. Сенсационная новость мгновенно разлетается по Москве и приносит мировому светилу очередную порцию признания. Однако радость оказывается недолгой: вопрос, что из Шарика — то есть гражданина Шарикова — может получиться «высокая психическая личность», очень быстро становится под сомнение.', 8.4, 'https://kinopoiskapiunofficial.tech/images/posters/kp/77335.jpg', 97, 40, 40, 1),
(145, 'Бриллиантовая рука', 'В южном городке орудует шайка валютчиков, возглавляемая Шефом и его помощником Графом (в быту — Геной Козодоевым). Скромный советский служащий и примерный семьянин Семен Семенович Горбунков отправляется в зарубежный круиз на теплоходе, где также плывет Граф, который должен забрать бриллианты в одном из восточных городов и провезти их в загипсованной руке. Но из-за недоразумения вместо жулика на условленном месте падает ничего не подозревающий Семен Семенович, и драгоценный гипс накладывают ему.', 8.5, 'https://kinopoiskapiunofficial.tech/images/posters/kp/46225.jpg', 98, 41, 40, 1),
(146, 'Хатико: Самый верный друг', 'Однажды, возвращаясь с работы, профессор колледжа нашел на вокзале симпатичного щенка породы акита-ину. Профессор и Хатико стали верными друзьями. Каждый день пес провожал и встречал хозяина на вокзале.', 8.4, 'https://kinopoiskapiunofficial.tech/images/posters/kp/387556.jpg', 99, 37, 8, 1),
(147, 'Большой куш', 'Фрэнки Четыре Пальца должен был переправить краденый алмаз из Англии в США своему боссу Эви, но, сделав ставку на подпольный боксерский поединок, он попал в круговорот весьма нежелательных событий. Вокруг него и его груза разворачивается сложная интрига с участием множества колоритных персонажей лондонского дна — русского гангстера, троих незадачливых грабителей, хитрого боксера и угрюмого громилы грозного мафиози. Каждый норовит в одиночку сорвать большой куш.', 8.6, 'https://kinopoiskapiunofficial.tech/images/posters/kp/526.jpg', 14, 22, 8, 1),
(148, 'Кавказская пленница, или Новые приключения Шурика', 'Отправившись в одну из горных республик собирать фольклор, студент Шурик влюбляется в симпатичную девушку Нину - спортсменку, отличницу, комсомолку и просто красавицу. Но её внезапно похищают банда их трёх человек, чтобы насильно выдать замуж. Наивный Шурик не сразу сообразил, что творится у него под носом, - однако затем отважно ринулся освобождать кавказскую пленницу.', 8.5, 'https://kinopoiskapiunofficial.tech/images/posters/kp/44745.jpg', 100, 42, 40, 1),
(149, 'Гарри Поттер и Дары Смерти: Часть II', 'В грандиозной последней главе битва между добрыми и злыми силами мира волшебников перерастает во всеобщую войну. Ставки ещё никогда не были так высоки, а поиск убежища — столь сложен. И, быть может, именно Гарри Поттеру придется пожертвовать всем в финальном сражении с Волан-де-Мортом.', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/407636.jpg', 101, 7, 8, 1),
(150, 'Брат', 'Демобилизовавшись, Данила Багров вернулся в родной городок. Но скучная жизнь российской провинции не устраивала его, и он решился податься в Петербург, где, по слухам, уже несколько лет процветает его старший брат. Данила нашел брата. Но все оказалось не так просто — брат работает наемным убийцей.', 8.3, 'https://kinopoiskapiunofficial.tech/images/posters/kp/41519.jpg', 102, 31, 1, 1),
(151, 'В бой идут одни «старики»', 'Эта эскадрилья стала «поющей» - так капитан Титаренко подбирал себе новичков. Его «старикам» было не больше двадцати, но «желторотиков», пополнение из летных училищ ускоренного выпуска, в бой все равно, по возможности, не пускали. \r\n\r\nИм еще многое предстояло испытать - и жар боев, и радость первой победы над врагом, и величие братства, скрепленного кровью, и первую любовь, и горечь утраты... И настанет день, когда по команде «в бой идут одни старики» бывшие желторотики бросятся к своим самолетам...', 8.7, 'https://kinopoiskapiunofficial.tech/images/posters/kp/25108.jpg', 103, 28, 40, 1),
(152, 'Пираты Карибского моря: Проклятие Черной жемчужины', 'Жизнь харизматичного авантюриста, капитана Джека Воробья, полная увлекательных приключений, резко меняется, когда его заклятый враг капитан Барбосса похищает корабль Джека Черную Жемчужину, а затем нападает на Порт Ройал и крадет прекрасную дочь губернатора Элизабет Свонн.\n\nДруг детства Элизабет Уилл Тернер вместе с Джеком возглавляет спасательную экспедицию на самом быстром корабле Британии, чтобы вызволить девушку и заодно отобрать у злодея Черную Жемчужину. Вслед за этой парочкой отправляется амбициозный коммодор Норрингтон, который к тому же числится женихом Элизабет.\n\nОднако Уилл не знает, что над Барбоссой висит вечное проклятие, при лунном свете превращающее его с командой в живых скелетов. Проклятье будет снято лишь тогда, когда украденное золото Ацтеков будет возвращено пиратами на старое место.', 8.4, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4374.jpg', 7, 15, 2, 1),
(153, 'Офицеры', 'Судьбы двух друзей - Алексея Трофимова и Ивана Вараввы - прослеживаются на протяжении многих лет. В 20-е они вместе служили на пограничной заставе, бились с басмачами. Там они, будучи еще совсем молодыми, на всю жизнь запомнили наказ своего командира: «Есть такая профессия - родину защищать». Потом Испания, Великая Отечественная война и мирные дни. Старые друзья снова встречаются, уже став генералами.', 8.5, 'https://kinopoiskapiunofficial.tech/images/posters/kp/42736.jpg', 104, 33, 40, 1),
(154, 'Титаник', 'В первом и последнем плавании шикарного «Титаника» встречаются двое. Пассажир нижней палубы Джек выиграл билет в карты, а богатая наследница Роза отправляется в Америку, чтобы выйти замуж по расчёту. Чувства молодых людей только успевают расцвести, и даже не классовые различия создадут испытания влюблённым, а айсберг, вставший на пути считавшегося непотопляемым лайнера.', 8.4, 'https://kinopoiskapiunofficial.tech/images/posters/kp/2213.jpg', 105, 31, 32, 1),
(155, 'Брат 2', 'Участвуя в программе на телевидении, Данила Багров встречает своих друзей по службе в Чечне. Одного из них внезапно убивают. Выясняется, что у того были неприятности из-за брата-хоккеиста в Америке. Данила должен разобраться. Он вылетает в Америку и за компанию берёт с собой старшего брата.', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/41520.jpg', 106, 22, 42, 1),
(156, 'Гладиатор', 'В великой Римской империи не было военачальника, равного генералу Максимусу. Непобедимые легионы, которыми командовал этот благородный воин, боготворили его и могли последовать за ним даже в ад.\n\nНо случилось так, что отважный Максимус, готовый сразиться с любым противником в честном бою, оказался бессилен против вероломных придворных интриг. Генерала предали и приговорили к смерти. Чудом избежав гибели, Максимус становится гладиатором.\n\nБыстро снискав себе славу в кровавых поединках, он оказывается в знаменитом римском Колизее, на арене которого он встретится в смертельной схватке со своим заклятым врагом...', 8.6, 'https://kinopoiskapiunofficial.tech/images/posters/kp/474.jpg', 107, 22, 43, 1),
(157, 'Жизнь прекрасна', 'Во время Второй мировой войны из Италии в концлагерь были отправлены евреи - отец с маленьким сыном. Жена-итальянка добровольно последовала за ними. В лагере отец сказал мальчику, что всё происходящее вокруг является большой интересной игрой за приз в виде настоящего танка. И этот классный приз достанется тому мальчику, который сможет не попасться на глаза надзирателям.', 8.6, 'https://kinopoiskapiunofficial.tech/images/posters/kp/381.jpg', 108, 31, 44, 1),
(158, 'Служебный роман', 'Анатолий Ефремович Новосельцев, рядовой служащий одного статистического управления — человек робкий и застенчивый. Ему хотелось бы получить вакантное место зав. отделом, но он не знает как подступиться к этому делу. Старый приятель Самохвалов советует ему приударить за Людмилой Прокофьевной Калугиной — сухарем в юбке и директором заведения.', 8.3, 'https://kinopoiskapiunofficial.tech/images/posters/kp/43869.jpg', 41, 43, 40, 1),
(159, 'Мой сосед Тоторо', 'Сестры Сацуки и Мэй переезжают вместе с папой в деревенский дом. Однажды девочки обнаруживают, что по соседству с ними живут лесные духи — хранители леса во главе со своим могущественным и добрым повелителем Тоторо. Постепенно Тоторо становится другом девочек, помогая им в их повседневных приключениях.', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/8221.jpg', 56, 40, 9, 1),
(160, 'Карты, деньги, два ствола', 'Четверо молодых парней накопили каждый по 25 тысяч фунтов, чтобы один из них мог сыграть в карты с опытным шулером и матерым преступником, известным по кличке Гарри-Топор. Парень в итоге проиграл 500 тысяч, на уплату долга ему дали неделю.\n\nВ противном случае и ему и его «спонсорам» каждый день будут отрубать по пальцу, а потом... Чтобы выйти из положения, ребята решили ограбить бандитов, решивших ограбить трех «ботаников», выращивающих марихуану для местного наркобарона. Но на этом приключения четверки не заканчиваются...', 8.6, 'https://kinopoiskapiunofficial.tech/images/posters/kp/522.jpg', 14, 44, 28, 1),
(161, 'Мой Хатико', 'Начало 2000-х годов. Во время поездки за город с коллегами немолодой университетский преподаватель Чэнь подбирает на дороге грязного и испуганного щенка. Никто не соглашается взять пёсика себе, поэтому мужчине приходится втихаря принести его домой, хотя супруга терпеть не может собак. Пообещав, что найдёт щенку новый дом, Чэнь тем не менее отказывает всем претендентам — так пёс получает кличку Хатико и становится новым членом семьи.', 8.6, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4395219.jpg', 109, 1, 37, 1),
(162, 'Пианист', 'Фильм снят по автобиографии Владислава Шпильмана, одного из лучших пианистов Польши 30-х годов прошлого века. Главный герой фильма — Владек — занимается искусством до тех пор, пока территорию Польши не занимают нацисты. Жизнь всех евреев меняется: их помещают в Варшавское гетто, запрещают работать, унижают, заставляют носить отличительные повязки, а через некоторое время отправляют в концлагерь.', 8.5, 'https://kinopoiskapiunofficial.tech/images/posters/kp/355.jpg', 110, 25, 45, 1),
(163, 'Пеле: Рождение легенды', 'История стремительного восхождения талантливого мальчика Пеле из трущоб Сан-Паулу - от дворовой босоногой команды до победы на Чемпионате мира.', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/803422.jpg', 111, 13, 2, 1),
(164, 'Принцесса Мононоке', 'Убив вепря, юный принц Аситака навлек на себя смертельное проклятие. Старая знахарка предсказала, что только он сам способен изменить свою судьбу, и отважный воин отправился в опасное путешествие. Так он оказался в загадочной стране, где люди под предводительством злой госпожи Эбоси воевали с обитателями леса: духами, демонами и гигантскими существами, каких Аситака раньше никогда не видел. \n\nИ была с ними принцесса Мононоке - повелительница зверей и дочь волчицы. Теперь судьба всех зависит только от одного воина - принца Аситаки.', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/441.jpg', 112, 31, 9, 1),
(165, 'Песнь моря', 'Десятилетний Бен живет на островном маяке вместе с отцом Конором и маленькой сестренкой Сиршей. Девочка все никак не заговорит, но зато обнаруживается, что она шелки, то есть принадлежит к народу людей-тюленей, как и исчезнувшая шесть лет назад мать. Напуганный Конор отправляет детей в город к бабушке, но Бен жаждет вернуться, а Сиршу продолжает звать море. Так начинается их полное приключений путешествие домой.', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/714248.jpg', 113, 5, 46, 1),
(166, 'Судьба человека', 'Фильм рассказывает о русском солдате, которого война подвергла страшным испытаниям, лишила дома и семьи, бросила в концлагерь. Но судьба не сломила его дух - он выжил, отстоял своё право быть человеком, сохранил способность любить...', 8.4, 'https://kinopoiskapiunofficial.tech/images/posters/kp/44027.jpg', 93, 45, 40, 1),
(167, 'Укрощение строптивого', 'Категорически не приемлющий женского общества грубоватый фермер вполне счастлив и доволен своей холостяцкой жизнью. Но неожиданно появившаяся в его жизни женщина пытается изменить его взгляды на жизнь и очаровать его.', 8.4, 'https://kinopoiskapiunofficial.tech/images/posters/kp/63912.jpg', 16, 46, 44, 1),
(168, 'Тот самый Мюнхгаузен', 'Комическая фантазия о жизни, любви и смерти знаменитого барона Мюнхгаузена, жившего в XVIII веке и ставшего героем многих веселых книг и преданий, опирается на персонажей и эпизоды знаменитого романа Р. Распе, но по сути является самостоятельным произведением.\n\n«Мыслящий человек просто обязан время от времени поднимать себя за волосы» - похоже, это и удается авторам картины. Барон хочет жениться на любимой им Марте, но церковь отказывается обвенчать их, так как имеется живая жена, «усмирявшая его 20 лет». Уставшая Марта хочет, чтобы барон стал таким, как все, но барон этого не хочет, да и не может.\n\nГерцог разрешит брак только в том случае, если барон письменно подтвердит, что все его истории лживы, а он сам - обыкновенный человек.', 8.3, 'https://kinopoiskapiunofficial.tech/images/posters/kp/77283.jpg', 114, 30, 40, 1),
(169, 'Джанго освобожденный', 'Шульц — эксцентричный охотник за головами, который выслеживает и отстреливает самых опасных преступников. Он освобождает раба по имени Джанго, поскольку тот может помочь ему в поисках трёх бандитов. Джанго знает этих парней в лицо, ведь у него с ними свои счёты.', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/586397.jpg', 115, 2, 2, 1),
(170, 'Мужики!..', 'Узнав о том, что умерла его бывшая невеста, шахтер Павел Зубов приезжает в родное село. У него на руках оказываются оставшиеся сиротами трое детей. Старшая дочь — его, Павла. Осознание ответственности перед нею приводит Павла к мужественному решению: он становится отцом всем троим детям.', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/46745.jpg', 13, 29, 40, 1),
(171, 'Матрица', 'Жизнь Томаса Андерсона разделена на две части: днём он — самый обычный офисный работник, получающий нагоняи от начальства, а ночью превращается в хакера по имени Нео, и нет места в сети, куда он бы не смог проникнуть. Но однажды всё меняется. Томас узнаёт ужасающую правду о реальности.', 8.5, 'https://kinopoiskapiunofficial.tech/images/posters/kp/301.jpg', 15, 20, 17, 1),
(172, 'Маленький принц', 'Мир невозможен без фантазии и приключений. По крайней мере в это верит добродушный старик авиатор, по соседству с которым недавно поселилась одна очень педантичная мама со своей прилежной дочкой. Жизнь девочки подчинена строгому учебному плану, в котором время на друзей предусмотрено только следующим летом. Однако этот тщательно выстроенный план трещит по швам, когда в жизнь девочки врывается странный сосед с его невероятными рассказами о Маленьком Принце и далеких звездах. Осталось только починить самолет, и в путь! Так начинается большое путешествие девочки - полное опасностей, волшебства, юмора и настоящей дружбы.', 8.1, 'https://kinopoiskapiunofficial.tech/images/posters/kp/572553.jpg', 116, 13, 47, 1),
(173, 'Хоббит: Нежданное путешествие', 'Хоббит Бильбо Бэггинс пускается в грандиозный поход, целью которого является отвоевание утраченного королевства гномов Эребор у дракона Смауга. Совершенно неожиданно с хоббитом налаживает контакт волшебник Гэндальф Серый. Так Бильбо находит себя и присоединяется к компании тринадцати гномов, возглавляемых легендарным воином Торином Дубощитом. Их путешествие пройдёт через Дикий Край, предательские земли, населенные гоблинами и орками, смертоносными варгами, гигантскими пауками, меняющим шкуры народом и волшебниками.\n\nИ хотя их цель находится на Востоке, среди пустошей Одинокой Горы, сначала им придется выбраться из туннелей гоблинов, где Бильбо встретит существо, которое изменит его жизнь навсегда - Голлума.', 8.1, 'https://kinopoiskapiunofficial.tech/images/posters/kp/278522.jpg', 7, 2, 31, 1),
(174, 'Иди и смотри', '1943 год, Великая Отечественная война. Подросток Флёра, откопав карабин среди обрывков колючей проволоки, ржавых пулемётных лент и простреленных касок, отправляется в лес к партизанам.', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/42571.jpg', 91, 36, 40, 1),
(175, 'Пятый элемент', 'Каждые пять тысяч лет открываются двери между измерениями и темные силы стремятся нарушить существующую гармонию. Каждые пять тысяч лет Вселенной нужен герой, способный противостоять этому злу. XXIII век. Нью-йоркский таксист Корбен Даллас должен решить глобальную задачу - спасение всего рода человеческого.\n\nЗло в виде раскаленной массы, наделенной интеллектом, надвигается на Землю. Победить его можно, только лишь собрав воедино четыре элемента (они же стихии - земля, вода, воздух и огонь) и добавив к ним загадочный пятый элемент.', 8.1, 'https://kinopoiskapiunofficial.tech/images/posters/kp/2656.jpg', 117, 31, 48, 1),
(176, 'Ведьмина служба доставки', 'Молодая ведьма Кики по достижении 13 лет должна прожить среди людей определённое время. Вместе с котом Дзидзи она отправляется в город, где знакомится с добрым пекарем, который помогает ей начать собственное дело - экстренную службу доставки. Новая работа знакомит Кики со множеством различных людей и предоставляет возможность обрести новых друзей и совершить массу всевозможных проделок.', 8.1, 'https://kinopoiskapiunofficial.tech/images/posters/kp/2428.jpg', 118, 47, 9, 1),
(177, 'Белый Бим Черное ухо', 'Трогательная лирическая киноповесть о судьбе собаки, теряющей любимого хозяина, об отношении людей к «братьям меньшим», которое как рентгеном просвечивает души, выявляя в одних низость и мелочную подлость, а в других - благородство, способность сострадать и любить…', 8.4, 'https://kinopoiskapiunofficial.tech/images/posters/kp/46068.jpg', 13, 48, 40, 1),
(178, 'Шерлок Холмс и доктор Ватсон: Сокровища Агры', 'Здесь есть все — таинственные обстоятельства убийства, сверкающие драгоценности, колоритнейшие фигуры. Но главное — в ходе расследования доктор Ватсон встречает женщину, с которой, быть может, надолго свяжет свою жизнь...', 8.4, 'https://kinopoiskapiunofficial.tech/images/posters/kp/77264.jpg', 119, 49, 40, 1),
(179, 'Хоббит: Битва пяти воинств', 'Когда отряд из тринадцати гномов нанимал хоббита Бильбо Бэгинса в качестве взломщика и четырнадцатого, «счастливого», участника похода к Одинокой горе, Бильбо полагал, что его приключения закончатся, когда он выполнит свою задачу - найдет сокровище, которое так необходимо предводителю гномов Торину. Путешествие в Эребор, захваченное драконом Смаугом королевство гномов, оказалось еще более опасным, чем предполагали гномы и даже Гэндальф - мудрый волшебник, протянувший Торину и его отряду руку помощи.\n\nВ погоню за гномами устремилась армия орков, ведомых пробудившимся в руинах древним злом, а эльфы и люди, с которыми Бильбо и его товарищам пришлось иметь дело во время путешествия и которые пострадали от последствий желания гномов вернуть свой дом, предъявили права на щедрое вознаграждение - часть сокровищ Одинокой горы. Скоро неподалеку от Одинокой горы встретятся пять армий, и лишь кровопролитная битва определит результаты смелого гномьего похода.', 7.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/694633.jpg', 7, 5, 31, 1),
(180, 'Лев', 'Сару, мальчик из трущоб, потерялся в возрасте пяти лет. История об удивительных поворотах его судьбы и поисках семьи.', 8.1, 'https://kinopoiskapiunofficial.tech/images/posters/kp/864138.jpg', 64, 50, 49, 1),
(181, 'Престиж', 'Роберт и Альфред - фокусники-иллюзионисты, которые на рубеже XIX и XX веков соперничали друг с другом в Лондоне. С годами их дружеская конкуренция на профессиональной почве перерастает в настоящую войну.\n\nОни готовы на все, чтобы выведать друг у друга секреты фантастических трюков и сорвать их исполнение. Непримиримая вражда, вспыхнувшая между ними, начинает угрожать жизни окружающих их людей…', 8.5, 'https://kinopoiskapiunofficial.tech/images/posters/kp/195334.jpg', 120, 9, 8, 1),
(182, 'Крестный отец', 'Криминальная сага, повествующая о нью-йоркской сицилийской мафиозной семье Корлеоне. Фильм охватывает период 1945-1955 годов.\n\nГлава семьи, Дон Вито Корлеоне, выдаёт замуж свою дочь. В это время со Второй мировой войны возвращается его любимый сын Майкл. Майкл, герой войны, гордость семьи, не выражает желания заняться жестоким семейным бизнесом. Дон Корлеоне ведёт дела по старым правилам, но наступают иные времена, и появляются люди, желающие изменить сложившиеся порядки. На Дона Корлеоне совершается покушение.', 8.7, 'https://kinopoiskapiunofficial.tech/images/posters/kp/325.jpg', 5, 35, 2, 1),
(183, 'По соображениям совести', 'Медик американской армии времён Второй мировой войны Десмонд Досс, который служил во время битвы за Окинаву, отказывается убивать людей и становится первым идейным уклонистом в американской истории, удостоенным Медали Почёта.', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/649917.jpg', 24, 50, 50, 1),
(184, 'Эрнест и Селестина: Приключения мышки и медведя', 'Большая дружба начинается с малого... Она — маленькая мышка, он — огромный медведь. Она — ребенок, он — взрослый. Она мечтает быть художницей, хотя по правилам своего мира должна стать дантистом, он — музыкант и поэт, ведущий бездумную жизнь и никогда не имеющий куска хлеба на завтра. Они живут в разных мирах: для обитателей мышиного царства нет ничего более дикого, чем подружиться с «большим плохим медведем», да и его соседи вряд ли поймут, зачем водиться с мышкой. Но дружба и родство душ сродни настоящему волшебству. И какое этой парочке дело до условностей, разницы в размере, исторических предрассудков и культурных барьеров?', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/592260.jpg', 121, 2, 51, 1),
(185, 'Прислуга', 'Американский Юг, на дворе 1960-е годы. Скитер только-только закончила университет и возвращается домой, в сонный городок Джексон, где никогда ничего не происходит. Она мечтает стать писательницей, вырваться в большой мир. Но для приличной девушки с Юга не пристало тешиться столь глупыми иллюзиями, приличной девушке следует выйти замуж и хлопотать по дому.\n\nМудрая Эйбилин на тридцать лет старше Скитер, она прислуживает в домах белых всю свою жизнь, вынянчила семнадцать детей и давно уже ничего не ждет от жизни, ибо сердце ее разбито после смерти единственного сына.\n\nМинни - самая лучшая стряпуха во всем Джексоне, а еще она самая дерзкая служанка в городе. И острый язык не раз уже сослужил ей плохую службу. На одном месте Минни никогда подолгу не задерживается. Но с Минни лучше не связываться даже самым высокомерным белым дамочкам. Двух черных служанок и белую неопытную девушку объединяет одно - обостренное чувство справедливости и желание хоть как-то изменить порядок вещей. Смогут ли эти трое противостоять целому миру? Сумеют ли они выжить в этой борьбе?', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/470553.jpg', 13, 7, 34, 1),
(186, '12 разгневанных мужчин', 'Юношу обвиняют в убийстве собственного отца, ему грозит электрический стул. Двенадцать присяжных собираются, чтобы вынести вердикт: виновен или нет. С начала заседания почти все считают подсудимого виновным, и лишь только один из двенадцати позволил себе усомниться. И он решает убедить остальных в своей правоте.', 8.5, 'https://kinopoiskapiunofficial.tech/images/posters/kp/346.jpg', 122, 51, 2, 1),
(187, 'Мадагаскар', 'Четверо изнеженных животных из Центрального зоопарка в Нью-Йорке - лев Алекс, зебра Марти, жираф Мелман и гиппопотамиха Глория - решаются на побег. Оказавшись после кораблекрушения на экзотическом острове Мадагаскар, населенном лемурами и поедающими их фоссами, путешественники с ужасом понимают, что с городскими привычками им придется распрощаться. \r\n\r\nЗдесь нет людей, любимых клеток, вкусной кормежки. Начинается шоу «Последний герой» только с животными - нашим друзьям нужно выжить в непривычной среде обитания, где на каждом шагу подстерегает опасность...', 8.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/6006.jpg', 52, 24, 2, 1),
(188, 'Гарри Поттер и Кубок огня', 'Гарри Поттер, Рон и Гермиона возвращаются на четвёртый курс школы чародейства и волшебства Хогвартс. При таинственных обстоятельствах Гарри был отобран в число участников опасного соревнования — Турнира Трёх Волшебников, однако проблема в том, что все его соперники — намного старше и сильнее.\n\nК тому же, знаки указывают на возвращение Лорда Волдеморта. Вскоре Гарри предстоит побороться не только за победу в соревновании, но и, прежде всего, за свою жизнь.', 8.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/8408.jpg', 30, 24, 8, 1),
(189, '12 стульев', 'Во время революции и последовавшего за ней краткого периода военного коммунизма многие прятали свои ценности как можно надежнее. И вот Ипполит Матвеевич Воробьянинов, бывший Старгородский предводитель дворянства и светский лев, а ныне - скромный делопроизводитель ЗАГСа, узнает от умирающей тещи, что некогда она спрятала свои бриллианты и жемчуга в общей сложности на 150 000 золотых рублей под обивку одного из двенадцати стульев гостиного гарнитура работы известного мастера Гамбса.\n\nБросив все, Воробьянинов бросается на поиски стульев, в чем ему, конечно же, небескорыстно, берется помочь молодой авантюрист, «великий комбинатор» Остап Бендер. Найти следы разрозненного гарнитура непросто. Не облегчает положения и то, что перед смертью теща Воробьянинова открыла тайну сокровищ и своему исповеднику, отцу Федору, всю жизнь мечтавшему о собственном свечном заводике в Самаре...', 8.3, 'https://kinopoiskapiunofficial.tech/images/posters/kp/46789.jpg', 123, 33, 40, 1),
(190, 'Вам и не снилось...', 'Школьники Роман и Катя тянутся друг к другу со всей безоглядностью первой любви. Мать Кати очень счастлива во втором браке и в озарении этого счастья хорошо понимает дочь. Роман находит поддержку у отца, давно и безответно любящего Катину маму. Но рядом ходят люди, ничего не знающие о любви...', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/45660.jpg', 77, 46, 40, 1),
(191, 'Остров сокровищ', 'Шхуна «Испаньола» бороздит морские просторы в поисках острова, на котором спрятаны легендарные сокровища пиратского капитана Флинта. На корабле зреет заговор. Разбойники во главе с одноногим Джоном Сильвером, кажется, близки к цели.', 8.3, 'https://kinopoiskapiunofficial.tech/images/posters/kp/573759.jpg', 124, 40, 40, 1),
(192, 'Шоу Трумана', 'Представьте себе, что вы вдруг начинаете понимать, что все вокруг вас — декорации, а люди — актеры, притворяющиеся теми, кем они вам кажутся. Весь ваш мир оказывается большим телесериалом, где вы исполняете главную роль, даже не подозревая об этом. Вся ваша жизнь — результат работы автора телешоу, которое вот уже тридцать лет смотрит вся планета, начиная с момента вашего рождения.\n\n В такой ситуации оказался Труман, главный герой картины. Будет ли он продолжать жить в безопасном мире, где, как он теперь знает, у него практически нет свободы выбора, или все-таки выйдет из «игры» и станет сам хозяином своей судьбы, в которой его ждет не запланированная сценарием девушка?', 8.3, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4541.jpg', 125, 44, 2, 1),
(193, 'Дело храбрых', 'История о команде пожарных под названием Granite Mountain Hotshots, столкнувшихся в Аризоне с одним из самых смертоносных пожаров в истории.', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/965754.jpg', 126, 16, 2, 1),
(194, 'Крик тишины', 'Блокадный Ленинград, февраль 1942 года. Заканчивается самая страшная блокадная зима. Зина Воронова совсем отчаялась. Ее трёхлетний сын Митя ослабел, а карточки на хлеб уже отоварены на два дня вперед. Последняя надежда — эвакуация. Но с маленькими детьми не берут. Тогда женщина идет на чудовищный шаг — эвакуируется, оставив сына одного в промерзшей квартире. Во время налета мальчика спасает девочка-подросток Катя. Девочка выдает Митю за своего брата и обещает себе сделать все, чтобы Митя выжил. Несмотря ни на что.', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1228407.jpg', 91, 8, 1, 1),
(195, 'Один дома 2: Затерянный в Нью-Йорке', 'Самый маленький герой Америки устраивает большой переполох в Нью-Йорке! Кевин МакКалистер вернулся! Но теперь он один не дома, а в Нью-Йорке и у него достаточно денег и кредитных карточек, чтобы превратить Большое Яблоко в собственную площадку для игр.\n\nНо, как всегда, Кевину не суждено быть долго одному: его старые приятели ― жулики Гарри и Марв ― сбежали из тюрьмы, куда они попали стараниями Кевина. И надо же им было попасть именно в тот город, где Кевин планировал поразвлечься! Новые западни и ловушки уже ждут горе-бандитов.', 8.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/5928.jpg', 21, 52, 2, 1),
(196, 'Крестный отец 2', 'Для дона Корлеоне и его сына не существует моральных преград на пути к достижению целей. Они превращают мафию, построенную по патриархальным сицилийским законам, в весьма прагматичную, жесткую корпорацию, плавно интегрируя её в большой бизнес Америки.', 8.5, 'https://kinopoiskapiunofficial.tech/images/posters/kp/327.jpg', 5, 53, 2, 1),
(197, 'В августе 44-го', 'Лето 1944. До Великой Победы остается еще около года. Белоруссия уже освобождена, однако с ее территории регулярно выходит в эфир группа лазутчиков, передавая врагам очень важную информацию о советских войсках. На поиски шпионов, в район регулярных выходов в эфир запеленгованной рации, был послан отряд разведчиков, во главе с офицером СМЕРШа.', 8.1, 'https://kinopoiskapiunofficial.tech/images/posters/kp/41381.jpg', 127, 11, 52, 1),
(198, 'Пираты Карибского моря: Сундук мертвеца', 'Вновь оказавшись в ирреальном мире, лихой капитан Джек Воробей неожиданно узнает, что является должником легендарного капитана «Летучего Голландца» Дэйви Джонса. Джек должен в кратчайшие сроки решить эту проблему, иначе ему грозит вечное проклятие и рабское существование после смерти. Вдобавок ко всему, срывается свадьба Уилла Тернера и Элизабет Суонн, которые вынуждены составить Джеку компанию в его злоключениях…', 8.1, 'https://kinopoiskapiunofficial.tech/images/posters/kp/63991.jpg', 7, 9, 2, 1),
(199, 'Летят журавли', 'Рассказ о людях, в чьи судьбы безжалостно вторглась война. Не все смогли с честью вынести это испытание. В центре киноповести - трагическая история двух влюбленных, которых разлучила война.', 8.3, 'https://kinopoiskapiunofficial.tech/images/posters/kp/7724.jpg', 128, 54, 40, 1),
(200, 'Двухсотлетний человек', 'Начало нового тысячелетия; происходит прорыв в глобальных технологиях. Люди уже не заводят дома собак и кошек: они покупают себе роботов. Вот и семья Мартинов приобретает себе необычный подарок: робота нового поколения NDR-114, а в обычной жизни просто Эндрю.\n\nКупленный как прибор, запрограммированный для выполнения домашней работы, Эндрю вдруг начинает испытывать странные ощущения. Он еще не знает, что это называется чувствами.', 8.1, 'https://kinopoiskapiunofficial.tech/images/posters/kp/7640.jpg', 129, 20, 13, 1),
(201, 'На войне как на войне', 'Младшего лейтенанта, только закончившего военное училище, назначили командиром «самоходки» с экипажем опытных и бывалых бойцов. Об их жизни, боевой и будничной рассказывает этот фильм.', 8.4, 'https://kinopoiskapiunofficial.tech/images/posters/kp/46285.jpg', 93, 41, 40, 1),
(202, 'Гарри Поттер и Принц-полукровка', 'Теперь не только мир волшебников, но и мир маглов ощущает на себе всевозрастающую силу Волан-де-Морта, а Хогвартс уже никак не назовешь надежным убежищем, каким он был раньше. Гарри подозревает, что в самом замке затаилась некая опасность, но Дамблдор больше сосредоточен на том, чтобы подготовить его к финальной схватке, которая, как он знает, уже не за горами. Вместе они пытаются разгадать секрет бессмертия Волан-де-Морта, а для этого Дамблдор приглашает на должность преподавателя по зельеварению своего старинного друга и коллегу — профессора Горация Слизнорта, который обожает устраивать вечеринки для избранных и гордится своими обширными связями в высших кругах. Но этот бонвиван и не подозревает, что как раз от него Дамблдор надеется заполучить самую важную информацию о крестражах.\n\nТем временем учеников атакуют самые разные враги, а подростковые эмоции хлещут через край. Гарри начинает понимать, что становится все более неравнодушным к Джинни, однако, и Дин Томас тоже. А Лаванда Браун вбила себе в голову, что Рон — тот самый единственный, которого она ждет, да вот только не учла волшебного эффекта шоколадных конфет Ромильды Вейн! Ну и, наконец, Гермиона пылает жгучей ревностью, но старается не показывать своих чувств. Пока романтические отношения расцветают, лишь один ученик остается в стороне. Он твердо намерен оставить свою метку, темную метку. Любовь витает в воздухе, но впереди ждет беда, и Хогвартс, возможно, уже никогда не будет прежним.', 7.8, 'https://kinopoiskapiunofficial.tech/images/posters/kp/89515.jpg', 30, 10, 8, 1),
(203, 'Вторая жизнь Уве', 'Уве - пожилой въедливый ворчун, достающий соседей вечными придирками. Он впадает в ярость при виде брошенного не туда мусора или неправильно припаркованной машины. И кроет на чем свет стоит легкомысленную семейку новосёлов, в которой папаша и гвоздя вбить не способен. Зато Уве умеет всё. В доме и в гараже у него всегда идеальный порядок. Как и в мыслях. Вот только жизнь давно перестала иметь для него смысл.', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/848894.jpg', 41, 13, 53, 1),
(204, 'Рататуй', 'Крыс Реми обладает уникальным вкусом. Он готов рисковать собственной жизнью, чтобы посмотреть любимое кулинарное шоу и раздобыть какую-нибудь приправку или просто свежий продукт. Реми живет со своими сородичами, которые его не понимают и не принимают его увлечения кулинарией. Когда Реми случайно попадает на кухню шикарного ресторана, он решает воспользоваться выпавшим ему шансом и проверить свои навыки. \n\nНа эту же кухню попадает и юный Лингвини. Всё, на что он может рассчитывать — это должность уборщика. Но он тоже получает свой шанс.', 8.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/89514.jpg', 60, 55, 2, 1),
(205, 'Твоё имя', 'Токийский парень Таки и провинциальная девушка Мицуха обнаруживают, что между ними существует странная связь. Во сне они меняются телами и проживают жизни друг друга. Но однажды эта способность исчезает так же внезапно, как появилась. Таки решает во что бы то ни стало отыскать Мицуху.', 8.4, 'https://kinopoiskapiunofficial.tech/images/posters/kp/958722.jpg', 130, 50, 9, 1),
(206, 'Человек-паук: Через вселенные', 'Мы всё знаем о Питере Паркере. Он спас город, влюбился, а потом спасал город снова и снова… Но все это – в нашем измерении. А что если в результате работы гигантского коллайдера откроется окно из одного измерения в другое? Найдется ли в нем свой Человек-паук? И как он будет выглядеть? Приготовьтесь к тому, что в разных вселенных могут быть разные Люди-пауки и однажды им придется собраться вместе для борьбы с почти непобедимым врагом.', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/920265.jpg', 131, 6, 19, 1),
(207, 'Брестская крепость', 'История о героической обороне Брестской крепости, которая приняла на себя первый удар немецко-фашистских захватчиков 22 июня 1941 года. Рассказ о трёх главных очагах сопротивления, возглавляемых командиром полка Петром Гавриловым, комиссаром Ефимом Фоминым и начальником 9-й погранзаставы Андреем Кижеватовым.', 8.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/436263.jpg', 132, 19, 52, 1),
(208, 'Навсикая из долины ветров', 'Будущее. После ядерной войны Землю постигла ужасная экологическая катастрофа. Поверхность планеты почти целиком покрывают леса, испускающие в атмосферу ядовитые споры растений. Оставшиеся в живых люди живут в зонах, ещё не покрытых лесами, и периодически сталкиваются с чудовищными насекомообразными монстрами. Долина ветров — одно из царств, образовавшихся на руинах прежних государств. Им управляет отважная принцесса Навсикая. Но мирное существование Долины ветров нарушается, когда маленькая страна сталкивается с воинственными соседями, которые стремятся воссоздать опасное оружие, способное окончательно уничтожить планету.', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/8240.jpg', 133, 56, 9, 1),
(209, 'Хоббит: Пустошь Смауга', 'Продолжение путешествия хоббита Бильбо Бэггинса, волшебника Гэндальфа и 13 отважных гномов. Их компания должна добраться до Одинокой горы. А там они встретятся с величайшей опасностью из всех — созданием куда более ужасающим, чем все их прошлые противники, чудовищем, которое проверит на прочность не только их мужество, но крепость их дружбы и правильность выбранного пути, — драконом Смаугом.', 8.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/408876.jpg', 7, 17, 31, 1);
INSERT INTO `media` (`id`, `title`, `description`, `rating`, `image_url`, `genre_id`, `year_id`, `country_id`, `type_id`) VALUES
(210, 'Корпорация монстров', 'Склизкий гад в сливном бачке, мохнатый зверь, похожий на чудовище из «Аленького цветочка», гигантские мокрицы под кроватью — все они существуют на самом деле. Все, что им нужно — пугать детей, потому что из детских криков они получают электричество.\n\nПолнометражный мультфильм рассказывает о кризисах в мире монстров, их жизни. Но однажды вся мирная жизнь монстров оказывается под угрозой: в их мир попадает ребенок. А с детьми столько хлопот, что они могут довести даже монстров.', 8.1, 'https://kinopoiskapiunofficial.tech/images/posters/kp/458.jpg', 96, 11, 30, 1),
(211, 'Смех и горе у Бела моря', 'Мультипликационный фильм по произведениям Бориса Шергина и Степана Писахова.', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/279828.jpg', 134, 40, 40, 1),
(212, 'Приключения Паддингтона 2', 'В антикварном магазине Лондона обаятельный и хорошо воспитанный медведь Паддингтон находит уникальную старинную книгу. Пока он изо всех своих медвежьих сил старается накопить на неё, редчайшее издание внезапно похищают. Паддингтон оказывается втянут в аферу века, затеянную знаменитым, но вышедшим в тираж актером, который ныне рекламирует собачьи консервы, а свой талант к перевоплощению использует в охоте за сокровищами.', 8.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/906042.jpg', 59, 16, 54, 1),
(213, 'Назад в будущее 2', 'Продолжение фантастической истории о приключениях американского подростка во времени. На этот раз с помощью модернизированной Доком машины времени Марти из 80-х попадает в будущее.\n\nДети Марти в беде, и их надо выручать. Приходится повозиться со злодеем...', 8.3, 'https://kinopoiskapiunofficial.tech/images/posters/kp/5502.jpg', 135, 47, 2, 1),
(214, 'Укрась прощальное утро цветами обещания', 'Красавица Макия — из рода бессмертных. На протяжении веков многие армии пытались захватить её народ, чтобы завладеть секретом вечной жизни. И вот теперь, когда город разрушен, девушка прячется в лесу. Здесь она находит потерявшего родителей маленького мальчика Эриала и начинает о нём заботиться.', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1103852.jpg', 136, 6, 9, 1),
(215, 'Сестрёнка', 'Сколько себя помнит Ямиль, война была всегда. Но Ямиль очень ждёт, когда она кончится - ведь тогда вернётся Отец, которого Ямиль знает только по фотографиям и письмам.\n\nОднажды Мама уезжает в далёкий город и привозит с собой молчаливую девочку Оксану и передает наказ Отца заботиться о ней, как о родной сестрёнке...', 8.3, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1178267.jpg', 93, 8, 1, 1),
(216, 'Молчание ягнят', 'Психопат похищает и убивает молодых женщин по всему Среднему Западу. ФБР, уверенное, что все преступления совершены одним и тем же человеком, поручает агенту Клариссе Старлинг встретиться с заключенным-маньяком Ганнибалом Лектером, который мог бы помочь составить психологический портрет убийцы. Сам Лектер отбывает наказание за убийства и каннибализм. Он согласен помочь Клариссе лишь в том случае, если она попотчует его больное воображение подробностями своей личной жизни.', 8.3, 'https://kinopoiskapiunofficial.tech/images/posters/kp/345.jpg', 137, 12, 2, 1),
(217, 'Зверополис', 'Добро пожаловать в Зверополис – современный город, населенный самыми разными животными, от огромных слонов до крошечных мышек. Зверополис разделен на районы, полностью повторяющие естественную среду обитания разных жителей – здесь есть и элитный район Площадь Сахары и неприветливый Тундратаун. В этом городе появляется новый офицер полиции, жизнерадостная зайчиха Джуди Хоппс, которая с первых дней работы понимает, как сложно быть маленькой и пушистой среди больших и сильных полицейских. Джуди хватается за первую же возможность проявить себя, несмотря на то, что ее партнером будет болтливый хитрый лис Ник Уайлд. Вдвоем им предстоит раскрыть сложное дело, от которого будет зависеть судьба всех обитателей Зверополиса.', 8.3, 'https://kinopoiskapiunofficial.tech/images/posters/kp/775276.jpg', 138, 50, 2, 1),
(218, 'Знакомьтесь, Джо Блэк', 'В жизни богатого и влиятельного газетного магната Уильяма Пэрриша появляется сама Смерть, принявшая обличье обворожительного молодого человека по имени Джо Блэк.\n\nСмерть, уставшая от своих привычных обязанностей,предлагает Пэрришу необычное соглашение: магнат станет проводником Джо в мире живых, где тот планирует провести свой отпуск. По окончании каникул Смерть заберет Пэрриша с собой. С помощью Уильяма, загадочный и эксцентричный Джо начинает свое путешествие по бренной Земле.\n\nНо происходит непредвиденное. Оказывается, что тело погибшего мужчины, которое Смерть выбрала для себя, принадлежало юноше, в которого была влюблена дочь Пэрриша.', 8.1, 'https://kinopoiskapiunofficial.tech/images/posters/kp/5059.jpg', 139, 44, 2, 1),
(219, 'Покровские ворота', 'Если вы развелись, и ваша бывшая жена снова вышла замуж — это еще не значит, что вы свободны. Если вы пригласили девушку на свидание, и она пришла, это еще не значит, что она будет вашей. Но если при этом ваш сосед по коммуналке — аспирант Костик, то можете быть уверены — все будет хорошо.', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/77203.jpg', 140, 57, 40, 1),
(220, 'Игры разума', 'От всемирной известности до греховных глубин — все это познал на своей шкуре Джон Форбс Нэш-младший. Математический гений, он на заре своей карьеры сделал титаническую работу в области теории игр, которая перевернула этот раздел математики и практически принесла ему международную известность.\n\nОднако буквально в то же время заносчивый и пользующийся успехом у женщин Нэш получает удар судьбы, который переворачивает уже его собственную жизнь.', 8.5, 'https://kinopoiskapiunofficial.tech/images/posters/kp/530.jpg', 141, 11, 2, 1),
(221, 'Любовь и голуби', 'Ликвидируя неисправность лебедки, Василий Кузякин получил травму и путевку на юг. Там он встретил роковую женщину Раису Захаровну и… вернулся Вася с курорта не к себе в деревню, а в дом Раисы Захаровны. Началась для него новая жизнь, в которой было много непонятного и интересного, но не было дома, где остались Надя, дети и голуби.', 8.3, 'https://kinopoiskapiunofficial.tech/images/posters/kp/45146.jpg', 16, 56, 40, 1),
(222, 'Звёздные войны: Эпизод 3 — Месть ситхов', 'Идёт третий год Войн клонов. Галактическая Республика, некогда бывшая спокойным и гармоничным государством, превратилась в поле битвы между армиями клонов, возглавляемых канцлером Палпатином, и армадами дроидов, которых ведёт граф Дуку, тёмный лорд ситхов. Республика медленно погружается во тьму. Лишь рыцари-джедаи, защитники мира и справедливости, могут противостоять злу, которое вскоре поглотит галактику. Но настоящая битва идёт в душе у молодого рыцаря-джедая Энакина, который разрывается между долгом джедая и любовью к своей жене, сенатору Падме Амидале. И от того, какое чувство в нём победит, зависит будущее всего мира.', 8.1, 'https://kinopoiskapiunofficial.tech/images/posters/kp/5619.jpg', 53, 24, 55, 1),
(223, 'Война', 'Аслан Гугаев, командир отряда чеченских боевиков, отпускает троих пленников: двух русских солдат, сержанта Ивана Ермакова и рядового Кулика — потому что они не контрактники, а призывники, и англичанина Джона Бойла — потому что он должен собрать два миллиона фунтов стерлингов и привезти деньги Гугаеву в качестве выкупа за свою невесту Маргарет. Маргарет остается у Аслана. Так же, как и капитан российской армии Медведев...\n\nЗа отведенные ему два месяца Джон не находит нужную сумму и не находит поддержки у британских властей, зато, вернувшись в Россию, находит Ваню Ермакова, живущего в Тобольске. Джон и Ваня опять едут в Чечню. Чтобы освободить английскую девушку Маргарет и русского капитана Медведева...', 8.1, 'https://kinopoiskapiunofficial.tech/images/posters/kp/41431.jpg', 132, 25, 1, 1),
(224, 'Малышка на миллион', 'Тренеру по боксу Фрэнку Данну так и не удалось воспитать чемпиона. Он владеет спортивным залом в Лос-Анджелесе, где всё ещё проводит тренировки. Дочь не отвечает на его письма, а его лучший боец подписал контракт с другим менеджером. Неожиданно в жизни Фрэнка появляется Мэгги Фицжеральд, 31-летняя официантка, мечтающая стать боксером. Фрэнк не желает тренировать женщину, но упорство Мэгги заставляет его передумать. Впереди - их главное сражение, требующее собрать в кулак всю волю и мужество.', 8.1, 'https://kinopoiskapiunofficial.tech/images/posters/kp/81297.jpg', 142, 23, 2, 1),
(225, 'Холодное лето пятьдесят третьего...', '1953 год. Двое политических ссыльных вступают в схватку с бандой амнистированных уголовников.', 8.1, 'https://kinopoiskapiunofficial.tech/images/posters/kp/7660.jpg', 89, 58, 40, 1),
(226, 'Не может быть!', 'Фильм включает три новеллы о негативных явлениях провинциальной жизни молодой страны Советов: тупости, пьянстве, стяжательстве, бездуховности - всем том, что и сейчас существует благополучно и повсеместно.', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/46368.jpg', 16, 39, 40, 1),
(227, 'Мстители: Война бесконечности', 'Пока Мстители и их союзники продолжают защищать мир от различных опасностей, с которыми не смог бы справиться один супергерой, новая угроза возникает из космоса: Танос. Межгалактический тиран преследует цель собрать все шесть Камней Бесконечности - артефакты невероятной силы, с помощью которых можно менять реальность по своему желанию. Всё, с чем Мстители сталкивались ранее, вело к этому моменту – судьба Земли никогда ещё не была столь неопределённой.', 8.1, 'https://kinopoiskapiunofficial.tech/images/posters/kp/843649.jpg', 143, 6, 2, 1),
(228, 'Невероятный мир глазами Энцо', 'Для собаки по кличке Энцо жизнь – это гонка. Не важно, как ты ее проходишь – за рулем автомобиля или на четырех лапах, все равно тебя ждут крутые виражи, ямы-западни, опасные взлеты и падения. Они выбивают с трека даже самых сильных – это начинающий гонщик Дэнни и его пес Энцо знают наверняка. Каждому из них предстоит своя гонка, но оба понимают: победить не значит обогнать соперников. Победить – значит вернуться после поражения на трассу и пройти ее до самого финиша, какой бы скользкой ни была дорога.', 8.3, 'https://kinopoiskapiunofficial.tech/images/posters/kp/470191.jpg', 144, 8, 2, 1),
(229, 'Добро пожаловать, или Посторонним вход воспрещен', 'Пионер Костя Иночкин, будучи в пионерском лагере, переплыл реку и оказался на запретной для посещений территории, за что и был изгнан его начальником товарищем Дыниным. Не желая доводить бабушку до инфаркта своим досрочным прибытием, мальчик тайно возвращается в лагерь, где пионеры так же тайно содержат его и предпринимают все меры, чтобы не состоялся родительский день. Ведь именно в этот день Костина бабушка заявится в лагерь...', 8.3, 'https://kinopoiskapiunofficial.tech/images/posters/kp/44238.jpg', 34, 59, 40, 1),
(230, 'Человек-паук', 'Питер Паркер – обыкновенный школьник. Однажды он отправился с классом на экскурсию, где его кусает странный паук-мутант. Через время парень почувствовал в себе нечеловеческую силу и ловкость в движении, а главное – умение лазать по стенам и метать стальную паутину. Свои способности он направляет на защиту слабых. Так Питер становится настоящим супергероем по имени Человек-паук, который помогает людям и борется с преступностью. Но там, где есть супергерой, рано или поздно всегда объявляется и суперзлодей...', 7.7, 'https://kinopoiskapiunofficial.tech/images/posters/kp/838.jpg', 143, 25, 2, 1),
(231, 'Приключения Шерлока Холмса и доктора Ватсона: Охота на тигра', 'Доктор Ватсон рано похоронил своего друга в водах Рейхенбахского водопада. Шерлок Холмс не так прост. Он воскрес из мертвых, чтобы вступить в схватку с последним безжалостным убийцей из шайки гения преступного мира профессора Мориарти...', 8.4, 'https://kinopoiskapiunofficial.tech/images/posters/kp/368937.jpg', 18, 46, 40, 1),
(232, 'Рыбка Поньо на утесе', 'Маленькая любопытная рыбка Поньо — дочь колдуна и прекрасной морской богини — уплывает из дома, чтобы понаблюдать за жизнью людей. Поньо застревает в банке и оказывается выброшенной на берег. Её подбирает пятилетний Сосукэ. Малыши привязываются друг к другу, и теперь у Поньо только одно желание — стать человеком.', 8.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/261127.jpg', 56, 37, 9, 1),
(233, 'Семь', 'Детектив Уильям Сомерсет - ветеран уголовного розыска, мечтающий уйти на пенсию и уехать подальше от города и грешных обитателей. За 7 дней до пенсии на Сомерсета сваливаются две неприятности: молодой напарник Миллс и особо изощренное убийство. Острый ум опытного сыщика сразу определяет, что за этим преступлением, скорее всего, последуют другие. Новости подтверждают его догадку. Поняв, что убийца наказывает свои жертвы за совершенные ими смертные грехи, детектив встает перед выбором: вернуться к работе либо уйти и передать дело своему менее опытному напарнику?', 8.3, 'https://kinopoiskapiunofficial.tech/images/posters/kp/377.jpg', 45, 4, 2, 1),
(234, 'Терминал', 'Фильм рассказывает историю Виктора Наворски, отправившегося в Нью-Йорк из Восточной Европы. Пока Виктор летел в самолете, на его родине произошел государственный переворот. Оказавшись в международном аэропорту имени Джона Кеннеди с паспортом ниоткуда, он не имеет права въехать в Соединенные Штаты и должен коротать свои дни и ночи на скамейках у выхода 67, пока война в его родной стране не закончится.\n\nТянутся недели и месяцы, и Виктор обнаруживает, что небольшой мирок терминала может быть наполнен абсурдом, щедростью, амбициями, развлечениями, желанием сохранить свой статус, интуитивной прозорливостью и даже любовью к очаровательной стюардессе Амелии. Виктору удается завоевать симпатии всех, кроме одного человека — чиновника аэропорта Фрэнка Диксона, который считает его бюрократической ошибкой, проблемой, которую он не может контролировать, но от которой жаждет избавиться.', 8.1, 'https://kinopoiskapiunofficial.tech/images/posters/kp/6877.jpg', 41, 23, 2, 1),
(235, 'Бесславные ублюдки', 'Вторая мировая война. В оккупированной немцами Франции группа американских солдат-евреев наводит страх на нацистов, жестоко убивая и скальпируя солдат.', 8.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/9691.jpg', 145, 10, 13, 1),
(236, 'Мулан', 'Для великого народа наступили тяжелые времена: на страну напало воинственное племя гуннов. Переодевшись в мужскую одежду, Мулан присоединяется к другим воинам и отправляется в опасный поход к подножию заснеженных гор. Ее сопровождает забавный дракончик Мушу, который больше похож на маленькую собачку, чем на мифическое чудовище. \n\nПытаясь скрыть тайну, они попадают в забавные ситуации и не подозревают, что их секрет вот - вот раскроется!...', 8.1, 'https://kinopoiskapiunofficial.tech/images/posters/kp/5277.jpg', 146, 44, 30, 1),
(237, 'Небесный замок Лапута', 'Альтернативная реальность, соответствующая началу XX века. В руках девочки по имени Сита находится Летающий Камень. За ним охотятся агенты правительства и пираты, потому что Камень представляет огромную ценность. Пытаясь скрыться от преследователей, Сита встречает Падзу, своего ровесника, работающего в шахтерском городке. Вместе дети выясняют, что Камень — ключ к таинственному летающему острову Лапута.', 8.3, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1846.jpg', 56, 60, 9, 1),
(238, 'Привидение', 'Влюблённая пара Сэм и Молли возвращается домой после приятного вечера, когда на них нападает грабитель. Защищаясь, Сэм погибает и становится призраком. Он узнаёт, что его смерть не была случайной, а над его возлюбленной нависла смертельная опасность. Чтобы предупредить Молли, Сэм начинает обход практикующих медиумов и, о чудо! - находит женщину, которая действительно может его слышать. Только вот сама она не горит желанием помогать назойливому привидению.', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1991.jpg', 147, 12, 2, 1),
(239, 'Хороший, плохой, злой', 'Разгар Гражданской войны, Дикий Запад. По воле судьбы трое мужчин вынуждены объединить усилия в поисках украденного золота. Но совместная работа — не самое подходящее занятие для таких отъявленных бандитов. Компаньоны вскоре понимают, что в их дерзком и опасном путешествии по разоренной войной стране самое важное — никому не доверять и держать пистолет наготове.', 8.5, 'https://kinopoiskapiunofficial.tech/images/posters/kp/349.jpg', 148, 42, 56, 1),
(240, 'Гарри Поттер и Орден Феникса', 'Гарри проводит свой пятый год в школе Хогвартс и обнаруживает, что многие из членов волшебного сообщества отрицают факт недавнего состязания юного волшебника с воплощением вселенского зла Волдемортом. Все делают вид, что не имеют ни малейшего представления о том, что злодей вернулся. Однако впереди волшебников ждет необычная схватка.', 7.8, 'https://kinopoiskapiunofficial.tech/images/posters/kp/48356.jpg', 30, 55, 8, 1),
(241, 'Собачья жизнь', 'Собаки бывают разных пород, мастей и размеров. Они - наши самые верные и преданные друзья, а мы учим их хорошим манерам. Собаки всегда думают о нас, правда, иногда и о беконе. Все они каждый день провожают и встречают нас у порога в уверенности, что пока им есть, кого облизывать и любить, в их жизни есть смысл.', 8.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/571896.jpg', 149, 16, 34, 1),
(242, 'Вверх', '78-летний ворчун Карл Фредриксен считает, что жизнь обходит его стороной. Чтобы сдержать обещание, данное своей почившей жене, он решает осуществить свою мечту о великом приключении, привязав тысячи воздушных шариков к своему дому и улетев в дебри Южной Америки. Не пролетев и полмили, путешественник обнаруживает, что он ненароком прихватил с собой крайне разговорчивого и неисправимо жизнерадостного 8-летнего мальчика по имени Рассел...', 8.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/325381.jpg', 150, 10, 30, 1),
(243, 'Гарри Поттер и Дары Смерти: Часть I', 'Гарри Поттера ждёт самое страшное испытание в жизни — смертельная схватка с Волан-де-Мортом. Ждать помощи не от кого — Гарри одинок, как никогда… Друзья и враги Гарри предстают в совершенно неожиданном свете. Граница между Добром и Злом становится всё призрачнее…', 7.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/276762.jpg', 30, 19, 8, 1),
(244, 'Общество мертвых поэтов', 'Джон Китинг — новый преподаватель английской словесности в консервативном американском колледже. От чопорной массы учителей его выгодно отличают легкость общения, эксцентричное поведение и пренебрежение к программе обучения. \n\nОднажды он посвящает своих подопечных в тайну Общества мёртвых поэтов. С этого момента каждый из учеников старается обрести свой собственный голос в безликом хоре, взглянуть на окружающий мир, высоко подпрыгнув над серой школьной оградой.', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4996.jpg', 13, 47, 2, 1),
(245, 'Мимино', 'Провинциальный пилот Валико Мизандари по прозвищу Мимино, что значит «сокол», занимается вертолётными перевозками почты, фруктов, кур, баранов и даже коров в горных районах Грузинской ССР. Однажды встретив в Тбилисском аэропорту приятеля по лётному училищу и увидев, на каком великолепном сверхзвуковом самолёте тот летает и в компании каких красавиц-стюардесс работает, Мимино решает изменить свою жизнь и отправляется в Москву подавать документы на переобучение. В гостинице он оказывается в одном номере с армянским водителем Рубеном Хачикяном, которого ошибочно приняли за профессора-эндокринолога.', 8.1, 'https://kinopoiskapiunofficial.tech/images/posters/kp/46638.jpg', 125, 43, 40, 1),
(246, 'Пираты Карибского моря: На краю света', 'Новые приключения Джека Воробья и его друзей Уилла Тернера и Элизабет Суонн. На этот раз Уиллу и Элизабет придется объединиться с самим Капитаном Барбоссой для того, чтобы отправиться на край света и спасти своего друга — Джека. Ситуация осложняется тем, что Элизабет попадает к сингапурским пиратам…', 8.1, 'https://kinopoiskapiunofficial.tech/images/posters/kp/102124.jpg', 7, 55, 2, 1),
(247, 'Аладдин', 'В славном граде Аграба живёт Аладдин, веселый воришка с золотым сердцем. Живёт и не знает, что вскоре его ждёт величайшее приключение в жизни. Ведь только с его помощью чёрный маг Джафар может овладеть невероятным сокровищем — лампой, в которой заключён исполняющий желания могущественный Джинн. И только хитроумие, смекалка и доброта Аладдина и его друзей — обезьянки Абу, принцессы Жасмин и самого Джинна - способны помешать Джафару завладеть лампой и захватить власть над миром.', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/2361.jpg', 151, 52, 2, 1),
(248, 'День сурка', 'Телевизионный комментатор Фил Коннорс каждый год приезжает в маленький городок в штате Пенсильвания на празднование Дня сурка. Но на этот раз веселье рискует зайти слишком далеко. Время сыграло с ним злую шутку: оно взяло да и остановилось.\n\nТеперь на календаре Фила чернеет одна и та же дата - 2 февраля, из которой он никак не может выбраться. Неунывающий ведущий пытается извлечь выгоду из своего комичного положения: впереди у него уйма времени и безмятежное предсказуемое будущее.\n\nОтныне с ним не случится ничего плохого... и ничего хорошего. У Фила осталась одна заветная мечта, простая и незамысловатая - 3 февраля...', 8.1, 'https://kinopoiskapiunofficial.tech/images/posters/kp/527.jpg', 70, 26, 2, 1),
(249, 'Белое солнце пустыни', 'Бесконечная пустыня. Боец Сухов, прикуривающий от динамитной шашки, нескладный Петруха с вечно заклинивающей трехлинейкой, обаятельный Верещагин с надоевшей черной икрой и знаменитыми песнями-балладами, ловкий Саид , злодей Абдулла со своей бандой, любознательная Гульчатай, играющая с черепахой.', 8.1, 'https://kinopoiskapiunofficial.tech/images/posters/kp/46066.jpg', 152, 61, 40, 1),
(250, 'Кин-дза-дза!', 'Прораб Владимир Николаевич Машков и не подозревал, что обычный путь до универсама за хлебом и макаронами обернется межгалактическими путешествиями. А все эта встреча со странным босоногим человеком с каким-то маленьким устройством — «машинкой перемещения», как тот ее назвал. \n\nКороче, нажал на кнопку и оказался вместе со случайным попутчиком, студентом в кроличьей шапке, в пустыне, и не в каких-нибудь Каракумах, а на планете-пустыне Плюк в тентуре, галактика Кин-дза-дза в спирали.', 8.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/44811.jpg', 97, 60, 40, 1),
(251, 'Душа', 'Уже немолодой школьный учитель музыки Джо Гарднер всю жизнь мечтал выступать на сцене в составе джазового ансамбля. Однажды он успешно проходит прослушивание у легендарной саксофонистки и, возвращаясь домой вне себя от счастья, падает в люк и умирает. Теперь у Джо одна дорога — в Великое После, но он сбегает с идущего в вечность эскалатора и случайно попадает в Великое До. Тут новенькие души обретают себя, и у будущих людей зарождаются увлечения, мечты и интересы. Джо становится наставником упрямой души 22, которая уже много веков не может найти свою искру и отправиться на Землю.', 8.4, 'https://kinopoiskapiunofficial.tech/images/posters/kp/775273.jpg', 58, 14, 30, 1),
(252, 'Шерлок Холмс и доктор Ватсон: Двадцатый век начинается', 'Заключительный фильм телесериала «Приключения Шерлока Холмса и доктора Ватсона». В основе его — поздние и малоизвестные рассказы Артура Конан Дойля, объединенные темой приближающейся мировой войны и борьбы легендарного детектива с иностранными шпионами.', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/77267.jpg', 153, 60, 40, 1),
(253, 'Аватар', 'Бывший морпех Джейк Салли прикован к инвалидному креслу. Несмотря на немощное тело, Джейк в душе по-прежнему остается воином. Он получает задание совершить путешествие в несколько световых лет к базе землян на планете Пандора, где корпорации добывают редкий минерал, имеющий огромное значение для выхода Земли из энергетического кризиса.', 8.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/251733.jpg', 65, 10, 2, 1),
(254, 'Апокалипсис', '1517 год. Полуостров Юкатан. В один день рушится мир индейца по имени Лапа Ягуара. Его деревню захватывает соседнее племя, уничтожая хижины, забирая местных жителей в плен. Его ведут в город, чтобы принести в жертву богам. Перед лицом неминуемой смерти Лапа Ягуара должен побороть свои самые сильные страхи и совершить отчаянный рывок, чтобы спасти то, что ему дорого.', 8.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/160977.jpg', 154, 9, 32, 1),
(255, 'Маугли дикой планеты', 'Попав в метеоритный дождь, юный космический исследователь Вилли оказывается на неизвестной планете. С помощью робота Бака он должен выжить здесь до прибытия спасательной миссии его родителей. Но батарея Бака быстро садится, и, чтобы спасти Бака и вернуться домой, Вилли придется найти новых друзей и научиться жить по законам джунглей дикой планеты.', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1209780.jpg', 155, 8, 6, 1),
(256, 'Люди в чёрном', 'Они - самый большой секрет Земли. Они работают на неофициальное правительственное агентство, регулирующее деятельность инопланетян на Земле.\n\nОни - это лучшая, последняя и единственная линия защиты Земли от отбросов вселенной. Их работа секретна, их оружие совершенно, им нет равных, они не оставляют следов. Они - это Люди в черном.', 8.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1091.jpg', 43, 31, 2, 1),
(257, 'Запах женщины', 'Наступил День благодарения, и отставной полковник разведки Фрэнк Слэйд решает справить праздник, побаловав себя поездкой в Нью-Йорк. Фрэнк хочет обставить свой последний «коронный выход» по высшему разряду: изысканный отель, шикарный лимузин, дорогая выпивка и женщины потрясающей красоты.\n\nЕсть лишь две проблемы. Первая: Фрэнк слеп на оба глаза. И вторая: волнующиеся родственники полковника решают нанять за небольшую сумму провожатого в лице нуждающегося студента престижного колледжа по имени Чарли Симмз. Последнее, что было нужно в поездке полковнику Слэйду - так это «зеленый» юнец Чарли. Но случилось так, что путешествие этих двух потрясающе непохожих друг на друга людей изменило их жизни навсегда.', 8.4, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4871.jpg', 13, 52, 2, 1),
(258, 'Чудо', 'С одной стороны мальчик Август Пулман такой же как и другие мальчишки его возраста - любит ходить на дни рождения к друзьям, играть в компьютерные игры, фанатеет от «Звездных войн», играет со своей собакой, ссорится и мирится со старшей сестрой. А с другой - он совсем не такой как другие мальчишки его возраста. Во-первых, Август никогда не ходил в обычную школу - с первого класса с ним дома занималась мама. Во-вторых, Август перенес 27 операций. Из-за очень редкой, но иногда встречающейся генетической ошибки у Августа нет лица. И вот такой мальчик должен пойти в школу. В первый раз. К обычным детям.', 8.1, 'https://kinopoiskapiunofficial.tech/images/posters/kp/722951.jpg', 109, 16, 57, 1),
(259, 'Анастасия', 'Анастасия — дочка последнего русского царя Николая, погубленного зловещим Распутиным. Ей удается спастись, добраться вместе с бабушкой до переполненного вокзала и… потеряться в толпе. Проходит десять лет. Анастасия стала взрослой красавицей и теперь хочет попасть в Париж. Сможет ли царевна осуществить задуманное? Ведь Распутин уже поднялся из своей могилы…', 8.1, 'https://kinopoiskapiunofficial.tech/images/posters/kp/2513.jpg', 156, 31, 2, 1),
(260, 'Вечера на хуторе близ Диканьки', 'Веселая история про то, как в рождественскую ночь в украинском селе всех попутал бес и как могучему кузнецу Вакуле удалось одолеть нечистую силу и добыть для своей невесты царские черевички. Экранизация повести Н. В. Гоголя «Ночь перед Рождеством».', 8.1, 'https://kinopoiskapiunofficial.tech/images/posters/kp/45694.jpg', 157, 62, 40, 1),
(261, 'Унесённые ветром', 'Могучие ветры Гражданской войны в один миг уносят беззаботную юность южанки Скарлетт О`Хара, когда привычный шум балов сменяется грохотом канонад на подступах к родному дому. Для молодой женщины, вынужденной бороться за новую жизнь на разоренной земле, испытания и лишения становятся шансом переосмыслить идеалы, обрести веру в себя и найти настоящую любовь.', 8.4, 'https://kinopoiskapiunofficial.tech/images/posters/kp/456.jpg', 128, 63, 2, 1),
(262, 'Жестокий романс', 'Действие разворачивается на берегу Волги в вымышленном провинциальном городке Бряхимове в 1877—1878 годах. Харита Игнатьевна Огудалова — дворянка хорошей и уважаемой фамилии, вдова с тремя взрослыми дочерьми, обеднела после смерти мужа, но делает всё, чтобы устроить жизнь дочерей и выдать их замуж за достаточно богатых и знатных женихов. В отсутствие средств она держит открытый дом, рассчитывая, что общество красивых и музыкальных барышень привлечёт холостых мужчин, достаточно богатых, чтобы жениться по любви на бесприданницах.\n\nЕдинственная «непристроенная» дочь Хариты — самая младшая — Лариса Дмитриевна Огудалова, к которой неравнодушны сразу несколько состоятельных господ, среди которых Сергей Сергеевич Паратов — красивый, обаятельный, франтоватый, легкомысленный и богатый барин.', 8.1, 'https://kinopoiskapiunofficial.tech/images/posters/kp/45314.jpg', 158, 56, 40, 1),
(263, 'Головоломка', 'Райли — обычная 11-летняя школьница, и, как у каждого из нас, ее поведение определяют пять базовых эмоций: Радость, Печаль, Страх, Гнев и Брезгливость. Эмоции живут в сознании девочки и каждый день помогают ей справляться с проблемами, руководя всеми ее поступками. До поры до времени эмоции живут дружно, но вдруг оказывается, что Райли и ее родителям предстоит переезд из небольшого уютного городка в шумный и людный мегаполис. Каждая из эмоций считает, что именно она лучше прочих знает, что нужно делать в этой непростой ситуации, и в голове у девочки наступает полная неразбериха. Чтобы наладить жизнь в большом городе, освоиться в новой школе и подружиться с одноклассниками, эмоциям Райли предстоит снова научиться работать сообща.', 8.1, 'https://kinopoiskapiunofficial.tech/images/posters/kp/645118.jpg', 159, 13, 30, 1),
(264, 'Игра', 'Николас Ван Ортон - само воплощение успеха. Он преуспевает, он невозмутим и спокоен, привык держать любую ситуацию под контролем. На день рождения Николас получает необычный подарок - билет для участия в «Игре».\n\nЕму обещают, что игра вернет яркие чувства, позволит ощутить вкус и остроту жизни. Вступив в игру, Николас начинает осознавать, что это игра всерьез, игра не на жизнь, а на смерть.', 8.3, 'https://kinopoiskapiunofficial.tech/images/posters/kp/12198.jpg', 160, 31, 2, 1),
(265, 'В погоне за счастьем', 'Крис Гарднер – отец-одиночка. Воспитывая пятилетнего сына, Крис изо всех сил старается сделать так, чтобы ребенок рос счастливым. Работая продавцом, он не может оплатить квартиру, и их выселяют.\n\nОказавшись на улице, но не желая сдаваться, отец устраивается стажером в брокерскую компанию, рассчитывая получить должность специалиста. Только на протяжении стажировки он не будет получать никаких денег, а стажировка длится 6 месяцев...', 8.3, 'https://kinopoiskapiunofficial.tech/images/posters/kp/104938.jpg', 64, 9, 2, 1),
(266, 'Белорусский вокзал', 'Герои фильма расстались на Белорусском вокзале летом 1945-го. Спустя четверть века они встречаются на похоронах боевого товарища. В их душах с новой силой оживает пережитое. Время не властно над их памятью: ветераны сохранили верность фронтовой дружбе, способность жертвовать собой, неистребимую любовь к жизни.', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/46063.jpg', 13, 64, 40, 1),
(267, 'Как прогулять школу с пользой', 'Вслед за городским мальчиком Полем зрителям предстоит узнать то, чему в школе не учат. А именно — как жить в реальном мире. По крайней мере, если это мир леса. Здесь есть хозяин — мрачный граф, есть власть — добродушный, но строгий лесничий Борель, и есть браконьер Тотош — человек, решивший быть вне закона, да и вообще подозрительный и неприятный тип. \n\nЧью сторону выберет Поль: добропорядочного лесничего Бореля или браконьера Тотоша? А может, юный сорванец и вовсе станет лучшим другом надменному графу?', 8.1, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1032308.jpg', 161, 16, 6, 1),
(268, 'Омерзительная восьмерка', 'США после Гражданской войны. Легендарный охотник за головами Джон Рут по кличке Вешатель конвоирует заключенную. По пути к ним прибиваются еще несколько путешественников. Снежная буря вынуждает компанию искать укрытие в лавке на отшибе, где уже расположилось весьма пёстрое общество: генерал конфедератов, мексиканец, ковбой… И один из них — не тот, за кого себя выдает.', 8.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/819101.jpg', 162, 13, 2, 1),
(269, 'Лекарь: Ученик Авиценны', 'Англия, XI век. Мать десятилетнего Роба Коула умирает в страшных мучениях: никто не знает ни природы её болезни, ни лекарства против неё. Маленький Роб, потрясенный до глубины души, во что бы то ни стало стремится разгадать эту тайну.\n\n Ему суждено пройти долгий путь, от Англии до Персии, его учителями становятся сначала обыкновенный шарлатан Барбер, а потом - великий лекарь Авиценна. Мудрый учитель видит в Робе необыкновенный талант к медицине, но советует ему не спешить делать вещи, которые не соответствуют веку. Но Роб ни перед чем не останавливается в своем желании научиться спасать людей от смерти, и над его собственной жизнью нависает угроза, ведь он дважды пошел против предрассудков: использовал для научных исследований тело человека и полюбил женщину, отданную в жены другому.', 7.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/645276.jpg', 163, 17, 41, 1),
(270, 'Храброе сердце', 'Действие фильма начинается в 1280 году в Шотландии. Это история легендарного национального героя Уильяма Уоллеса, посвятившего себя борьбе с англичанами при короле Эдварде Длинноногом.\n\nОн рано лишился отца, погибшего от рук англичан, и его забрал к себе дядя Оргайл, который дал ему хорошее образование в Европе. На родину Уильям возвращается уже взрослым человеком, мечтающим завести семью и жить мирной жизнью.\n\nНо судьба распорядилась иначе. Его невесту убили англичане, и он начал свой крестовый поход за свободу.', 8.3, 'https://kinopoiskapiunofficial.tech/images/posters/kp/399.jpg', 24, 4, 2, 1),
(271, 'Ученик чудовища', '9-летний мальчик Рэн остался без родителей, сбежал от опекунов и скитался по улицам Токио. Там он встречает великого воина Медвежута — похожее на медведя чудище, явившееся из параллельного мира, чтобы найти себе ученика. Им и становится Рэн. В мире чудовищ мальчик получает имя Девята и под началом Медвежута начинает тренировки, чтобы стать мастером боевых искусств.', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/885317.jpg', 164, 13, 9, 1),
(272, 'Обыкновенное чудо', 'Пришло время – волшебник женился, остепенился, занялся хозяйством. Но однажды, встретив в лесу медведя, все-таки не вытерпел: взял и превратил его в прекрасного юношу, поставив условие, что тот снова станет медведем, если его поцелует принцесса.', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/77282.jpg', 165, 65, 40, 1),
(273, 'Ветер крепчает', 'Мальчик Дзиро мечтает о полетах и красивых самолетах, способных обогнать ветер. Вот только пилотом ему не стать — он с рождения близорук. Но Дзиро не расстается с мечтой о небе, он начинает придумывать идеальный самолет и со временем становится одним из лучших авиаконструкторов мира. На пути к успеху он не только встретит много интересных людей, переживет Великое землетрясение в Токио и жестокие войны, но и обретет любовь своей жизни – прекрасную Наоко.', 8.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/693969.jpg', 166, 17, 9, 1),
(274, 'Творение Господне', 'В 40-х годах XX-го века Альфред Блэлок, хирург от Бога, совершил революцию в медицине. Работая в одной из больниц Балтимора, он разработал методику операций по спасению детей с врожденным пороком сердца.\n\nЕго соратником, незаменимым помощником и лучшим другом стал чернокожий лаборант Вивьен Томас. Общественное мнение никак не могло смириться с этим вопиющим фактом, и в итоге под угрозой оказалась не только их дружба, но и продолжение совместных исследований.', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/233084.jpg', 64, 23, 2, 1),
(275, 'Собака на сене', 'Богатая и знатная сеньора Диана терзается сомнениями: ей нужно выбрать между достойными ее руки женихами и личным секретарем — красавцем и ловеласом. А тот, в свою очередь, не может решить, кто ему больше по сердцу — его обворожительная хозяйка или ее прелестная служанка...', 8.1, 'https://kinopoiskapiunofficial.tech/images/posters/kp/77206.jpg', 167, 43, 40, 1),
(276, 'Алеша Попович и Тугарин Змей', 'Когда подступила к Ростову вражеская орда во главе с Тугариным Змеем, Алеша Попович не сумел уберечь жителей от выплаты дани. Теперь богатырь должен восстановить доброе имя, вернуть золото и прогнать неприятеля с земли русской. Он отправляется в путешествие, а помогут ему в этом дядька Тихон, девушка Любава, ее бабушка и говорящий конь Юлий.', 7.8, 'https://kinopoiskapiunofficial.tech/images/posters/kp/81041.jpg', 151, 23, 1, 1),
(277, 'Расправь крылья', 'Подросток Тома навещает во время отдыха своего отца Кристиана, чудаковатого орнитолога. Но для юноши, увлеченного гаджетами и играми, разведение диких гусей во французской деревне и эксперименты отца наводят лишь тоску. Однако все меняется, когда Тома решает спасти исчезающий вид диких гусей и отправляется в воодушевляющее путешествие с «небесными ангелами», как их называет Кристиан.', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1256482.jpg', 168, 8, 58, 1),
(278, 'Подольские курсанты', 'Октябрь 1941 года, Подмосковье. Около трёх с половиной тысяч курсантов подольских артиллерийского и пехотного училищ получают приказ занять оборону на Ильинском рубеже и совместно с регулярными частями 43-й армии сдерживать наступление фашистских захватчиков, пока не подойдёт подкрепление. Погибая, вчерашние мальчишки держат оборону от многократно превышающих сил немцев и на двенадцать дней становятся преградой на пути врага к Москве.', 8.1, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1191022.jpg', 132, 14, 1, 1),
(279, 'Красотка', 'Финансовый магнат Эдвард Льюис, проезжая по ночному городу, останавливается около красивой женщины. Ее зовут Вивьен и она берет только наличными. Наутро он понимает, что не хочет расставаться с ней и предлагает девушке остаться в его номере в отеле еще на некоторое время - за дополнительный гонорар.\n\nВивьен оказывается в море блеска и лжи. Она терпит небрежное отношение к ней ради понравившегося мужчины, который перестал быть для нее просто клиентом.', 8.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/8125.jpg', 16, 12, 2, 1),
(280, 'Самая обаятельная и привлекательная', 'У инженера Нади Клюевой максимум общественной и минимум личной жизни. Всё меняется, когда она случайно встречает в автобусе свою старую знакомую, бывшую одноклассницу Сусанну, ныне работающую социологом на заводе бытовых кондиционеров. Сусанна решает наладить личную жизнь своей подруги, используя научный метод.', 8.1, 'https://kinopoiskapiunofficial.tech/images/posters/kp/43602.jpg', 16, 36, 40, 1),
(281, 'Невидимая сторона', 'Благополучная белая семья берет к себе толстого, неграмотного бездомного темнокожего подростка и помогает стать ему спортивной звездой, и поступить в университет.', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/450213.jpg', 111, 10, 2, 1),
(282, 'Доктор Лиза', 'Один день из жизни Елизаветы Глинки — филантропа и основательницы фонда «Справедливая помощь». Еще утром она планировала провести его с семьей, отмечая 30-летие свадьбы, но даже сегодня не может отключить телефон. Доктор Лиза должна ехать на вокзал, чтобы накормить бездомных, и к знакомому врачу Шевкунову, чтобы попросить морфин для умирающей девочки. Все это время за ней следят правоохранительные органы, которые давно интересуются этой чрезвычайно энергичной благотворительницей.', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1254059.jpg', 64, 14, 1, 1),
(283, 'Жизнь других', 'Сто тысяч сотрудников, двести тысяч информаторов. Вместе они — щит и меч партии, знаменитое Штази. Их метод — подозрение. Жизнь других — их профессия.\n\nПопулярный писатель и драматург Георг Драйман так бы и дожил до конца своих дней, обласканный вниманием благодарных читателей и абсолютно неинтересный для спецслужб, если бы не роман с известной театральной актрисой. Слишком известной, чтобы остаться незамеченной влиятельным чиновником из ЦК. Так в жизни Драймана появляются специалисты из Штази.', 8.1, 'https://kinopoiskapiunofficial.tech/images/posters/kp/126196.jpg', 50, 9, 59, 1),
(284, 'Монстры на каникулах', 'Граф Дракула для себя и своей любимой дочки построил хорошо укрытый от посторонних глаз отель, куда монстры со всего света приезжают отдохнуть от семейных забот, повседневной суеты и, конечно… людей. Но вездесущие американские туристы проникают и сюда.', 7.7, 'https://kinopoiskapiunofficial.tech/images/posters/kp/280174.jpg', 40, 2, 2, 1),
(285, 'Карнавальная ночь', 'Команда молодых работников клуба готовится к встрече Нового года. Они задумывают провести интересный и веселый праздник, но, на беду ребят, их берется контролировать директор клуба Огурцов — бюрократ, буквоед и чинуша. Собрав всех в своем кабинете, он подробно рассказывает о «своем видении» того, как правильно и полезно провести новогоднюю ночь. Организаторы понимают, что Огурцов собирается вместо праздника преподнести гостям клуба некий коктейль из смотра художественной самодеятельности и партсобрания. И тогда молодежь решает хитростью обойти недалекого начальника, чтобы организовать настоящий новогодний бал.', 8.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/44720.jpg', 169, 51, 40, 1),
(286, 'Человек дождя', 'Грубоватому и эгоистичному молодому человеку Чарли в наследство от отца достались лишь розовые кусты да «Бьюик» 1949 года, а львиная доля наследства уходит его брату-аутисту Раймонду. Задавшись целью отобрать «свою долю», Чарли похищает старшего брата. Но когда выясняет, что Раймонд обладает недюжими математическими способностями, памятью и внимательностью, решает использовать это в корыстных целях.', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/519.jpg', 13, 40, 2, 1),
(287, 'Весна на Заречной улице', 'Лучший сталевар завода Саша Савченко не привык к отказам женщин. Решив по-быстрому покорить молодую учительницу Татьяну Левченко из школы рабочей молодёжи, он неожиданно получает отказ. Поначалу он пытается играть в безразличие, но позже Саша внезапно понимает, что к нему впервые пришло настоящее, глубокое чувство.', 8.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/45748.jpg', 77, 51, 40, 1),
(288, 'Семь жизней', 'Инженер Бен отправляется в необычное путешествие. В ходе своей поездки он встречает семерых незнакомцев, включая смертельно больную Эмили, которая называет себя девушкой с подбитыми крыльями. Бен неожиданно влюбляется в нее, что сильно усложняет его первоначальный план. Сможет ли он разгадать послание судьбы?', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/395787.jpg', 77, 37, 2, 1),
(289, 'Могила светлячков', 'Последние дни Второй мировой войны, американская авиация бомбит беззащитные японские города. В водоворот каждодневного кошмара попадают 14-летний Сэйта и его сестренка Сэцуко - потеряв близких, они остались совсем одни. Мальчик в одночасье становится взрослым и осознаёт, что от него зависит жизнь маленькой сестры.\n\nУкрывшись в заброшенном убежище, Сэйта и Сэцуко пытаются выжить собственными силами. И пусть в их глазах смертоносный огонь в небе - всего лишь огоньки светлячков, жестокая война не щадит даже невинные детские души, вынося им беспощадный приговор.', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/8219.jpg', 170, 40, 9, 1),
(290, 'Ford против Ferrari', 'В начале 1960-х Генри Форд II принимает решение улучшить имидж компании и сменить курс на производство более модных автомобилей. После неудавшейся попытки купить практически банкрота Ferrari американцы решают бросить вызов итальянским конкурентам на трассе и выиграть престижную гонку 24 часа Ле-Мана. Чтобы создать подходящую машину, компания нанимает автоконструктора Кэррола Шэлби, а тот отказывается работать без выдающегося, но, как считается, трудного в общении гонщика Кена Майлза. Вместе они принимаются за разработку впоследствии знаменитого спорткара Ford GT40.', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/835086.jpg', 171, 8, 2, 1),
(291, 'Формула любви', 'Музыкальная комедия по мотивам повести Алексея Толстого «Граф Калиостро» . В 1780 году Джузеппе Калиостро прибыл в Россию для представления высшей знати. Умыкнув под предлогом лечения отца юную Марью Ивановну, граф пытается влюбить в себя девицу, но безуспешно. В провинциальном поместье, где волею случая оказались путешественники, живет юноша, влюбленный в мраморную статую. С помощью Калиостро он надеется оживить мрамор, но встреча с живой Машей все меняет...', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/81432.jpg', 16, 56, 40, 1),
(292, 'Счастливое число Слевина', 'Слевину не везет. Дом опечатан, девушка ушла к другому… Его друг Ник уезжает из Нью-Йорка и предлагает Слевину пожить в пустой квартире. В это время крупный криминальный авторитет по прозвищу Босс хочет рассчитаться со своим бывшим партнером за убийство сына и в отместку «заказать» его наследника.', 8.1, 'https://kinopoiskapiunofficial.tech/images/posters/kp/86326.jpg', 3, 24, 60, 1),
(293, 'Король говорит!', 'Герцог готовится вступить в должность британского короля Георга VI, отца королевы Елизаветы II. После того, как его брат отрекается от престола, мужчина неохотно соглашается на трон. Измученный страшным нервным заиканием и сомнениями в своих способностях руководить страной, Георг обращается за помощью к неортодоксальному логопеду по имени Лайонел Лог.', 8.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/485311.jpg', 9, 19, 8, 1),
(294, 'Человек с бульвара Капуцинов', 'В одном из ковбойских городков Дикого Запада с его традиционной стрельбой, сквернословием и мордобоем появляется тихий миссионер кино мистер Фёст. Неведомое прежде ковбоям «синема» до неузнаваемости меняет уклад их жизни, нравы и привычки. ', 8.1, 'https://kinopoiskapiunofficial.tech/images/posters/kp/45463.jpg', 172, 58, 40, 1),
(295, 'Таксист', 'В результате военного переворота в декабре 1979 года южнокорейским президентом становится Чон Ду-хван. После расстрела студенческой демонстрации в городе Кванджу местные жители решают массово выступить против режима. Диктатор бросает на подавление восстания военные части. \n\nВ это время оказавшийся в Токио репортёр германской газеты решает проникнуть в Кванджу, чтобы донести до внешнего мира правду о том, что творится в Корее. Доставить немца в зону боевых действий и обратно должен простой сеульский таксист Ман-соп, который с утра даже не представлял, что скоро ему придется скрываться от военных патрулей.', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1008113.jpg', 9, 16, 61, 1),
(296, 'Загадочная история Бенджамина Баттона', 'Фильм о мужчине, который родился в возрасте 80 лет, а затем… начал молодеть. Этот человек, как и каждый из нас, не мог остановить время. Его путь в ХХI век, берущий свое начало в Новом Орлеане в 1918 году в самом конце Первой Мировой войны, будет столь необычен, что вряд ли мог иметь место в жизни кого-либо другого. Фильм повествует о судьбе уникального человека, о людях и событиях, что ждут его впереди, о любви, которую он обретет и потеряет, о радостях жизни и грусти потерь и о том, что остается с нами вне времени.', 8.1, 'https://kinopoiskapiunofficial.tech/images/posters/kp/81555.jpg', 173, 37, 2, 1),
(297, 'Счастье в конверте', 'Три удивительные истории о любви и дружбе, о вере в мечту и связи поколений, о том, как не предавать себя и оставаться человеком в любой жизненной ситуации.\n\nВ век технологий люди привыкли спешить, бежать, зарабатывать, забывая при этом о главном – о себе и своих настоящих желаниях. Нам кажется, что мы станем счастливее как только у нас появится новая машина или высокая зарплата. А все значительно проще – секрет счастья скрыт в душе каждого человека: в умении верить в чудо, дружить, любить, быть отважным, следовать за своей мечтой!', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1234939.jpg', 174, 8, 1, 1),
(298, 'Железный человек', 'Миллиардер-изобретатель Тони Старк попадает в плен к Афганским террористам, которые пытаются заставить его создать оружие массового поражения. В тайне от своих захватчиков Старк конструирует высокотехнологичную киберброню, которая помогает  ему сбежать. Однако по возвращении в США он узнаёт, что в совете директоров его фирмы плетётся заговор, чреватый страшными последствиями. Используя своё последнее изобретение, Старк пытается решить проблемы своей компании радикально...', 8.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/61237.jpg', 143, 37, 19, 1),
(299, 'Догвилль', 'Юная Грейс, сбежав от банды гангстеров, находит спасение в маленьком городке Догвилль где-то в Скалистых горах. Местные жители – один прекраснее другого – готовы ее укрыть. А взамен им совсем ничего не надо, ну, разве что помочь по дому или присмотреть за детьми. Но постепенно милый Догвилль превращается для девушки в тюрьму.', 8.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/7226.jpg', 50, 15, 62, 1),
(300, 'Пролетая над гнездом кукушки', 'Рэндла Патрика Макмёрфи, патологического преступника и бунтаря, переводят из колонии в психиатрическую клинику, чтобы установить, является он душевнобольным или нет. В клинике он обнаруживает, что отделение контролирует хладнокровная, строгая и одержимая распорядком старшая медсестра Милдред Рэтчед. Макмёрфи намерен не подчиняться абсурдным, на его взгляд, правилам и одновременно повеселиться от души. Его бунтарская натура заражает других пациентов, но сестра Рэтчед решительно настроена пресечь это.', 8.5, 'https://kinopoiskapiunofficial.tech/images/posters/kp/336.jpg', 13, 39, 2, 1);
INSERT INTO `media` (`id`, `title`, `description`, `rating`, `image_url`, `genre_id`, `year_id`, `country_id`, `type_id`) VALUES
(301, 'Приходи на меня посмотреть', 'Софья Ивановна давно не встает со своего кресла. А ее единственная дочь Таня, похоже, смирилась с положением старой девы. Вся ее жизнь - это заботы о больной матери. Но в один из предновогодних вечеров Софья Ивановна собралась умирать. И с этого момента в московской квартире начинаются настоящие новогодние чудеса.', 8.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/40955.jpg', 16, 22, 1, 1),
(302, 'По семейным обстоятельствам', 'Женщина средних лет решает разменять свою квартиру, где она живет вместе с семьей дочери. Но встреча с обаятельным мужчиной благополучно разрешает «квартирный вопрос»: она переселяется к избраннику и на собственном опыте узнает, что значит жить с родителями.', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/43007.jpg', 125, 65, 40, 1),
(303, 'Свой среди чужих, чужой среди своих', '1920-е годы, маленький город на юге России. Гражданская война закончилась, но до полной победы большевиков ещё далеко. Группа бандитов из бывших белых офицеров грабит поезд с золотом, на которое нужно было купить хлеб для голодающих, и пятеро друзей - бывших красных бойцов - вступают с ними в смертельную схватку. Подозрение в предательстве падает на одного из них, и, сбежав от товарищей, он должен вернуть золото, чтобы доказать свою невиновность.', 8.1, 'https://kinopoiskapiunofficial.tech/images/posters/kp/44062.jpg', 175, 53, 40, 1),
(304, 'Максим Перепелица', 'Веселого парня, деревенского шутника и балагура Максима Перепелицу призывают на службу в армию. Но и там, пытаясь избежать трудностей армейской жизни, он пытается ловчить. Однако открытый добродушный нрав, настоящий характер заставляют парня переосмыслить происходящее с ним. На побывку в родное село, где его дожидается любимая, Максим приезжает в звании младшего сержанта.', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/46512.jpg', 1, 66, 40, 1),
(305, 'Ла-Ла Ленд', 'Это история любви старлетки, которая между прослушиваниями подает кофе состоявшимся кинозвездам, и фанатичного джазового музыканта, вынужденного подрабатывать в заштатных барах. Но пришедший к влюбленным успех начинает подтачивать их отношения.', 8.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/841081.jpg', 176, 50, 35, 1),
(306, 'Доктор', 'Ночью в психоневрологическом отделении для подростков происходит ужасное событие — едва не гибнет один из пациентов. Взрослые предполагают, что виновник ночного происшествия — кто-то из ребят. Врачи опасаются, что история повторится и закончится трагедией. Есть версия, что подростки по ночам играют в «собачий кайф», игру с удушением. Разобраться во всем и остановить смертельную игру должен Иван Христофоров — психиатр, который лечит юных пациентов не столько таблетками, сколько педагогическими методами. Но, оказывается, что найти виновника — это самое простое.', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/5002368.jpg', 13, 3, 1, 1),
(307, 'Дневник памяти', 'Это история отношений юноши и девушки из разных социальных слоев, живших в Южной Каролине. Ной и Элли провели вместе незабываемое лето, пока их не разделили вначале родители, а затем Вторая мировая война.\n\nПосле войны все изменилось: Элли обручилась с удачливым бизнесменом, а Ной жил наедине со своими воспоминаниями в старинном доме, который ему удалось отреставрировать. Когда Элли прочла об этом в местной газете, она поняла: ей нужно найти его и решить наконец судьбу их любви...', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/3561.jpg', 77, 23, 2, 1),
(308, 'Балто', 'Наполовину лайка, наполовину волк, Балто и сам не знает кто он такой на самом деле. Всеми гонимый бродяга в ледяной пустыне Аляски. Только его друзья русский полярный гусь Борис, медвежата Мак и Лак и красавица-лайка Дженна уверены, что хотя он и не такой как все, но в его груди бьется благородное сердце.\n\nОднажды случается несчастье. Эпидемия дифтерии охватила детей небольшого поселка, а свирепая вьюга сделала непроходимыми все дороги. Лишь собачья упряжка может преодолеть шестьсот миль через ослепляющий арктический шторм и привезти спасительное лекарство.\n\nНо собаки сбились с дороги где-то на замерзших просторах. Теперь только Балто может найти упряжку и спасти детей, а заодно стать героем и настоящей легендой!', 8.3, 'https://kinopoiskapiunofficial.tech/images/posters/kp/7097.jpg', 177, 4, 8, 1),
(309, 'Мальчик в полосатой пижаме', 'История, происходящая во время Второй мировой войны и показанная сквозь глаза невинного и ничего не подозревающего о происходящих событиях Бруно, восьмилетнего сына коменданта концентрационного лагеря. Его случайное знакомство и дружба с еврейским мальчиком по другую сторону ограды лагеря, в конечном счете, приводит к самым непредсказуемым и ошеломительным последствиям.', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/281251.jpg', 93, 37, 8, 1),
(310, 'Вокзал для двоих', 'Город Заступинск, где-то между Москвой и Алма-Атой, ближе к Воронежу. Вокзальная буфетчица Вера и пианист Платон Рябинин из Москвы познакомились при весьма непривлекательных обстоятельствах. В результате Вера потеряла жениха с дынями, но нашла любимого, который вскоре должен отбыть в отдаленные места, чтобы нести наказание за несовершенное преступление...', 8.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/45822.jpg', 77, 57, 40, 1),
(311, 'День выборов', 'Руководитель одной из самых рейтинговых радиостанций страны получает заказ от загадочного клиента. Необходимо «раскрутить» на региональных выборах своего кандидата, отобрать голоса у конкурентов и тем самым повлиять на избрание нового губернатора. За выполнение задачи государственной важности берутся лучшие умы радиостанции.', 7.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/309408.jpg', 1, 55, 1, 1),
(312, 'Восточный ветер', 'Из-за плохой успеваемости родители отправляют 14-летнюю Мику в поместье к строгой бабушке. Поездка преподносит один сюрприз за другим: оказывается, бабушка, Мария Кальтенбах – знаменитая всадница в прошлом, которая теперь тренирует молодые таланты и разводит лошадей. Несмотря на то, что сама Мика ни разу в жизни не ездила верхом, да и не горит желанием научиться, один из обитателей конюшни - вороной жеребец по имени Оствинд неожиданно привлекает её внимание. Девушка легко находит с ним общий язык, даже не подозревая о том, что все вокруг считают коня диким и опасным. Так начинается их необыкновенная дружба.', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/703187.jpg', 168, 17, 41, 1),
(313, 'О чём говорят мужчины', 'О чем говорят мужчины? Конечно, о женщинах. Нет, еще о работе, о деньгах, о машинах, о футболе,… но в основном, все-таки, о женщинах. А уж если у них впереди два дня, которые они, вырвавшись из офисов и семей, уехав от всех забот и обязательств, проведут в дороге – два дня, насыщенные событиями и приключениями – то можете быть уверены, что за это время они успеют обсудить немало тем…\n\nИ еще. Из этих разговоров – это мы точно знаем – многие женщины узнают о себе очень много нового...', 7.8, 'https://kinopoiskapiunofficial.tech/images/posters/kp/468102.jpg', 1, 19, 1, 1),
(314, 'Республика ШКИД', '1920 годы. Послереволюционный беспредел. «Трепещите, халдеи!» — по улицам Петрограда шныряют колоритные и жалкие беспризорники, которых время от времени вылавливают и направляют в детские приюты. В одном из них — школе имени Достоевского (ШКИД) — собрались голодные, наглые и сообразительные оборвыши. Этим «приютом комедиантов» управляет директор, не потерявший ни чести, ни интеллигентности. Его обезоруживающее доверие научит ребят мужскому достоинству, поможет не раствориться в беге смутного времени...', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/42088.jpg', 161, 42, 40, 1),
(315, 'Легенда №17', 'История жизни хоккеиста Валерия Харламова.', 8.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/601564.jpg', 111, 2, 1, 1),
(316, 'Профессионал', 'Убить президента африканской республики. Такое задание получил секретный агент Жослен Бомон. Внезапно политика изменилась, и французское правительство сдает героя африканским властям. Сбежав с каторги, волк-одиночка возвращается на родину с одной целью: довести задание до конца. А чернокожий лидер как раз приезжает во Францию.', 8.1, 'https://kinopoiskapiunofficial.tech/images/posters/kp/39259.jpg', 89, 29, 6, 1),
(317, 'Назад в будущее 3', 'Несмотря на просьбы Дока не навещать его в XIX веке, Марти вновь хочет вмешаться в ход событий и на машине времени уносится в 1885 год, навстречу Дикому Западу. \n\nЭто путешествие, как и все прежние, не обходится без опасных приключений, но смелый Марти, рискуя жизнью, предотвращает трагедию в жизни Эммета Брауна. Тот, в свою очередь, без памяти влюбляется в очаровательную незнакомку, которую спасает от гибели, и поездка домой — в будущее — теряет для него всякий смысл.', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/7103.jpg', 178, 12, 2, 1),
(318, 'Темный рыцарь: Возрождение легенды', 'Восемь лет назад Бэтмен растворился в ночи, превратившись из героя в беглеца. Приняв на себя вину за смерть прокурора Харви Дента, он пожертвовал всем. Вместе с комиссаром Гордоном они решили, что так будет лучше для всех. Пока преступность была раздавлена антикриминальным актом Дента, ложь действовала.\n\nТем не менее, еще опаснее становится появление нового врага Бэйна, чье лицо закрыто маской.  Он разворачивает в Готэме чудовищную деятельность, и это вынуждает Брюса Уэйна выйти из импровизированного изгнания. Однако даже надев свой костюм, Бэтмен может проиграть Бэйну. Но с появлением хитрой воровки по прозвищу Женщина — Кошка с загадочным прошлым всё меняется.', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/437410.jpg', 92, 2, 8, 1),
(319, 'Искупление', 'Действие фильма начинается в 1935 году и разворачивается на фоне Второй мировой войны. Талантливая тринадцатилетняя писательница Бриони Таллис бесповоротно меняет ход нескольких жизней, когда обвиняет любовника старшей сестры в преступлении, которого он не совершал.', 8.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/255611.jpg', 179, 55, 14, 1),
(320, 'Амели', 'Знаете ли вы, что все события, происходящие в нашем мире, даже самые незначительные, взаимосвязаны самым удивительным и чудесным образом?\n\nКак полет крошечной мухи может вызвать где-то далеко мощный ураган, так и странные и, на первый взгляд, непонятные поступки тихой и одинокой девушки, живущей в мире своих фантазий, могут навсегда изменить жизнь совершенно разных людей, подарив им счастье и раскрасив окружающий мир яркими красками. Эту девушку зовут Амели Пулен.', 8.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/341.jpg', 16, 11, 59, 1),
(321, 'В джазе только девушки', 'Когда чикагские музыканты Джо и Джерри случайно становятся свидетелями бандитской перестрелки, они в срочном порядке смываются на поезде во Флориду, прикинувшись женщинами. Теперь они — Джозефина и Дафна, новенькие и хорошенькие инструменталистки женского джаз-бэнда.\n\nДо поры до времени их маскировка срабатывает. Но вскоре любвеобильная солистка влюбляется в «переодетого» мужчиной Джозефину, престарелый миллионер подкатывает к Дафне, а босс мафии, разгадав тайну маскарада, решает срочно разделаться со свидетелями.', 8.5, 'https://kinopoiskapiunofficial.tech/images/posters/kp/356.jpg', 180, 45, 2, 1),
(322, '12 лет рабства', 'Соломон Нортап был женатым и образованным мужчиной, который жил и работал в штате Нью-Йорк, когда два человека однажды предложили ему привлекательную работу в Вашингтоне. По прибытии он был похищен, стал рабом и влачил жалкую жизнь, переходя от одного хозяина к другому.', 7.8, 'https://kinopoiskapiunofficial.tech/images/posters/kp/606646.jpg', 9, 17, 8, 1),
(323, 'Ледниковый период', 'Действие разворачивается 20 тыс. лет назад. Чтобы избежать приближающегося из-за наступления ледникового периода холода, животные мигрируют на юг. Однако некоторые из них всё-таки решают остаться - одинокий, угрюмый мамонт Манфред, а также бесшабашный ленивец Сид.\n\nСлучайно эта парочка наталкивается на человеческого детёныша. Они решаются вернуть его людям и отправляются в путешествие. По пути они встречают саблезубого хитрого тигра. И теперь этой веселой компании предстоят забавные приключения!', 8.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/707.jpg', 52, 25, 36, 1),
(324, 'Доспехи Бога 2: Операция Кондор', 'Азиатский Ястреб возвращается! На этот раз ему предстоит новая работа, из-за которой наш герой опять приезжает в Мадрид. Некий загадочный миллионер предлагает Ястребу заняться поисками нацистских сокровищ, которые спрятаны в глубине африканской пустыни. Он передает ключ к сокровищнице, соглашается финансировать экспедицию и отправляет с Ястребом попутчицу - специалиста по Африке Аду.\n\nВо время своего пребывания в Мадриде Ястреб знакомится с немецкой девушкой Эльзой, которая разыскивает своего деда, пропавшего во время войны в Африке. После ряда приключений Эльза тоже присоединяется к экспедиции.', 8.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/24701.jpg', 181, 32, 63, 1),
(325, 'Ворошиловский стрелок', 'Пенсионер, железнодорожник в отставке, скромно живёт со своей внучкой Катей. В соседнем доме постоянно собираются трое молодых бездельников, чувствующие себя безнаказанными хозяевами жизни. Однажды они хитростью заманили Катю к себе, где изнасиловали.\n\nПоначалу насильников арестовывают, однако отец одного из них — большой милицейский начальник — освобождает их. После безуспешных попыток наказать преступников законным путём, Иван Фёдорович посчитал своим долгом восстановить справедливость сам...', 7.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/41442.jpg', 5, 20, 1, 1),
(326, 'Изгой', 'Инспектор логистической компании FedEx Чак Ноланд — трудоголик, у которого нет времени даже на собственную невесту. Во время очередной командировки самолет с Ноландом падает в Тихий океан. Чак, единственный, кому посчастливилось спастись, оказывается на необитаемом острове, где ему придется бороться за выживание.', 8.3, 'https://kinopoiskapiunofficial.tech/images/posters/kp/627.jpg', 63, 22, 2, 1),
(327, 'Дурак', 'Жизни 800 человек общежития висят буквально на волоске из-за безразличия местных властей. В любую секунду здание может рухнуть. И кто бы мог подумать, что судьбы людей окажутся в руках простого сантехника. Но удастся ли ему что-то изменить и предотвратить катастрофу?', 8.1, 'https://kinopoiskapiunofficial.tech/images/posters/kp/808639.jpg', 13, 5, 1, 1),
(328, 'Блеф', 'Белль Дюк имеет старые счеты с Филиппом Бэнгом, который отбывает свой срок за решёткой. Для того чтобы поквитаться с Филиппом, Белль Дюк вступает в сговор с другим аферистом по имени Феликс, чтобы тот организовал побег Филиппа Бэнга из тюрьмы. Побег удаётся, но парочка заодно обманывает и Белль Дюк, исчезнув прямо из-под её носа. Выясняется, что и Филипп Бэнг, в свою очередь, не прочь отомстить Белль Дюк. Для этого он задумывает грандиозную мистификацию, сродни покерному блефу.', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/10179.jpg', 98, 48, 44, 1),
(329, 'Джуманджи', 'Случайно обнаружив настольную игру со странным названием «Джуманджи», Алан Пэрриш на глазах изумленной подружки перенёсся в джунгли. Он находился в этом мире до тех пор, пока двое ни о чем не подозревающих подростков не нашли игру и не сняли волшебные чары, освободив Алана из многолетнего плена. Теперь им предстоит решить нелегкую задачу - пройти немыслимые препятствия и одержать победу над силами магии.', 7.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/8161.jpg', 29, 4, 2, 1),
(330, 'Зверопой 2', 'Тяжело быть продюсером, когда ты коала и у тебя лапки. Еще сложнее, когда твоя верная помощница древнее печатной машинки. И совсем весело, когда твоя труппа — это танцующий без остановки пухляш, колючая девочка-панк, застенчивая школьница, верзила-гангстер и многодетная мама, чьи дети — поросята в прямом смысле слова. Рецепт успеха прост — рвануть в мировую столицу развлечений, завербовать легендарного рок-музыканта и взорвать сцену новым шоу.', 8.3, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1009142.jpg', 124, 21, 30, 1),
(331, 'Такси', 'Таксист Даниэль помешан на быстрой езде. Как ураган проносится он по извилистым улицам Марселя на мощном ревущем «Пежо», пугая прохожих и приводя в ужас пассажиров. Начинающий следователь Эмильен вынуждает его помогать в поимке банды грабителей банков, каждый раз ускользающих от полиции на неуловимых «Мерседесах».', 7.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/14349.jpg', 14, 44, 6, 1),
(332, 'Красавица и чудовище', 'В заколдованном замке, скрытом в темном лесу, живет ужасное Чудовище. Растопить лед в его сердце и вернуть ему человеческий облик, сняв заклятие, может только прекрасная девушка, которая полюбит его таким, какой он есть.', 8.3, 'https://kinopoiskapiunofficial.tech/images/posters/kp/540.jpg', 182, 32, 30, 1),
(333, 'Гостиница Окко', 'Орико Сэки по прозвищу Окко переезжает к бабушке, чтобы помогать в небольшой семейной гостинице. Там она обнаруживает призрака — бойкого мальчика Ури-Бо, одного из многих магических постояльцев отеля. Окко предстоит раскрыть и другие секреты, которые скрывает гостиница, а еще разобраться — всегда ли нужно слушать старших и что значит быть настоящим другом.\n\n', 8.3, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1176141.jpg', 183, 6, 9, 1),
(334, 'Берегись автомобиля', 'Скромный страховой агент и актер театра самодеятельности Юрий Деточкин оказывается непримиримым борцом за справедливость. Он угоняет машины взяточников, продаёт их, а вырученные деньги перечисляет детским домам. Правда, для правосудия, представляемого актером того же театра, а в миру — следователем Подберёзовиковым, этот Робин Гуд представляется хитроумным, изобретательным и неуловимым преступником.', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/46089.jpg', 90, 42, 40, 1),
(335, 'Крепкий орешек', 'В суперсовременном небоскребе Лос-Анджелеса полицейский Джон Макклейн ведет смертельную схватку с бандой политических террористов, взявших в заложники два десятка человек, в число которых попадает и его жена. Началось все с того, что парень приехал в город к жене, оказался на рождественском приеме, а кончилось настоящей войной...', 8.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/471.jpg', 35, 40, 2, 1),
(336, 'Приключения Реми', 'Удивительное путешествие по Франции маленького Реми в компании уличного музыканта, обезьянки и цирковой собаки.  Вместе им предстоит пережить неожиданные встречи, приключения и испытания, чтобы раскрыть тайну происхождения мальчика.', 8.1, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1108571.jpg', 184, 6, 20, 1),
(337, 'Реквием по мечте', 'Каждый стремится к своей заветной мечте. Сара Голдфарб мечтала сняться в известном телешоу, ее сын Гарольд с другом Тайроном — сказочно разбогатеть, подруга Гарольда Мэрион грезила о собственном модном магазине, но на их пути были всевозможные препятствия. Все они выбирают неочевидные пути достижения своих целей, и мечты по-прежнему остаются недостижимыми, а жизни героев рушатся безвозвратно.', 8.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/367.jpg', 13, 22, 2, 1),
(338, 'Солдатик', 'История о волнующих и героических событиях, произошедших в жизни самого маленького солдата — героя Великой Отечественной Войны, шестилетнего Сережи Алешкова. Он потерял всех своих родных, попал в действующую армию. С шестилетним мальчиком затеяли игру в солдатика, чтобы сохранить ему детство, а он, чтобы соответствовать этому почетному для него званию, стал настоящим защитником Родины.', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1254051.jpg', 93, 6, 52, 1),
(339, 'Ирония судьбы, или С легким паром!', '31 декабря пошли друзья в баню попариться, по традиции смыть с себя все плохое, чтобы встретить Новый год чистыми, а «напарились» до такой степени (пивом и водкой), что отправили в Ленинград не того.', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/77331.jpg', 16, 39, 40, 1),
(340, 'Билли Эллиот', 'Чем должен увлекаться сын шахтера? Сомнений нет: боксом и только боксом. Но у 11-летнего Билли Эллиота на этот счет было свое мнение — он обожает балет.\n\nОтец и старший брат Тони впадают в ярость, когда узнают, что он променял бокс на «менее мужественный» балет. И только острая на язык миссис Уилкинсон поддерживает Билли в его желании танцевать, и он получает шанс поступить в Королевскую балетную школу.', 8.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/610.jpg', 55, 22, 48, 1),
(341, 'Мумия', 'На бескрайних просторах египетской пустыни компания сорвиголов разных национальностей рыщет в поисках несметных сокровищ фараона, над которыми тяготеет жуткое древнее проклятие.\n\nРядом с кладом покоится мумия коварного жреца, жестоко казненного за ужасное убийство могущественного правителя Египта. Золотоискатели потревожили многовековой покой гробницы, и мумия встает из могилы, чтобы погрузить мир в царство кошмара...', 7.8, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4484.jpg', 7, 20, 2, 1),
(342, 'Попкульт', '«Попкульт» — это проект на стыке ностальгии и любви к массовой культуре. В шоу, которое выходит на YouTube-канале «sndk», авторы разбирают прошлое на атомы через призму игр, анимации, кино, комиксов и технологий, чтобы понять, как формировалась современная индустрия развлечений. Каждый выпуск посвящён одному году и его релизам, которые повлияли на развитие поп-культуры.', 9.4, 'https://kinopoiskapiunofficial.tech/images/posters/kp/5260016.jpg', 185, 3, 1, 2),
(343, 'Герои Энвелла', 'История о четырех геймерах, которые нашли необычный ноутбук, оказавшийся порталом в мир игры «Герои Энвелла». Здесь все реально: и сам город, и его жители, и опасности, поджидающие на каждом шагу. В первом сезоне герои проходят игру и в финале сражаются с ее главным злодеем — Моргартом, который хочет вырваться в реальный мир. В продолжении сериала повзрослевшие ребята пытаются справиться с личными проблемами, но неожиданно из игры приходит сигнал о помощи. Арт, Кира, Вик и Фил возвращаются в мир Энвелла и встречают старых знакомых.', 9.3, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1072974.jpg', 186, 16, 1, 2),
(344, 'Космос', 'Астрофизик Нил Деграсс Тайсон встает за штурвал своего «Корабля воображения» и отправляется в путешествие по космосу, продолжив то, на чём остановился Карл Саган несколько десятилетий назад.', 9.3, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1309325.jpg', 185, 8, 2, 2),
(345, 'Шоу Грязного Фрэнка', 'Шоу повествует о героической борьбе сэра Фрэнсиса Грязного и его верных друзей против зловещего тёмного бога в сюрреалистической «омнивселенной».', 9.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1043658.jpg', 187, 7, 64, 2),
(346, 'Друзья', 'Шестеро друзей – Рейчел, Моника, Фиби, Джоуи, Чендлер и Росс – живут по соседству, вместе убивают время, делятся секретами и иногда очень сильно влюбляются.', 9.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/77044.jpg', 16, 27, 2, 2),
(347, 'LEGO Ниндзяго', 'Ниндзя сражаются со злодеями в Ниндзяго-Сити и за его пределами, отправляются на новые задания и обретают союзников, а их дружба проходит проверку на прочность.', 9.1, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1282979.jpg', 188, 8, 65, 2),
(349, 'Тара Дункан', 'Тара Дункан — обычная девочка, которая случайно попадает в Другой Мир, чтобы научиться контролировать свои волшебные силы и помочь своей семье защитить королевство Мими.', 9.1, 'https://kinopoiskapiunofficial.tech/images/posters/kp/5330292.jpg', 189, 21, 6, 2),
(350, 'Малышарики', 'Анимационный развлекательно-образовательный проект для малышей от 0 до 3 лет, охватывающий̆ все сферы жизнедеятельности ребенка с самого рождения: здоровье и физическое развитие, познание, социализацию, труд и творчество. Благодаря использованию современных технологий и положенных в основу разработок детских психологов и педагогов, проект органично сочетает в себе интерактивность и безопасность.', 9.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/988056.jpg', 190, 13, 1, 2),
(351, 'Волшебная девочка Кунг-Фу', 'Любопытная 8-летняя девочка всегда мечтала отправиться в приключения и исследовать удивительные места. Однажды она находит в прачечной своей матери странный носок, который умеет говорить. Раньше он был мастером кунг-фу из другого мира, которому было поручено охранять древний свиток. Когда мастер прошел через вихрь в это время, его силы ослабли, и он превратился в носок. Когда девочка надевает носок на ногу, она превращается в супергероиню — сногсшибательную девушку Кунг-Фу. И теперь, чтобы победить зло и защитить свой мир, вместе они должны выполнить миссию Кунг-Фу Ва и следовать древнему свитку.', 9.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/5217709.jpg', 191, 21, 37, 2),
(373, 'Гравити Фолз', 'История рассказывает о приключениях близнецов, брата и сестры Диппера и Мэйбл Пайнс, чьи летние планы отправляются в чулан, когда родители оправляют их к дальнему родственнику в тихий городок Гравити Фолз. Но так ли прост этот город, родственник и жители, и какие тайны ждут своих первооткрывателей?', 9.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/591929.jpg', 192, 2, 2, 2),
(374, 'Кот Басик', 'У самого обычного молодого программиста живет совершенно необычный кот по имени Басик. Он наделен сверхъестественным интеллектом. Впрочем, это никого не удивляет. В современном мире не принято удивляться. И очень зря! Ведь Басик действительно удивительный кот. Он умный, сдержанный, заботливый и к тому же настоящий джентльмен. Его забавные приключения и хитроумные проделки удивят и позабавят не только хозяина, но и зрителей!', 9.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/5231945.jpg', 193, 3, 1, 2),
(376, 'Геройчики', 'Мальчик Рома очень любит играть, поэтому в его комнате полным-полно разных игрушек. Кого здесь только нет: и загадочный пушистый инопланетянин Бублик, и отважный петух-тянучка Ко-Ко, и благородная ящерица-самурай О-Раш, и милая куколка Пинки, и воинственный плюшевый заяц Генерал Де-Кроль со своими роботами, и, конечно, отважные супергерои Флай и Глория. Все эти игрушки обожают игры, веселье, соревнования, приключения и вечеринки.\n\nКогда Ромы нет в комнате, они живут собственной увлекательной игрушечной жизнью. Но, если что-то случается с их любимым Ромой, Геройчики тут же бросают свои затеи и делают все возможное, чтобы помочь ему справиться с неприятностями.', 9.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/5126621.jpg', 193, 3, 1, 2),
(377, 'Просто о важном. Про Миру и Гошу', 'В центре мультсериала – обыкновенная семья с двумя детьми и милой собачкой по кличке Соня. Как и все дети, брат и сестра Гоша и Мира познают мир, играют, иногда ссорятся и попадают в затруднительные ситуации: дома, в школе или во дворе. Что делать, если тебя без причины обижают сверстники? А что, если они обижают кого-то другого? Как помириться после ссоры? И как перестать бояться старости? Зачем сознаваться в своей вине, и почему обман хуже ошибки? На эти и другие важные вопросы Гоше и Мире помогают ответить мама и папа. Маленькие герои убеждаются, что с поддержкой близких всегда можно найти выход; что добрые дела – самые простые, а честный и откровенный разговор творит чудеса!', 9.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/2039957.jpg', 195, 8, 1, 2),
(378, 'Подстрочник', 'Фильм «Подстрочник» - киномонолог Лилианны Лунгиной о жизни души и мира вокруг. С беспощадной зоркостью рассматривая собственное развитие с малых лет до последних дней, она делает внутренние события не менее увлекательными, чем внешние. Ее рассказ - это уникальное сочетание исповеди и масштабности, крупного и общего плана: это и портрет и фреска, потому что героиня ни на минуту не упускает из виду жизнь общую, общественную, пытаясь представить зрителям судьбу России и отчасти Европы в ХХ веке.', 9.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/468815.jpg', 196, 37, 1, 2),
(379, 'Лалабук', 'Библиотека мульткниг для детей от 2 до 7 лет. Мульткниги — полезные и красивые мультфильмы по книгам детских писателей с иллюстрациями профессиональных художников.', 9.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4976275.jpg', 193, 21, 1, 2),
(380, 'Цветняшки. Колыбельные', 'Сказочные истории, наполненные родительской любовью и заботой с качественным музыкальным оформлением и уникальными голосами озвучания, помогающие малышу настроиться на дневной и ночной сон.', 9.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/5258285.jpg', 193, 3, 1, 2),
(381, 'Братья Кратт: Зов природы', 'Крис и Мартин исследуют дикую природу всего мира, чтобы побольше узнать о жизни животных. Всюду их сопровождают верные друзья Авива, Коки и Джимми. С помощью специальных супер-костюмов братья Кратты могут повторять все, что делают сами животные. Эта сверхспособность позволяет ребятам не только наблюдать за дикими зверями, но и выручать их в опасных ситуациях.', 9.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/574810.jpg', 197, 19, 19, 2),
(382, 'Гормити', 'Давным-давно волшебный остров Горм находился под угрозой страшного врага — дарканов. Гормити под предводительством своих могущественных лордов объединили силы, чтобы противостоять этой угрозе. Война разразилась, но Гормити победили! Сегодня эту битва помнят как легендарную. Единственное оставшееся доказательство — это Единая башня, древняя крепость защитников добра. \n\nКогда четверо юных героев — Трек, Риф, Айкор и Эрон — обнаруживают башню, сбывается пророчество: дарканы вернулись! Наши герои должны попытаться призвать легендарных Гормити и раскрыть свои силы, чтобы спасти мир!', 9.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1285303.jpg', 193, 6, 67, 2),
(383, 'МегаМен: Полный заряд', 'В течение многих лет роботы и люди мирно жили бок о бок в футуристическом мире высоких технологий Кремниевого Города. Однако есть те, кто стремится разрушить этот баланс. К счастью, в Кремниевом Городе есть свой защитник – это Аки Лайт. Он обычный жизнерадостный школьник-робот со своим секретом… Глубоко в его программе лежат протоколы, которые могут превратить его в могущественного героя Мегамена!', 9.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1048721.jpg', 186, 6, 68, 2),
(384, 'Кубокот — в школу без забот', 'Кот Кубокот рассказывает, что и как надо подготовить к школе, чем в школе занимаются, какие необычные школы бывают и многое другое.', 8.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/5366407.jpg', 193, 1, 1, 2),
(385, 'Семнадцать мгновений весны', 'Германия, канун окончания Второй мировой войны. Советский разведчик полковник Исаев, он же - штандартенфюрер СС Штирлиц, исполняет последние задания Центра, диктуемые ходом военных действий и политическими интригами верхов противоборствующих сторон.', 8.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/89540.jpg', 198, 28, 40, 2),
(386, 'Вернуться в 1988', 'Жизнь дружелюбной компании соседей, которая живет словно большая семья, на фоне Олимпиады 1988 года в Сеуле. В каждой семье есть проблемы, но многие начинают верить в маленькое чудо на фоне грандиозного события, которое вскоре состоится в их городе.', 8.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/944829.jpg', 16, 13, 61, 2),
(387, 'Боевой континент', 'Тан Сань, один из самых способных учеников клана боевых искусств, крадет запретные знания своих мастеров. Это преступление карается смертью, поэтому Тан прыгает со скалы, погибает, а затем возрождается на Боевом континенте — месте, где у каждого есть свой дух, и где выживают только сильнейшие. Однако здесь Тан — сын кузнеца, а его дух — самый слабый в этом мире.', 8.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1338006.jpg', 199, 6, 37, 2),
(388, 'Блуи', 'Озорная, любопытная и полная идей Блуи — щенок австралийской пастушьей собаки. Она живёт вместе с родителями и младшей сестрой Бинго в большом уютном доме. Каждый день Блуи придумывает весёлые игры.', 8.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1338495.jpg', 67, 6, 3, 2),
(389, 'LEGO City Приключения', 'Сериал, состоящий из забавных, остроумных, динамичных зарисовок на тему городской жизни. Он посвящён надеждам, мечтам и злоключениям постоянно растущего сообщества уникальных персонажей.', 8.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1263620.jpg', 200, 8, 69, 2),
(390, 'Великая война', 'Проект «Великая война» рассказывает о наиболее значимых событиях и сражениях Великой Отечественной войны.', 8.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/503264.jpg', 201, 19, 1, 2),
(391, 'Шерлок', 'События разворачиваются в наши дни. Он прошел Афганистан, остался инвалидом. По возвращении в родные края встречается с загадочным, но своеобразным гениальным человеком. Тот в поиске соседа по квартире. Лондон, 2010 год. Происходят необъяснимые убийства. Скотланд-Ярд без понятия, за что хвататься. Существует лишь один человек, который в силах разрешить проблемы и найти ответы на сложные вопросы.', 8.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/502838.jpg', 45, 19, 8, 2),
(392, 'Во все тяжкие', 'Школьный учитель химии Уолтер Уайт узнаёт, что болен раком лёгких. Учитывая сложное финансовое состояние дел семьи, а также перспективы, Уолтер решает заняться изготовлением метамфетамина. Для этого он привлекает своего бывшего ученика Джесси Пинкмана, когда-то исключённого из школы при активном содействии Уайта. Пинкман сам занимался варкой мета, но накануне, в ходе рейда УБН, он лишился подельника и лаборатории.', 8.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/404900.jpg', 3, 37, 2, 2),
(393, 'Детектив Финник', 'Думаете, Берг тихий и спокойный городок? Как бы не так — он полон тайн и загадок. То вдруг остановятся все часы, то по рельсам проедет трамвай-призрак, то внезапно все улицы заполонят странные собаки. Но жители могут спать спокойно, ведь на страже порядка — Финник, первый в мире детектив-домовой. Этот сыщик обладает уникальным методом проб и ошибок и всегда готов встать на защиту своих друзей и всего города. Тайны, выходите на свет!', 8.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/5214685.jpg', 202, 3, 1, 2),
(395, 'Музыкальный патруль. Сказочные песни', 'В своих песнях персонажи расскажут, о чем мечтают и грустят, чему радуются.', 8.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/5301073.jpg', 193, 21, 1, 2),
(396, 'Вперед, Астробой!', 'Астробой — добрый мальчик-андроид, созданный учёным в память о погибшем сыне. В отличие от обычных роботов, Астробой не только сильный и очень умный, но способен на самые настоящие человеческие эмоции и чувства.\n\nАстробою и его лучшим друзьям предстоит много приключений и очень важных заданий. Вместе с профессором Элефаном, кошечкой Астрокитти и внучкой профессора Сузу мальчик-андроид займётся решением самых разных экологических проблем. Победить паразитов, губящих растения? Спасти маленьких черепашек? А может даже решить проблемы космического масштаба? Всё эту под силу смелому Астробою!', 8.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1044144.jpg', 193, 8, 70, 2),
(397, 'Время «Спартака»', 'История становления футбольного «Спартака» — легендарной команды, которая выигрывала чемпионство за чемпионством и побеждала сильнейшие клубы Европы в Лиге чемпионов. Олег Романцев, Владимир Бесчастных, Дмитрий Аленичев, Егор Титов, Станислав Черчесов, Андрей Тихонов и другие звёзды клуба вспоминают, как были добыты самые важные победы и на фоне каких событий 90-х они случились.', 8.7, 'https://kinopoiskapiunofficial.tech/images/posters/kp/5401054.jpg', 185, 1, 1, 2),
(398, 'Список Ланъя', 'Семья Линь была обвинена в измене и приговорена к смерти. 19-летнему Линь Шу, командующему одного из отрядов армии династии Лян, удалось выжить и спрятаться в Цзянху, мире бойцов. Приняв личность ученого Мэй Чансу, он основывает союз Цзянцзо и готовится отомстить.', 8.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1008652.jpg', 73, 13, 37, 2),
(399, 'Кунг-фу кролик', 'Молодой аниматор Винсент нарисовал кролика, оживающего на страницах его альбома. Зверек оказался умным, смелым и довольно своенравным, что ставит художника в затруднительные ситуации. Разочарованный и раздраженный, Винсент решает нарисовать собаку, чтобы перехитрить кролика и поставить его на место. Однако, к разочарованию создателя, ловкому пушистику каждый раз удается перехитрить пса. Таким образом три «заклятых друга» живут вместе, превращая свою обычную жизнь в хаос, приключения, а главное — в бесконечное веселье.', 8.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/5217900.jpg', 67, 5, 37, 2),
(400, 'Трон, отмеченный богом', 'Однажды появились демоны и боги-демоны, из-за которых всё человечество оказалось на грани гибели. В один момент 6 храмов объединились ради спасения мира людей, и началась великая война. Маленький мальчик решил присоединиться к храму в качестве рыцаря, чтобы спасти свою мать. Тренируясь, он пытается возвыситься, стать самым могучим рыцарем и унаследовать трон в этом жестоком мире на грани гибели.', 8.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/5237286.jpg', 199, 3, 37, 2),
(401, 'Колобанга. Только для пользователей интернета', 'В городке Колобанга живут всем известные смайлы-колобки. Они отвечают за электронную переписку Антона и передают в сообщениях его эмоции. Жизнь колобков вполне можно было бы назвать веселой и беззаботной, если бы не одно происшествие: однажды из Колобанги похищают почтовую собачку Атоса. Пока Сыщик устраивает допросы и ищет свидетелей, смелые друзья Колобок, Умник и Чёлка пускаются в невероятную интернет-авантюру.', 8.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/940678.jpg', 203, 13, 1, 2),
(402, 'Birchpunk', 'Истории из разных городов России будущего, где технический прогресс гармонично сочетается с загадочной русской душой. Люди перемещаются на космопоездах, но на полустанках до сих пор продают жареную курицу в фольге. В городах развёрнута сверхбыстрая сеть 20G, но почтовые посылки теряются на просторах Солнечной системы. В мире будущего, где роботы стали обыденностью, Россия не готова отказаться от привычек прошлого.', 8.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1451274.jpg', 66, 14, 1, 2),
(403, 'Корги по имени Моко. Защитники планеты', 'Пришелец из космоса мистер Оу нарушает мирную жизнь Юмми и Моко. Упавший в окрестностях городка Айфай волшебный метеорит сильно изменил судьбу Моко. Оказалось, что Моко на самом деле — разумный мнопланетянин! С прибытием мистера Оу Моко обретает способность говорить и узнаёт, что ему грозит опасность похищения.', 8.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/5311724.jpg', 204, 3, 37, 2),
(404, 'Цветняшки', 'В волшебном альбоме Капелек Цветняшек живут Курочка Коко, Цыплёнок Пи, Волчонок У, Лисёнок Айяяй, Котёнок Мур и Зайчонок Скок. Каждый из них в интерактивном формате совершенствует навыки малыша — социальные, интеллектуальные, физические, сенсорные, музыкальные, художественные.', 8.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4463778.jpg', 205, 21, 1, 2),
(405, 'Романовы', 'Уникальный по форме проект, приуроченным к  400-летию воцарения на Руси дома Романовых, который сочетает в себе элементы и игрового, и документального кино, информационной графики и анимации. История расскажет о том, что представляло собой русское самодержавие как система управления, каковы ее недостатки и преимущества, какую роль монархи дома Романовых играли в событиях российской и мировой  истории. При помощи графики  создается максимально исторически-достоверная картина, которая погружает зрителя в атмосферу и ощущение времени и позволяет увидеть царя глазами современников.', 8.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/743975.jpg', 206, 17, 71, 2),
(406, 'Идефикс и неукротимые', '52 год до н. э. Жители небольшого кельтского городка Лютеция — люди мирные, но гордые и независимые. Когда многочисленная римская армия захватила их земли, каждый из них был готов биться за свою свободу. Причем не только люди, но и животные. Бездомный пёс по кличке Идефикс собирает банду, чтобы дать отпор римлянам. Кроме собак, в нее вступают кошка, сова и даже голубь, и у каждого из них есть невероятные способности. Эти маленькие герои готовы творить великую историю!', 8.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4635061.jpg', 96, 21, 6, 2),
(407, 'Алое сердце', 'Во время солнечного затмения девушка из XXI века Ко Ха-джин попадает в прошлое, во времена государства Корё. Она просыпается в 941 году в теле 16-летней аристократки Хэ-cу. Она помнит всё, но не может вернуться обратно и вынуждена жить по законам старого мира.', 8.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/984001.jpg', 139, 50, 61, 2),
(408, 'Зук', 'Зук — восьмилетняя зеленоволосая ведьма, дочь двух колдунов, которая летает на метле среди городских многоэтажек. Она посещает Школу магии и мечтает помогать другим своим колдовством. Но каждый раз случаются ситуации, противоречащие добрым намерениям ведьмочки. В конце концов ей всегда удаётся исправить ошибки благодаря правильному заклинанию и помощи друзей.\n\n', 8.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/5146135.jpg', 193, 21, 6, 2),
(409, 'Катя и Эф. Куда-Угодно-Дверь', 'Откуда появляются булочки на завтрак, почему подводная лодка все время тонет, как из горы появляются вилки и ложки и зачем синоптикам сачки? В первом сезоне девочка Катя и ее друг Эф отправляются на пекарни-заводы-поезда-пароходы и разбираются, как все работает.\n\nВо втором сезоне Катя и Эф путешествуют по разным странам и ходят в гости к детям по всему миру. Они узнают интересные факты про традиции, культуру и увлечения жителей, любуются достопримечательностями, занимаются разными видами спорта и готовят удивительные блюда.', 8.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1199602.jpg', 207, 6, 1, 2),
(410, 'Радужно-бабочково-единорожная кошка', 'Весёлая кошечка по имени Фелисити владеет волшебными силами. Её и всех её друзей ждёт много приключений в удивительном и мифическом мире.\n\n', 8.8, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1231066.jpg', 40, 8, 19, 2),
(412, 'Корги по имени Моко. Новый питомец', 'Юмми — маленькая девочка из обычной семьи. Однажды в ее жизни появляется милый щенок — корги по имени Моко. Никто не знает, откуда он взялся, и, похоже, он совершенно не умеет скучать. Любой, кто видит его, сразу тает от милой собачьей мордашки, но только не Юмми. Когда она узнаёт, что Моко собирается жить в их доме, она очень расстраивается. Как она может заботиться о какой-то собаке, когда она — сама беззаботность! Однако Моко полон решимости стать любимым питомцем Юмми.', 8.7, 'https://kinopoiskapiunofficial.tech/images/posters/kp/5311518.jpg', 193, 14, 37, 2),
(413, 'Том и Джерри', 'Кот Том гоняется за мышонком Джерри. Том придумывает хитроумные уловки, чтобы поймать Джерри, но тот всё время выкручивается из самых сложных ситуаций.', 8.8, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1372775.jpg', 209, 67, 2, 2),
(414, 'Космос: Возможные миры', 'Путешествие к новым мирам – потерянным, и тем, что ещё предстоит открыть. ', 8.8, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1320688.jpg', 185, 14, 2, 2),
(415, 'Врачебная мудрость', 'Истории врачей и медсестёр, которые окончили один медуниверситет в 1999 году и теперь работают вместе.', 8.8, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1281965.jpg', 125, 14, 61, 2),
(416, 'Братцы кролики', 'Истории о двух братьях кроликах — Оскаре и Адаме и их сестре Мэри, живущих в старинном замке по соседству с древними тайнами, привидениями и сказочными обитателями маленькой страны чудес. Главные герои не обязательно белые, но точно пушистые. Они где-то символизируют плодовитость и жизненную силу, где-то мастерски дурачат врагов, а где-то смотрят на луну и готовят эликсир бессмертия.', 8.7, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4534959.jpg', 193, 21, 1, 2),
(417, 'Путешествие к бессмертию', 'Обычный деревенский мальчишка случайно становится учеником небольшой секты. Несмотря на поджидающие трудности, он сразится с демонами и древними небожителями, чтобы найти свой собственный путь к бессмертию.', 8.8, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4530267.jpg', 199, 14, 37, 2),
(418, 'Амфибия', '13-летняя Энн оказывается в волшебном мире земноводных, сельской болотистой местности, которая полна человекоподобными лягушками. С помощью азартной молодой лягушки по имени Прутик, Энн превратится в героя и откроет для себя первую настоящую дружбу в своей жизни.', 8.8, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1174294.jpg', 210, 8, 72, 2),
(419, 'Бодо Бородо', 'Бодо Бородо, лучший учитель в мире по его собственному же мнению, не знает ничего, но сможет научить детей всему.', 8.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4404822.jpg', 190, 14, 1, 2),
(420, 'Полли Покет', 'Приключения находчивой девочки Полли, которая доказывает, что сильным может быть даже самый маленький человек. Взрослые часто говорят Полли, что она ещё слишком мала, чтобы делать всё, что ей хочется. Но Полли доказывает, что быть маленькой — это не ограничение, а наоборот, большой плюс. Это её главная сила! \n\nОднажды героиня наследует волшебный медальон, который уменьшает её до размеров 10 сантиментов. Благодаря этой способности Полли и её друзья постоянно попадают в классные приключения и решают проблемы необычным способом.', 8.8, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1172191.jpg', 211, 6, 19, 2),
(421, 'Дикие скричеры', 'В недалеком будущем все сходят с ума по скричерам - машинкам-трансформерам. В Зэфер-Сити проходит Скричер-чемпионат, победители которого становятся настоящими звёздами. В этом городе живут братья Ксандер и Ринго, которые мечтают когда-нибудь одержать победу в соревновании, но у них пока нет скричеров... Однажды в тренировочную машинку Ксандера попадает Джейхок, и она становится настоящим скричером с живой душой. Теперь Ксандер может участвовать в скричер-баттлах. Удастся ли ему осуществить свою мечту?', 8.8, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1172552.jpg', 212, 6, 37, 2),
(423, 'Крошечный мир', 'О крошечных существах различных экосистем, а также об их необычных навыках, помогающих им приспосабливаться к переменчивому и жестокому миру.', 8.8, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1404244.jpg', 185, 14, 2, 2),
(424, 'Lego Friends: Девчонки на задании', 'Пять подружек выполняют опасное задание по спасению своего города.', 8.8, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1225454.jpg', 214, 6, 73, 2),
(425, 'Кинопоиск: Как понимать кино', 'Сериал о том, как устроено кино. В каждом эпизоде рассказывается про разные аспекты кинотеории, которые помогут не просто смотреть фильмы, а по-настоящему понимать, как они сделаны.', 8.8, 'https://kinopoiskapiunofficial.tech/images/posters/kp/5354868.jpg', 185, 6, 1, 2),
(426, 'Эрнест и Селестина', 'Эрнест — большой косолапый медведь, клоун и музыкант — однажды приютил в своем доме маленькую Селестину — мышку-сиротку, сбежавшую из подземного мира своих сородичей. Эти два одиночки чувствуют себя очень комфортно вместе и всячески помогают друг другу, тем самым нарушая установленный порядок. Потому что обычно в мире медведей не одобряют дружбу с мышами. Как и в мире мышей: медведи считаются троллями-людоедами. Друзья никогда не скучают! По мере приближения первого снега они готовятся к спячке Эрнеста: нужно позаботиться о Биби, их диком гусе, который улетит еще до наступления больших холодов, сходить на бал мышей и отпраздновать первый день зимы. Наконец, надо приготовить вкусные тортики, чтобы Эрнест как следует перекусил перед сном!', 8.8, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1074581.jpg', 67, 16, 6, 2),
(427, 'Про людей и про войну', 'Цикл трагических, героических или даже смешных историй, которые произошли с молодыми людьми во время Великой Отечественной. Девушки и ребята, чьи мечты, планы и представления о счастье изменила война.', 8.8, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4443792.jpg', 215, 14, 1, 2),
(428, 'Тоботы. Детективы Галактики. Спин-офф', 'Тоботы Тайлера сталкиваются с инопланетным роботом по имени Сваг и его Тоботами, намеревающимися свергнуть первоначальную команду. Вскоре им приходится работать вместе, чтобы победить Android-юнкеров — группу роботов-криптидов, охотящихся на Тоботов, чтобы выкачать их V-энергию и восстановить своё абсолютное оружие. Тоботы, вперед!', 8.8, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4819407.jpg', 186, 21, 61, 2),
(429, 'Лекс и Плу: Космические таксисты', 'Лис Лекс и енот Плу живут на окраине Вселенной и занимаются любимым делом — работают космическими таксистами. Лекс и Плу — романтики и выдумщики, все свои поездки они совершают на машине, которую собрали сами. Она их не подводит, как и остальные товарищи по команде: лисичка Триша, голубоногая олуша Грэг и грибочек Криспи. Это точно не команда супергероев, и они не стремятся к славе, но случайно по дороге могут спасти пару планет.', 8.8, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1395807.jpg', 207, 8, 1, 2),
(430, 'Российская империя', 'Многонедельные съемки в столицах и десятки поездок по бывшей и настоящей территории страны. Это уникальные места, где никогда прежде не бывала телекамера: от польской деревни на пути Петра Великого до крыши Эрмитажа. Это все немецкие городки, из которых вышли русские императрицы. Места боевой славы русской армии — от Рима до Бейрута — и места национальных катастроф — от Севастополя до Восточной Пруссии. Исторические анекдоты и подлинные дневники, неизвестные документы и письма первых людей империи.', 8.8, 'https://kinopoiskapiunofficial.tech/images/posters/kp/453188.jpg', 206, 22, 1, 2);
INSERT INTO `media` (`id`, `title`, `description`, `rating`, `image_url`, `genre_id`, `year_id`, `country_id`, `type_id`) VALUES
(431, 'Мэгги и Бьянка в Академии моды', 'Героиня сериала Мэгги Дэвис — обычная американская девушка, которая мечтает стать всемирно известным дизайнером одежды.\n\nТакой случай выпадает на её 16-летие, когда Мэгги становится самой молодой в истории победительницей конкурса и получает двухлетнюю стипендию на обучение в Миланской Школе Дизайна. Там она встречает Бьянку — самодовольную итальянскую «принцессу».\n\nДевушек объединяет любовь к музыке и моде. Вместе они разгадают множество секретов, которые приготовила им судьба.', 8.8, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1046653.jpg', 216, 50, 44, 2),
(432, 'Фиксики. Новенькие', 'Мультсериал рассказывает о приключениях маленьких человечков — Фиксиков, которые живут внутри различных приборов и техники, содержат её в порядке и отлично знают, что и как устроено.', 8.8, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1351747.jpg', 193, 14, 1, 2),
(433, 'Алхимия душ', 'Душа великой воительницы оказывается запертой в теле слабой девушки, которая становится слугой заносчивого и вредного дворянина.', 8.8, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4872515.jpg', 217, 3, 61, 2),
(434, 'Команда МАТЧ', 'Команде зверей интересны нетипичные для них виды спорта. Их тренер, известный чемпион Лев Борисович, находит новаторские способы вдохновить юных спортсменов на достижение высоких результатов. Любительская команда бьет рекорд за рекордом, что не остается без внимания в спортивном сообществе. Кто же эти таинственные новички, вытеснившие признанных лидеров из турнирных таблиц?', 8.8, 'https://kinopoiskapiunofficial.tech/images/posters/kp/5111408.jpg', 218, 3, 1, 2),
(435, 'Спина к спине', 'Стоит только оставить друзей-рюкзачков – Рюка, Ботю и Моли – одних без присмотра, как они попадают в очередное удивительное приключение.  ​', 8.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1445210.jpg', 193, 14, 1, 2),
(436, 'Котенок Шмяк', 'Каждодневные приключения лучших друзей — котенка Шмяка и мышонка Сырника, которые живут в небольшом городишке и вместе познают силу доброты, дружбы и взаимовыручки.', 8.8, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4913499.jpg', 207, 14, 6, 2),
(437, 'Невероятные факты эволюции', 'Рассказ об особенностях жизни различных представителей животного мира.', 8.8, 'https://kinopoiskapiunofficial.tech/images/posters/kp/5278346.jpg', 219, 6, 9, 2),
(438, 'ВИП петс', 'Мы живем в мире, где собаки могут говорить и общаться друг с другом, но люди не знают и не понимают их. В этом мире есть 6 очень модных собак, VIP-питомцев. У каждого из них есть своя индивидуальность и хобби, но у всех есть общая страсть к волосам и любовь к укладке. VIP-питомцы тоже говорят, как и другие собаки, но их хозяйка этого не знает. Единственные, кто могут понять и поговорить с ними — это Фабио и Фабия. Фабио — самый крутой стилист в городе, и у него есть парикмахерская для людей, но в задней комнате, у него очень особенные клиенты: VIP-питомцы. Фабия — племянница Фабио, которая хочет стать парикмахером и помогает своему дяде и VIP-питомцам во многих ситуациях.', 8.8, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4820170.jpg', 193, 8, 24, 2),
(439, 'Блич: Тысячелетняя кровавая война', 'В Каракуре, родном городе Итиго Куросаки, начинают пропадать люди, а Общество душ фиксирует внезапный рост количества «пустых», уничтоженных в мире живых. Вскоре Итиго предстоит вступить в битву с лидером квинси, который собирается уничтожить Общество душ.', 8.7, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4789626.jpg', 220, 3, 9, 2),
(440, 'Приключения Пети и Волка', 'История о приключениях обычного школьника Пети и его друга Волка, связывающего мир людей с миром сказок. Петя помогает волшебным героям решать их волшебные проблемы, требующие нестандартного подхода.', 8.8, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1309185.jpg', 67, 6, 1, 2),
(441, 'Ум и Хрум', 'О вкусных приключениях двух обаятельных друзей-монстриков. Они обитают на удивительной планете, где всё вокруг состоит из еды. Но Хрум совершенно не знает меры и все время объедается разными вкусняшками, после чего моментально превращается в то, что съел. И теперь уже его умнейшему лучшему другу Уму предстоит выпутываться из разных неприятностей.', 8.8, 'https://kinopoiskapiunofficial.tech/images/posters/kp/5258067.jpg', 193, 3, 1, 2),
(442, 'Аркейн', 'История разворачивается в утопическом краю Пилтовер и жестоком подземном мире Заун и рассказывает о становлении двух легендарных чемпионов Лиги и о той силе, что разведёт их по разные стороны баррикад.', 8.8, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4445150.jpg', 221, 21, 4, 2),
(443, 'Тру и Радужное королевство', 'Когда прекрасный мир Радужного Королевства настигают проблемы, остается одна надежда на Тру! С её несмышлёным лучшим другом Котом Бартлби. Только Тру может высвободить силу Магических Желаний из Дерева Желаний для восстановления мира и любви в Королевстве.', 9.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1048695.jpg', 222, 16, 19, 2),
(444, 'Смешарики. Новый сезон', 'Истории о дружбе и приключениях обаятельных круглых героев. Весёлые и музыкальные, неожиданные и мечтательные, домашние и авантюрные. Целый мир в одной уютной Ромашковой долине.', 9.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1379016.jpg', 195, 14, 1, 2),
(445, 'Рик и Морти', 'В центре сюжета - школьник по имени Морти и его дедушка Рик. Морти - самый обычный мальчик, который ничем не отличается от своих сверстников. А вот его дедуля занимается необычными научными исследованиями и зачастую полностью неадекватен. Он может в любое время дня и ночи схватить внука и отправиться вместе с ним в безумные приключения с помощью построенной из разного хлама летающей тарелки, которая способна перемещаться сквозь межпространственный тоннель. Каждый раз эта парочка оказывается в самых неожиданных местах и самых нелепых ситуациях.', 9.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/685246.jpg', 223, 17, 2, 2),
(447, 'BadComedian', 'Юмористическое шоу, высмеивающее плохое кино. От российских «шедевров», до американской клюквы. А также серьёзные обзоры и переводы.', 9.1, 'https://kinopoiskapiunofficial.tech/images/posters/kp/972889.jpg', 225, 7, 1, 3),
(448, 'Хочу все знать!', 'Сколько в мире денег? Почему сегвей не падает? Что будет, если бросить атомную бомбу в жерло вулкана? Что такое «облако» или где хранится ваша информация? И когда же изобретут лекарство от рака? Уместить в голове все знания о нашей необъятной планете невозможно, хотя… Новый цикл легендарного киножурнала «Хочу все знать!» — это сериал-энциклопедия, в котором интереснейшие факты — от устройства Сахары до особенностей криозаморозки человека — объясняются просто и увлекательно.', 9.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4459937.jpg', 226, 21, 1, 3),
(449, 'Джейми Оливер: Готовим вместе', 'Джейми возвращается к своим зрителям в новом цикле кулинарных передач, построенном на трёх основных «ингредиентах»: семье, друзьях и еде. В каждом выпуске легендарный шеф на своей кухне будет делиться рецептами блюд, которые в тарелке создают волшебство, готовятся за минуты, удивляют до глубины души и влюбляют навсегда. Зрители узнают о новых идеях для превосходного барбекю, идеального пикника, зажигательного вечера в ритме танго и тако, затейливого расслабленного бранча с «изюминкой» и роскошного вечера, наполненного ароматом карри — у Джейми в запасе богатый арсенал советов и кулинарных лайфхаков на любой случай.', 9.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4886080.jpg', 224, 21, 28, 3),
(450, 'Топ Гир: Лучшее', 'Специальные выпуски телепередачи Топ Гир.', 9.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1227897.jpg', 227, 9, 28, 3),
(451, 'КьюАй. Весьма интересно', 'Комедийно-познавательная передача в форме игры, где ценится не столько ум или энциклопедические познания, сколько остроумие и умение импровизировать. Наряду с правильными ответами, засчитываются прежде всего интересные.', 8.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/493902.jpg', 228, 15, 28, 3),
(452, 'Эксперименты', 'Шоу показывает опыты с пылесосом, магнитной пушкой, градусником, газировкой, электрошокером и другими техническими устройствами.', 8.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4727482.jpg', 224, 21, 1, 3),
(453, 'Простые блюда на каждый день от Джейми Оливера', 'Джейми Оливер предлагает блюда, которые каждый может приготовить дома. Речь идет о простой семейной еде, создающей хорошее настроение: незатейливые, экономичные и аппетитные блюда дают прекрасный повод встретиться с близкими.', 8.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4290072.jpg', 224, 14, 28, 3),
(455, 'Бегущий человек', 'Развлекательное шоу в жанре городской погони. Постоянные участники сталкиваются в различных испытаниях и играх с лучшими артистами Кореи, будь то айдолы, актеры или просто медийные персонажи. Участники и гости оказываются запертыми в различных городских объектах (университет, театр, музей, стадион и т.д.) на неопределённое время. Разделившись на команды они должны наперегонки выполнять различные задания и конкурсы на получение призов. В финале проигравшая команда понесёт унизительное наказание.', 8.8, 'https://kinopoiskapiunofficial.tech/images/posters/kp/762100.jpg', 230, 19, 61, 3),
(456, 'Гранд тур', 'Автомобильные обзоры, приключения по всему миру, встречи со знаменитостями и юмор, который является непременным атрибутом каждого выпуска.', 8.8, 'https://kinopoiskapiunofficial.tech/images/posters/kp/982730.jpg', 231, 50, 8, 3),
(457, 'LAB с Антоном Беляевым', 'Музыкальная лаборатория, где известные артисты общаются о творчестве, исполняют свои композиции в необычных аранжировках, а также записывают совершенно неожиданные версии хитов других музыкантов.', 8.7, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1387178.jpg', 232, 14, 1, 3),
(458, 'Правила моей кухни', 'Острое австралийское кулинарное реалити-шоу. Под чутким руководством блестящих ведущих Пита Эванса и Ману Фиделя участники соревнуются друг с другом, выполняя изощренные задания. За определенное время необходимо приготовить одно или несколько блюд на заявленную ведущими тему. Позже все блюда оцениваются судьями, после чего одна из команд выбывает. С каждым новым заданием борьба становится все более ожесточенной, ведь на кону приз в $250 000.', 8.7, 'https://kinopoiskapiunofficial.tech/images/posters/kp/788496.jpg', 224, 19, 74, 3),
(459, 'Доктор Пол', 'Доктор Пол уже видел более 100 000 пациентов. Этот специалист по крупным сельскохозяйственным животным совсем не собирается уходить на пенсию и по-прежнему придерживается старой школы и серьезного подхода к ветеринарии. Непоколебимый и неудержимый, доктор обычно работает по 14 часов в день и является легендой в сообществе. ', 8.7, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1261626.jpg', 233, 7, 2, 3),
(460, 'Импровизаторы', 'Комики проходят проверку на способность импровизировать.', 8.6, 'https://kinopoiskapiunofficial.tech/images/posters/kp/5267860.jpg', 234, 1, 1, 3),
(461, 'Большой побег', 'Героям нужно выбраться из здания, найдя подсказки и разгадав загадки.', 8.6, 'https://kinopoiskapiunofficial.tech/images/posters/kp/5265004.jpg', 224, 1, 1, 3),
(462, 'Топ Гир', 'Джереми, Ричард и Джеймс с неподражаемым юмором рассказывают о самых значимых и интересных новинках автомобильного мира.', 8.6, 'https://kinopoiskapiunofficial.tech/images/posters/kp/566602.jpg', 235, 25, 28, 3),
(463, 'Джейми Оливер: Продолжаем готовить', 'Джейми делится некоторыми из своих невероятных рецептов, которые помогут эффективно использовать продукты. У него в запасе есть идеи, как максимально экономно использовать скопившиеся в кладовых и холодильниках продукты, чтобы приготовить вкусные и питательные блюда из самых простых ингредиентов, и чем можно их заменить.', 8.6, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1374525.jpg', 224, 14, 28, 3),
(464, 'Забей на панк-рок', 'Комедийная телевикторина о поп-музыке.', 8.6, 'https://kinopoiskapiunofficial.tech/images/posters/kp/601995.jpg', 236, 68, 28, 3),
(465, 'Taskmaster', 'В каждом эпизоде шоу Грег Дэвис и его верный помощник Алекс Хорн бросают вызов пяти его участникам-комикам. Все они соревнуются в остроумии, хитрости и смекалке, попутно выполняя дурацкие и смешные задания, чтобы... вернуть собственные вещи.', 8.6, 'https://kinopoiskapiunofficial.tech/images/posters/kp/934169.jpg', 228, 13, 28, 3),
(466, 'Мир наизнанку', 'Каждый сезон программы «Мира наизнанку» представляет собой серию программ, посвященных одной отдельно взятой стране либо одному географическому региону. Программа посвящена жизни, работе, отдыху, привычкам, обрядам и национальным особенностям народов различных стран. Путешествие по одной стране или региону продолжается по несколько месяцев, в ходе которых съемочная группа пытается показать зрителю не туристические стороны данного региона,а самобытную культуру местного населения.', 8.5, 'https://kinopoiskapiunofficial.tech/images/posters/kp/893442.jpg', 233, 19, 66, 3),
(467, 'Расследования авиакатастроф', 'Реконструкция реальных воздушных катастроф, интервью с авиационным специалистами и очевидцами происшествий.', 8.6, 'https://kinopoiskapiunofficial.tech/images/posters/kp/470801.jpg', 237, 15, 39, 3),
(468, 'Суперниндзя', 'Экстремальное шоу, в котором участники проверяют свою выносливость, проходя полосу препятствий. Для победы в шоу участникам необходимо пройти отборочный этап, полуфинал, финал и суперфинал. Для успешного выступления в проекте важны скорость и количество загоревшихся колец, которые нужно снимать на каждом этапе. Если кольцо не срывается, участник не может продолжить испытание. В полуфинале семьдесят атлетов сражаются не только с трассой, но и друг с другом, проходя испытания в парной гонке на уникальной двойной полосе. Тридцать пять героев попадают в финал, и только двух лучших атлетов ждёт долгожданный суперфинал. Победит тот, кто сможет обогнать соперника и заполучить последнее кольцо на вершине 26-метровой башни.', 8.5, 'https://kinopoiskapiunofficial.tech/images/posters/kp/5255425.jpg', 238, 1, 1, 3),
(469, 'Галилео с Даней Крастером', 'Рассказывать о законах термодинамики, способах визуализации звука и истории знаков препинания будет Денис Колесников, а показывать эксперименты из области химии, физики и биологии — популярный блогер-изобретатель Даня Крастер, чьи видео собрали миллионы просмотров. Закрепить пройденные в школе материалы старшеклассникам помогут анимационные ролики, из которых можно будет узнать малоизвестные факты о культурных и технологических достижениях.', 8.5, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4402090.jpg', 224, 14, 1, 3),
(470, 'В студии актерского мастерства', 'Шоу начиналось как семинар для студентов, собирающихся стать актёрами и режиссёрами. Гостем каждого семинара был уже состоявшийся актёр или режиссёр, который отвечал на вопросы студентов и ведущего. Гость обычно рассказывал о своём детстве, о том, почему он решил выбрать для себя профессию, связанную с кинематографом, и какой вклад он внёс в киноискусство. Приветствовались также советы студентам и другая полезная информация, которая могла бы помочь им в обучении.', 8.4, 'https://kinopoiskapiunofficial.tech/images/posters/kp/401131.jpg', 239, 27, 2, 3),
(471, 'Королевские гонки РуПола', 'Участницами конкурса становятся драг-королевы (травести-артисты), которые должны демонстрировать не только подиумные таланты, но и множество других способностей: комедийные, песенные, дизайнерские и тому подобное.', 8.4, 'https://kinopoiskapiunofficial.tech/images/posters/kp/579509.jpg', 238, 10, 2, 3),
(472, 'Кофе с Караном', '«Кофе с Караном» - самое популярное в Индии ток-шоу с участием знаменитостей. Его бессменный ведущий - Каран Джохар, один из самых популярных режиссеров в современном Болливуде, дает зрителям заглянуть по ту сторону закулисной жизни индийского кино и узнать самые пикантные подробности личной и профессиональной жизни звезд первой величины. Среди его гостей - Амитабх и Абхишек Баччаны, Каджол, Шахрукх Кхан, Айшвария Рай, Ритик Рошан, Саиф Али Кхан, Рани Мукхерджи, Карина Капур, Прити Зинта, Джон Абрахам, Санни и Бобби Деол, Бипаша Басу, Дино Мореа и многие другие...', 8.4, 'https://kinopoiskapiunofficial.tech/images/posters/kp/516468.jpg', 234, 23, 75, 3),
(473, 'Голый повар', 'Это кулинарное шоу, в котором доступно объясняется, насколько увлекателен и интересен может быть процесс создания блюд. В каждой серии зритель сможет понаблюдать за шоу, устраиваемым безумно талантливым и знаменитым шеф-поваром Великобритании Джейми Оливером, который стремится научить телезрителей готовить вкусные, красивые и полезные блюда, превратив процесс приготовления в самую настоящую увлекательную игру, выступление с декламацией современной литературы, аттракцион и настоящее искусство. Благодаря «Голому повару» можно узнать о полезных и простых вещах, на которые мы не обращаем внимания в нашей повседневной жизни из-за чрезмерной загруженности, а также выяснить, как правильно подавать продукты на стол, как выбрать ингредиенты, чтобы они были свежими и как приготовить блюдо с легкостью и удовольствием.', 8.4, 'https://kinopoiskapiunofficial.tech/images/posters/kp/570004.jpg', 224, 20, 28, 3),
(474, 'Чемпионат мира по футболу 2018', '21-й чемпионат мира по футболу под эгидой ФИФА, финальная часть которого прошла в России. Россия впервые стала страной-хозяйкой мирового чемпионата по футболу, соревнования проходили на 12 стадионах в 11 городах.', 8.4, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1183580.jpg', 240, 6, 1, 3),
(475, 'Транссибирские следопыты', 'Группа известных корейских актёров бесстрашно путешествует через всю Россию по Транссибирской железнодорожной магистрали.', 8.4, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1328019.jpg', 241, 8, 61, 3),
(476, 'Исследователи человеческого тела', 'Программа о возможностях человеческого тела. Ведущий и участники поп-группы Super Junior ставят на себе различные эксперименты.', 8.4, 'https://kinopoiskapiunofficial.tech/images/posters/kp/790164.jpg', 225, 55, 61, 3),
(477, 'Шоу Эрика Андре', 'Комедийное ток-шоу Эрика Андре, погружающее зрителя в сюрреалистический мир.', 8.4, 'https://kinopoiskapiunofficial.tech/images/posters/kp/703286.jpg', 234, 2, 2, 3),
(479, 'Ген высоты, или как пройти на Эверест', 'Съёмочная группа присоединилась к экспедиции российских альпинистов на Эверест, для того чтобы совершить восхождение на высочайшую гору Земли. Первая экспедиция в 2015 году была прервана серией землетрясений. В 2016-ом году группа вернулась к подножию Эвереста, чтобы рассказать историю его покорения и показать от начала и до конца процесс восхождения на главную вершину мира.', 8.4, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1045927.jpg', 233, 16, 1, 3),
(480, 'Вегетарианская кухня с Джейми Оливером', 'Праздник всевозможных овощных блюд, побуждающих и мясоедов и вегетарианцев всегда ставить перед собой на стол овощи! Джейми полагает, что самое время перестать думать об овощах, как о дополнении к основной еде, — овощи способны сами стать героем шоу, и Джейми готов показать нам как. Джейми знает, что многие из нас хотят есть поменьше мяса — кто по соображениям здоровья, кто из-за денег, а кто-то из гуманных соображений. Все мы медленно движемся в этом направлении — есть больше овощей и меньше мяса.', 8.4, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1311182.jpg', 224, 8, 28, 3),
(481, 'Лучший пекарь Британии', 'Участниками телепрограммы становятся десять кулинаров-любителей, которые готовы побороться за звание лучшего пекаря Королевства.', 8.4, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1048025.jpg', 238, 19, 28, 3),
(482, 'TALK', 'Комики говорят на жизненные темы: от предпочтений в сексе до школьного буллинга.', 8.3, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1435297.jpg', 239, 14, 1, 3),
(483, 'Рогов в городе', 'Александр Рогов отправится в модное турне, которое охватит восемь крупнейших регионов страны — Санкт-Петербург, Нижний Новгород, Ростов-на-Дону, Екатеринбург, Самару, Казань, Уфу и Сочи.\n\nНа месте всего за сутки Рогов преобразит героинь, которые отчаялись измениться. С помощью местных специалистов и шопинг-центров Александр подберёт девушкам новые образы и покажет, что и в своём городе можно найти стильные вещи и выглядеть не хуже столичных штучек.', 8.3, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4320355.jpg', 224, 8, 1, 3),
(484, 'Импровизация', 'В шоу нет сценария и всё происходящее на сцене придумывается участниками на ходу. Под управлением ведущего Павла Воли четыре комика и один звездный гость оказываются в самых странных ситуациях и выбираются из них с юмором.', 8.3, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1047767.jpg', 234, 50, 1, 3),
(486, 'Орёл и решка', 'Каждые выходные двое ведущих отправляются в различные города мира. По правилам программы один ведущий должен прожить субботу и воскресенье на 100 долларов, а второй может тратить неограниченные средства, которые хранятся на золотой карте. Чтобы решить, кто из них будет жить как миллионер, а кто будет учиться выживанию, ведущие перед каждым путешествиям бросают монету, и каждый раз всё решает Орёл или решка.', 8.3, 'https://kinopoiskapiunofficial.tech/images/posters/kp/762373.jpg', 224, 7, 66, 3),
(487, 'Путешествия с Гордоном Рамзи', 'Гордон Рамзи совершенствует свои кулинарные способности. Отправляясь в самые отдаленные уголки мира, он путешествует по джунглям, ловит рыбу голыми руками и изучает рецепты местной кухни.', 8.3, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1412480.jpg', 243, 8, 2, 3),
(488, 'Игры разума', 'Программа «Игры разума» приглашает вас в путешествие в мир интерактивных игр и тестов, которые помогут вам понять, как устроен ваш мозг.  По-настоящему умопомрачительные эксперименты протестируют то, как ваш мозг воспринимает окружающий мир.', 8.3, 'https://kinopoiskapiunofficial.tech/images/posters/kp/635433.jpg', 244, 7, 2, 3),
(489, 'Обеды за 30 минут от Джейми', 'Кулинарное шоу с гением кулинарии Джейми Оливером. Здесь он демонстрирует как приготовить полноценный, вкусный обед, завтрак или ужин за время меньшее чем понадобится на доставку пиццы. Джейми Оливер не остепенился даже после женитьбы и рождения второй дочки. Он поселился в графстве Эссекс, где провел все свое детство, и вплотную занялся выращиванием овощей и фруктов на собственном участке. Джейми и здесь добился успеха, как он сам признается, выращивание собственного урожая приносит ему море радости.\n\nОн научит как приготовить вкусный и сытный обед всего за 30 минут. Джейми Оливер экономит наше время. Для наиболее занятых людей, у которых нет времени долго стоять у плиты после длинного рабочего дня. Знаменитый англичанин учит нас, как потратить на приготовление целого обеда не больше получаса, не жертвуя качеством блюд.', 8.3, 'https://kinopoiskapiunofficial.tech/images/posters/kp/574330.jpg', 224, 19, 28, 3),
(490, 'Просто кухня', 'Кулинарное шоу, в котором шеф-повар Александр Белькович показывает, как готовить вкусно, быстро и недорого.', 8.3, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4447612.jpg', 224, 16, 1, 3),
(491, 'Что? Где? Когда?', 'Используя метод мозгового штурма, команда из шести игроков («знатоков») ищет в течение одной минуты правильный ответ на специально подобранный вопрос телезрителя. За правильный ответ очко получает команда знатоков, за неправильный же очко получают их противники — команда телезрителей. Побеждает команда, первой набравшая шесть очков.', 8.3, 'https://kinopoiskapiunofficial.tech/images/posters/kp/656730.jpg', 245, 39, 40, 3),
(492, 'Выжить любой ценой', 'Любите природу и путешествия? Не спешите с ответом. Сначала попробуйте остаться с ней один на один в самых неподходящих для лирики условиях, как это сделал ведущий передачи Discovery Channel «Выжить любой ценой». Бэр Гриллс, в прошлом спецназовец SAS (Special Air Service) и покоритель Эвереста, путешествует по диким и опасным уголкам планеты, демонстрируя навыки выживания в экстремальных условиях.', 8.3, 'https://kinopoiskapiunofficial.tech/images/posters/kp/450186.jpg', 243, 9, 28, 3),
(493, 'Путешествие Гордона, Джино и Фреда', 'Гордон Разми вместе с друзьями отправляется в путешествие. Каждый из его попутчиков – итальянский шеф-повар Джино Д\'Акомпо и французский метрдотель Фред Сирье – намерен доказать превосходство своей родины. Они посещают Шотландию, Италию, Францию и рассказывают об уникальных продуктах и особенностях кухни.', 8.3, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1363103.jpg', 241, 6, 28, 3),
(494, 'Взрослым не понять', 'Звезды шоу-бизнеса объединяются в команды по парам и угадывают слова и понятия, которые объясняют дети в возрасте от четырех до девяти лет.', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/5303815.jpg', 246, 1, 1, 3),
(495, 'Разрушители легенд', 'В нашей жизни существует множество разных легенд, поверий, интернетовских слухов или других мифов. И вот чтобы доказать или опровергнуть все эти истории, за дело берутся эксперты Адам Сэвидж и Джэми Хайнеман, а что из этого выходит, можно увидеть в каждом выпуске программы…', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/445124.jpg', 247, 15, 2, 3),
(496, 'Мы здесь', 'Трэвел-шоу, где знаменитые дрэг-дивы ездят по разным городам США (включая самые консервативные), знакомятся с местными представителями дрэг-культуры и устраивают с ними совместные выступления.', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1363066.jpg', 224, 14, 2, 3),
(497, 'The Ultimate Fighter', 'Конор Макгрегор возвращается в октагон, чтобы передать свои знания молодым бойцам, которые бьются за право попасть в UFC с командой опытных соперников под руководством Майкла Чендлера.', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/668250.jpg', 248, 24, 2, 3),
(498, 'Разве я вам вру?', 'Шоу, в котором две команды, возглавляемые одна Ли Маком, а другая Дэвидом Митчеллом, пытаются заставить друг друга поверить в их безумные истории.', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/676593.jpg', 228, 55, 28, 3),
(499, 'Реутов ТВ', 'Реутов ТВ — комедийная программа, подражающая региональным телевизионным каналам.', 8.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/668245.jpg', 225, 19, 1, 3),
(500, 'Эллен: Шоу Эллен ДеДженерес', 'Развлекательное ток-шоу, ведущая - несравненная Эллен ДеДженерес. В свою студию она приглашает известных личностей - актеров, певцов, спортсменов - и любит ставить их в неловкое положение. Кроме звезд, шоу полно шуток, розыгрышей и различных заданий, которые звезды должны выполнить.', 8.1, 'https://kinopoiskapiunofficial.tech/images/posters/kp/445866.jpg', 234, 15, 2, 3),
(501, 'КВН. Высшая лига', 'Популярные юмористические игры, в которых команды различных коллективов (учебных заведений, вузов, предприятий и т.д.) соревнуются в импровизациях на заданные темы, разыгрывании заранее заготовленных сцен, остроумных ответах на вопросы и т.д.', 8.1, 'https://kinopoiskapiunofficial.tech/images/posters/kp/405644.jpg', 228, 62, 40, 3),
(502, 'Прожекторперисхилтон', '«Прожектор Пэрис Хилтон» - проект Первого канала, ведущими которого стали Гарик Мартиросян, Иван Ургант, Саша Цекало и Сергей Светлаков. Это  программа, где нет ничего обязательного. Ведущие делают практически все, что хотят. Обсуждают темы, которые интересны зрителям, проводят «политинформацию» для населения. На столе в студии разложено много газет - ведь где еще, как не в свежих газетах, черпать актуальные новости, которые произошли на прошедшей неделе.', 8.1, 'https://kinopoiskapiunofficial.tech/images/posters/kp/460589.jpg', 249, 37, 1, 3),
(503, 'На выход', 'Восемь незнакомцев борются за выигрыш в 400 тысяч рублей, отвечая на вопросы ведущей.', 8.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/5265019.jpg', 238, 1, 1, 3),
(504, 'Полкино', '«Полкино» — это нескучный разговор о премьерах недели в компании трёх веселых ведущих...', 8.1, 'https://kinopoiskapiunofficial.tech/images/posters/kp/568028.jpg', 249, 19, 1, 3),
(505, 'Радио Долин', 'Антон Долин каждую неделю рассказывает о кино и не только.', 8.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4505404.jpg', 239, 21, 1, 3),
(506, 'Натурал глазами гея', 'Пятеро ведущих подбирают гардероб герою выпуска, меняют интерьер его жилья и дают советы в областях, в которых, как считается, геи разбираются лучше натуралов.', 8.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1112745.jpg', 224, 6, 2, 3),
(507, 'Лучший повар Америки', 'Множество талантливых и не очень кулинаров борются за звание «Лучший повар Америки» - их мастерство  оценивают судьи во главе с Гордоном Рамзи. Ставки высоки - 250 тыс. долларов, возможность издать свою книгу рецептов и статус Лучший повар Америки.', 8.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/579669.jpg', 238, 19, 2, 3),
(508, 'Усадьба эдвардианской эпохи', 'В начале эдвардианской эпохи в Британии проживали некоторые из самых богатых людей в мире. Среди состоятельных коммерсантов и промышленников распространилась тенденция щеголять своими богатствами... \n\nДобровольцы из числа наших современников попытаются воссоздать жизнь семейства «нуворишей» и их слуг в традиционной загородной резиденции эдвардианской эпохи, расположенной у границ Шотландии. Семья из пяти человек и 14 слуг поселятся в «Мандерстоне», где время повернется вспять, и жизнь потечет по законам безмятежного периода истории Великобритании, закончившегося с началом Первой мировой войны. Все будет исключительно по-английски: великолепный особняк, озеро для прогулок на лодках, показательная молочная ферма, чаепития, крокет и теннис в саду, лошади и экипажи в конюшне, группа людей, строго разделенных в жизни законами классовой принадлежности.', 8.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/581423.jpg', 250, 25, 28, 3),
(509, 'Рогов. Студия 24', 'Всего за сутки кардинально изменятся сразу два героя, недовольные внешним видом друг друга, и всё это произойдёт на глазах у гостей торгового центра «Мега Химки», где находится открытая студия модного проекта.\n\nВ центре внимания — братья и сёстры, супруги, друзья, коллеги и другие пары, которые хотят изменить друг друга. В начале каждого выпуска они попытаются сделать это самостоятельно и подобрать вещи на свой вкус, а позже на помощь придёт бьюти-команда Александра Рогова из лучших специалистов индустрии моды и красоты. В проекте двух героев ожидает не только внешнее преображение, но и внутренние метаморфозы: так, им предстоит пройти испытание, организованное ведущим с помощью психолога.', 8.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4320282.jpg', 224, 6, 1, 3),
(510, 'BBC: Всемирная история живописи', 'Серия «Всемирная история живописи» приглашает совершить увлекательное путешествие по знаменитым музеям и художественным галереям.\n\nА также познакомитесь с различными стилями и эпохами: от авторов древних наскальных рисунков и безымянных художников древнего мира до наиболее ярких представителей реализма, импрессионизма, модернизма и поп-арта...', 8.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/252073.jpg', 250, 68, 28, 3),
(511, '100 атлетов', '100 спортсменов и спортсменок выполняют задания на силу, скорость, ловкость и выносливость.', 8.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/5260139.jpg', 240, 1, 61, 3),
(512, 'Хуже быть не могло', 'Серия передач по одноименной книге, в которой ведущий передачи «Выжить любой ценой» применяет свои навыки в ситуациях, возможных в реальной городской жизни: аварии, пожары, нападения собак и т.д.', 8.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/505631.jpg', 243, 19, 2, 3),
(513, 'Значит, ты умеешь танцевать?', 'В мегаполисах США проводится кастинг на отбор ТОР 20 лучших танцоров, которые встретятся в финале. Количество претендентов несколько тысяч. Это реалити-шоу с профессиональными танцорами и обычными людьми.', 8.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/471829.jpg', 251, 24, 2, 3),
(514, 'Кулинарный поединок с Джейми Оливером', 'Джейми Оливер и Джимми Доэрти дружат со школьной скамьи. Оба всегда любили вкусно поесть. Теперь, когда они оба повзрослели и вернулись в родной Эссекс, они открыли небольшое кафе.', 8.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/911209.jpg', 224, 2, 28, 3),
(515, 'Стать шефом', '20 поваров-любителей проходят обучение под присмотром профессионалов и борются за приз в 1 миллион рублей и возможность стажироваться в московском мишленовском ресторане.', 8.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/5310765.jpg', 224, 1, 1, 3),
(516, 'Без границ', 'Попытка ответить на вопросы о здоровье человека, борьбе со старением и борьбе с экстремальными условиями.', 8.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4293010.jpg', 224, 3, 2, 3),
(517, 'Адам портит всё', 'Неприглядная правда о том, что дорого вашему сердцу. Адам Коновер рушит стереотипы, навязанные обществом, телевидением и соседями. Работа, секс, машины, рестораны, терроризм и благотворительность – все знания об этом подвергаются серьезному сомнению.', 8.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/934101.jpg', 252, 13, 2, 3),
(518, 'Долгий путь на север', 'Юэн Макгрегор и Чарли Бурмен пересекают Южную и Центральную Америку на электрических мотоциклах Harley-Davidson в третьей части своего эпического путешествия.', 8.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1396888.jpg', 253, 14, 28, 3),
(519, 'Ночное шоу с Джимми Фэллоном', 'Комедийное ток-шоу, каждый выпуск которого открывается монологом Фэллона и продолжается беседами со звездными гостями, забавными скетчами, играми с их участием, а также музыкальными выступлениями.', 7.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/820516.jpg', 242, 5, 2, 3),
(520, 'Рисуя с Джоном', 'Художник и музыкант Джон Лури размышляет о жизни, параллельно оттачивая свои акварельные техники.', 7.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4294914.jpg', 225, 21, 2, 3),
(521, 'Вечерний Уткин', 'Василий Уткин и его гости обсуждают главные футбольные события недели.', 7.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4958247.jpg', 254, 3, 1, 3),
(523, 'Невозможные шутники', 'Кью, Сал, Джо и Мурр – лучшие друзья, которые любят кидать друг другу вызовы на совершение самых невероятных трюков, когда-либо записанных на скрытую камеру.', 7.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/652825.jpg', 225, 7, 2, 3),
(526, 'Всё или ничего: Манчестер Сити', 'О жизни внутри и вокруг знаменитого английского футбольного клуба «Манчестер Сити».', 7.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1177693.jpg', 255, 6, 2, 3),
(527, 'В изоляции', 'Десять человек отправляются в отдаленные районы острова Ванкувер (Канада), достаточно далеко друг от друга, чтобы не вступать в контакт. У каждого из них ограниченный набор стандартного оборудования, одежды и средств оказания первой медицинской помощи. Также с собой они берут набор камер, чтобы документировать свои ежедневные переживания и эмоции. Им нужно попытаться жить в дикой природе как можно дольше, добывать пищу, искать укрытие и соседствовать с хищниками, и все это в полном одиночестве. Участники, желающие сняться с соревнования по какой-либо причине могут подать сигнал спасательной команде, используя предоставленный спутниковый телефон. Последний оставшийся участник выигрывает $ 500 000. Конкурсанты предупреждены, что шоу может длиться до года.', 7.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/929690.jpg', 256, 13, 2, 3),
(529, 'Рогов+', 'Александр Рогов работает в команде со звёздной соведущей. Каждые два выпуска Александр Рогов будет приглашать новых напарниц: известных актрис, блогеров и телеведущих. Цель шоу — помочь зрительницам получить шанс на новую жизнь.\n\nВ новом проекте к классическому мейковеру добавляются элементы ток-шоу: ведущие обсуждают историю героини и решают, как помочь ей попрощаться с давними проблемами. После чего Александр берёт на себя задачи по преображению героини, а его звёздная гостья поддерживает участницу на протяжении всей программы.', 7.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4973677.jpg', 257, 3, 1, 3),
(530, 'Ура! Пятница!', '«Ура! пятница» - самое необычное шоу из всех, которые вы видели. В нем нет привычных рамок и условностей, зато есть множество неожиданностей и сюрпризов. Нет провокационных вопросов и скандальных ответов, но есть добрый юмор и отличное настроение. И конечно, самый главный сюрприз программы - ее ведущий: абсолютная сенсация 2008 года - режиссер, продюсер, сценарист, а теперь еще и актер и самая настоящая рок-звезда - Фархан Ахтар! Среди гостей программы - суперзвезды Болливуда: Ритик Рошан, Аамир Кхан, Приянка Чопра, Дипика Падукон, Шахрукх Кхан, Риши и Ранбир Капур, Катрина Кэйф, Каран Джохар, Абишек Баччан, Шилпа Шетти и другие.', 7.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/518748.jpg', 234, 37, 75, 3),
(531, 'Проект «Подиум»', 'Двенадцать неизвестных дизайнеров одежды из разных городов Америки получают шанс прославиться на весь мир моды, и получить 100 000 долларов для раскрутки своего собственного бизнеса. Для этого им придется пройти серию нелегких испытаний в жестких условиях нехватки времени, заданной тематики и ограниченности материалов для работы.', 7.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/470777.jpg', 238, 23, 2, 3),
(532, 'Майамские чернила', 'Цикл передач о тату-салоне в городе Майами-Бич, штат Флорида. Его зовут Эми Джеймс, он мастер тату. Когда он открыл свой новый салон, он пригласил своих 3 лучших друзей, таких же мастеров тату. Вы сможете увидеть их работу здесь на Сауc-бич.', 7.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/470747.jpg', 233, 24, 2, 3),
(534, 'КликКлак шоу', 'Ведущий Руслан Усачев приглашает именитых гостей в специально подготовленный павильон площадью 1,5 тысячи квадратных метров. Их ждут забеги по липкому полу, битвы в Колизее, купание в ледяном бассейне, гонки на ходунках и другие безумные эксперименты.', 7.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/5315494.jpg', 238, 1, 1, 3),
(535, 'Рогов в деле', 'Изменить стиль, прическу, оправиться после серьезной болезни, прийти в себя после сильного потрясения — стилист Александр Рогов принимает героев своего шоу такими, какие они есть, и делает их еще лучше.', 7.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/2041754.jpg', 257, 14, 1, 3),
(536, 'По дороге с Норманом Ридусом', 'Сериал о путешествиях на мотоцикле, в котором Норман Ридус и приглашенная звезда недели путешествуют в определенную точку Америки на мотоцикле изучая местную байк-культуру и места для мотоциклистов.', 7.8, 'https://kinopoiskapiunofficial.tech/images/posters/kp/986620.jpg', 224, 50, 2, 3),
(537, 'Вайс', 'Новый документальный сериал про мир, в котором мы живем, но о котором ничего не знаем. Удивительные истории, известные личности и поездки в самые опасные места на Земле.', 7.8, 'https://kinopoiskapiunofficial.tech/images/posters/kp/762542.jpg', 259, 17, 2, 3),
(538, 'Обратный отсчёт', 'По условиям новой телеигры два участника получают 3 млн рублей, которые им предстоит сохранить. В каждом из пяти раундов их ждут интеллектуальные задачи и ограниченное время на их решение. Когда время заканчивается, счётчик начинает списывать деньги. В случае неверного ответа игроки также теряют крупную сумму. В финале звёзды играют друг против друга, а победитель забирает все деньги, которые удалось сохранить.', 7.8, 'https://kinopoiskapiunofficial.tech/images/posters/kp/5291662.jpg', 245, 1, 1, 3),
(539, 'Насекомые — гении стратегии', 'Предрассудки, окружающие насекомых, были источником многих недоразумений. Исследования показали, что количество насекомых, обогащающих землю, уменьшилось на 25% за 40 лет. Действительно ли насекомые заслуживают ненависти и недооценки со стороны людей?', 8.5, 'https://kinopoiskapiunofficial.tech/images/posters/kp/5238586.jpg', 185, 21, 61, 4),
(540, 'Маккартни 3,2,1', 'Пол Маккартни вспоминает свой творческий путь.', 8.5, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4467570.jpg', 260, 21, 2, 4),
(541, 'Дикие животные: Завоевание мегаполиса', 'В этом документальном проекте исследуются города с очень необычной перспективы — посредством глаз животных, обитающих в них. От горбатых китов, заплывающих в реку Гудзон, до колоний крупных летучих мышей в Аделаиде.', 8.5, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1260300.jpg', 185, 6, 28, 4),
(542, 'Слаймики', 'Слаймики — игрушки, живущие у Лизы дома. Они добрые, веселые и очень дружелюбные. С ними очень приятно играть, но они часто пачкают руки и одежду. Именно поэтому их не очень любит няня. И пытается от них избавиться.', 8.4, 'https://kinopoiskapiunofficial.tech/images/posters/kp/5326305.jpg', 193, 1, 76, 4),
(544, 'Элегантная вселенная', 'Научно-популярный фильм, посвящённый теории струн - наиболее плодотворному в настоящее время направлению теоретической физики. Основан на книге «Элегантная Вселенная» американского физика-теоретика Брайана Грина, который выступил в качестве ведущего этого фильма. Интервью с наиболее интересными струнными теоретиками, а также нобелевскими лауреатами Стивеном Вайнбергом и Шелдоном Глэшоу, современная компьютерная графика и простые, но довольно точные аналогии раскрывают базовые понятия теории относительности, квантовой механики и объясняют такие особенности теории струн (получившей своё развитие в М-теории), как суперсимметрия, 11-мерная Вселенная, пространства Калаби - Яу, браны и т.д.', 8.4, 'https://kinopoiskapiunofficial.tech/images/posters/kp/466416.jpg', 185, 15, 8, 4),
(545, 'Если наступит завтра', 'Героиня - скромная служащая банка Трэйси Уитни стоит на пороге счастья и успеха. Она обручена с любимым человеком, который, к тому же, баснословно богат и принадлежит к высшим кругам общества. И вот, из-за страшных и нелепых обстоятельств, все идет прахом: Трэйси оказывается в тюрьме, подставленная мафией и преданная любимым. Но её не так-то просто сломить: всю свою железную волю, острый ум и неотразимое женское обаяние она направляет на то, чтобы отомстить.', 8.4, 'https://kinopoiskapiunofficial.tech/images/posters/kp/231037.jpg', 122, 60, 2, 4),
(546, 'Русские хакеры: Начало', 'Исследование феномена русских хакеров: его зарождение в начале 1990-х и развитие в 2010-х. История погружается в жизнь самых известных хакеров, воссоздаёт цепочку событий от преступлений, наказания и до осознания масштаба происходящего. Это игра в кошки-мышки с властями России и США в эру, которая началась, когда ещё никто не знал, что интернет-преступления возможны.', 8.4, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4742511.jpg', 185, 21, 1, 4),
(547, 'Цветняшки. Игры друзей Цветняшек', 'Образовательные истории Цыпленка Пи, Волчонка У, Лисенка Айяяя, Котенка Мура и Зайчонка Скока, которые помогут малышу развивать интеллект, творческие способности, музыкальный вкус, речевое развитие, двигательные навыки и физические качества. Сделают досуг ребёнка и родителя увлекательным и полезным.', 8.4, 'https://kinopoiskapiunofficial.tech/images/posters/kp/5258278.jpg', 205, 3, 1, 4),
(549, 'Всё или ничего: «Арсенал»', 'О том, как проходил решающий сезон одного из крупнейших футбольных клубов мира.', 8.4, 'https://kinopoiskapiunofficial.tech/images/posters/kp/5023420.jpg', 261, 3, 28, 4),
(550, 'Земля больших возможностей', 'Когда-то Джастас Уолкер вместе с большой американской семьей перебрался из США в русскую Сибирь и обосновался в поселке Такучет Красноярского края. За годы фермерства Джастас обустроил в Такучете настоящее персональное хозяйство.', 8.4, 'https://kinopoiskapiunofficial.tech/images/posters/kp/5090280.jpg', 185, 3, 1, 4),
(551, 'Не могу выкинуть тебя из головы', 'Проект описывает мировую историю последнего полувека через эмоциональный опыт отдельных выдающихся личностей.', 8.4, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4380712.jpg', 206, 21, 28, 4),
(552, 'Хейди', 'После гибели родителей Хейди воспитывала тетушка. Когда девочке исполнилось 8 лет, ее привезли в горы к дедушке, который поначалу не признает внучку. Благодаря ангельскому терпению девочки и ласковым словам, сердце старика оттаивает. У Хейди появляются друзья. Однако, через некоторое время, тетушка отдает ее в богатый дом, где она должна стать компаньонкой больной девочки Клары, прикованной к инвалидной коляске...', 8.4, 'https://kinopoiskapiunofficial.tech/images/posters/kp/277688.jpg', 109, 26, 77, 4),
(553, 'Галапагосы: На краю земли', 'На уединенных островах посреди Тихого океана обитают существа, которых не встретишь более нигде в мире. Каким же образом шла эволюция на Галапагосе – от нескольких видов до богатого многообразия жизни, которое мы наблюдаем сейчас? Большинство обитателей Галапагоса являются эндемиками архипелага. Проект расскажет о важнейших вехах в ходе их эволюции, а также об изменениях окружающей их среды и о взаимодействии человека и природы.', 8.4, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1366140.jpg', 185, 6, 61, 4),
(554, 'Добро пожаловать в психушку', 'Эдди МакКенна – продавец окон с двойным остеклением. Ему 38 лет, он одинок, не любит свою работу и живет вместе со своей бабушкой в шотландском Глазго. Истинное наслаждение ему доставляет только подработка ди-джеем на радио. И пусть это всего лишь локальное радиовещание в больнице. \n\nОднажды ему предлагают восстановить радиостанцию в больнице Святого Джуда. Согласившись, Эдди становится ди-джеем в психиатрической лечебнице, где самое занимательное времяпрепровождение для пациентов – просмотр многочисленных сериалов, и больным совсем нет дела до радио. Но у Эдди сразу же появляются друзья: неуравновешенная девушка Франсин, инженер-шизофреник Фергус, страдающая навязчивым состоянием Розали и 19-летний юноша с маниакально-депрессивным психозом Кэмпбелл, тоже мечтающий стать радио-ведущим на настоящем коммерческом радио. Помогая им, Эдди помогает и себе обрести цель в жизни и понять, что настоящие психи – не всегда те, кого держат за стенами психушки.', 8.4, 'https://kinopoiskapiunofficial.tech/images/posters/kp/431133.jpg', 13, 27, 28, 4),
(555, 'Энн из Зеленых крыш', 'История о девочке-сироте, удочерённой пожилыми братом и сестрой. Наделённая пылким воображением, Энн постоянно попадает в какие-то переделки, но природное обаяние и умение располагать к себе людей всегда помогают ей с достоинством пройти все жизненные испытания.', 8.4, 'https://kinopoiskapiunofficial.tech/images/posters/kp/327449.jpg', 109, 36, 78, 4),
(556, 'Бекхэм', 'О карьере легендарного футболиста Дэвида Бекхэма.', 8.4, 'https://kinopoiskapiunofficial.tech/images/posters/kp/5053579.jpg', 262, 1, 8, 4),
(557, 'Блистательное семейство', 'Тэппей руководит одной из компаний конгломерата – сталелитейной «Ханшин Токюшу Сэйко». Предчувствуя скорый рост спроса на сталь и изделия из нее, он изобретает новые, качественные материалы, чтобы снабжать ими становящуюся на ноги японскую промышленность. Для выпуска стали нужен чугун, и в этом компания Тэппея зависит от единственного поставщика – крупнейшей металлургической компании «Тэйкоку Сэйтэцу».\n\nЧтобы стать по-настоящему независимым, Тэппею необходима собственная доменная печь, но строительство стоит огромных денег. За финансированием Тэппей решает обратиться к отцу, Дайскэ Мампё, президенту банка «Ханшин», также входящего в конгломерат Мампё. Так начинается эта история.', 8.4, 'https://kinopoiskapiunofficial.tech/images/posters/kp/402630.jpg', 13, 55, 9, 4),
(558, 'Противостояние', 'В 1979 году в одном из северных советских городов милиция расследует дело об убийстве человека, направлявшегося с золотых приисков домой. Сыщики выходят на след главного подозреваемого по имени Григорий Милинко. Но чем дальше продвигается дело, тем больше запутывается, так как выясняется, что настоящий Милинко погиб ещё на войне. Значит, кто-то украл его имя. Преступник объявлен во всесоюзный розыск, но преступления продолжаются.', 8.4, 'https://kinopoiskapiunofficial.tech/images/posters/kp/94116.jpg', 263, 36, 40, 4),
(559, 'Человеческая Вселенная', 'Профессор Брайан Кокс путешествует по земному шару и исследует вопрос, как на существование и развитие человека повлияли космические явления и события.', 8.5, 'https://kinopoiskapiunofficial.tech/images/posters/kp/893674.jpg', 185, 5, 28, 4),
(561, 'Discovery: Во Вселенную со Стивеном Хокингом', 'Знаменитый физик, профессор Стивен Хокинг, который в 30 лет оказался практически полностью парализован из-за прогрессирующей болезни, делится мыслями о самых интригующих загадках Вселенной, таких как инопланетная жизнь или путешествие во времени.', 8.5, 'https://kinopoiskapiunofficial.tech/images/posters/kp/542489.jpg', 185, 19, 28, 4),
(562, 'Кулинария как наука', 'Рассказ об основных элементах, лежащих в основе науки приготовления пищи: температуре, действии, микроорганизмах и вкусе.', 8.5, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4919166.jpg', 185, 14, 61, 4),
(563, 'Сваты. Жизнь без грима', 'Цикл документальных фильмов об актерах-исполнителях главных ролей и истории создания телевизионного сериала «Сваты». Как снималась история, что заставляло плакать и смеяться всю съемочную группу и насколько сложно быть героем такого проекта?', 8.5, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4416336.jpg', 185, 7, 1, 4),
(564, 'Планета динозавров', 'Использование уникальных современных технологий при создании этого фильма, позволяет зрителям перенестись на сотни миллионов лет назад и понаблюдать за жизнью одних из самых удивительных существ, когда-либо населявших нашу планету – динозавров. Некоторые особи из тех, о ком пойдет речь, были открыты учеными совсем недавно, в течение последних 10 лет. Перед зрителями открываются совершенно новые страницы доисторической эпохи, подробно рассказывающие о местах обитания и образе жизни этих гигантов.', 8.5, 'https://kinopoiskapiunofficial.tech/images/posters/kp/648762.jpg', 265, 7, 28, 4);
INSERT INTO `media` (`id`, `title`, `description`, `rating`, `image_url`, `genre_id`, `year_id`, `country_id`, `type_id`) VALUES
(565, 'Чудеса жизни', 'Этот сериал повествует о том, как 3.7 миллиарда лет назад некоторые фундаментальные законы породили самую сложную, разнообразную и уникальную силу во вселенной - жизнь. Свет, гравитация, время, материя и энергия послужили строительными кирпичиками всего сущего, от мельчайшего микроорганизма на Земле до самой большой галактики. В настоящее время, как предполагают, на Земле существует целых 100 миллионов различных биологических видов.', 8.5, 'https://kinopoiskapiunofficial.tech/images/posters/kp/760592.jpg', 185, 17, 28, 4),
(566, 'Насекомые, или Миллиметровый мир', 'Несмотря на крохотные размеры насекомые являются самой грозной силой природы. Рассказ об удивительных стратегиях выживания, которые насекомые выработали, чтобы приспособиться к окружающей среде, а также о том, как эти невероятные творения эволюции вносят вклад в поддержание глобальной экологии.', 8.5, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4919266.jpg', 185, 5, 61, 4),
(567, 'Стратегия выживания', 'Демонстрация невероятных и порой ошеломляющих стратегий, которые различные виды организмов используют последние четыре миллиарда лет, чтобы произвести потомство в битве за выживание.', 8.5, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1366141.jpg', 185, 16, 61, 4),
(568, 'Династии', 'Пять историй из жизни животных: пингвинов, шимпанзе, львов, гиеновидных собак и тигров. Все они ведут героическую борьбу с природными условиями и с другими животными — борьбу за выживание и будущее своей династии.', 8.5, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1226357.jpg', 185, 6, 79, 4),
(569, 'Вьетнам', 'Подробная история участия США в войне во Вьетнаме.', 8.5, 'https://kinopoiskapiunofficial.tech/images/posters/kp/775289.jpg', 201, 16, 2, 4),
(570, '1812-1815. Заграничный поход', 'В 2012 году исполнилось 200 лет со дня Бородинской битвы и изгнания из Российской империи наполеоновских войск. Картина продолжает тему Отечественной войны 1812 года и предлагает зрителям вспомнить о событиях 1813-1815 годов, которые менее известны широкой аудитории. Это рассказ о пути, пройденном русской армией от сожженной Москвы до Парижа: о сражениях при Дрездене и Кульме, о разгроме французов под Лейпцигом, о военных действиях русских войск во Франции. Зритель узнает подробности отречения Наполеона и его первой ссылки на остров Эльба, о неожиданном возвращении французского императора, о ста днях его правления и об окончательном разгроме его армии…', 8.5, 'https://kinopoiskapiunofficial.tech/images/posters/kp/913053.jpg', 266, 5, 71, 4),
(571, '12 стульев', 'Ироничное и смешное представление, в котором парочка авантюристов охотится за стульями работы мастера Гамбса.', 8.5, 'https://kinopoiskapiunofficial.tech/images/posters/kp/77270.jpg', 267, 48, 40, 4),
(572, 'Неизвестная планета Земля', 'Мы живем на планете Земля и даже не подозреваем о том, какие загадки и секреты она хранит. В этом интереснейшем проекте мы постараемся понять, что именно изучают современные ученые, какие готовятся исследования в скором времени, и почему человечество, пуская в космос исследовательские зонды, не может себе позволить спуститься на дно Марианской впадины? Авторы этого проекта пытаются раскрыть особенности современной науки, опираясь на историю и знания о перспективах на будущее.', 8.5, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1108508.jpg', 185, 6, 2, 4),
(573, 'Шок и трепет: История электричества', 'Электричество не только дает нам тепло и свет, но и обеспечивает связь во всем мире посредством интернета, теле- и радиовещания...', 8.5, 'https://kinopoiskapiunofficial.tech/images/posters/kp/661258.jpg', 185, 7, 28, 4),
(574, 'Земля: Мощь планеты', 'Перед вами невероятная история планеты Земля – единственной живой планеты во вселенной. Как же устроена наша планета? Как она работает, и что делает ее такой особенной? Исследуя великие силы, которые формируют Землю — вулканы, океан, атмосферу и лед – мы сможем узнать об их роли в истории нашей планеты. Как эти силы влияют на облик Земли, ее климат, и ее историю? Это сериал предоставляет нам удивительную возможность узнать о нашем доме как можно больше.', 8.5, 'https://kinopoiskapiunofficial.tech/images/posters/kp/408890.jpg', 185, 55, 28, 4),
(575, 'Подводная лодка', 'История боевого похода немецкой подводной лодки в 1941 году.', 8.5, 'https://kinopoiskapiunofficial.tech/images/posters/kp/228535.jpg', 46, 36, 80, 4),
(576, 'Большая перемена', 'Нестор Северов проваливается на экзамене в аспирантуру и идёт работать учителем в вечернюю школу. Он становится классным руководителем 9-го «А» - «удивительного, прекрасного, сумасшедшего» класса. Поначалу далёкий от мирской суеты Нестор Петрович начинает жить заботами своих взрослых учеников...', 8.5, 'https://kinopoiskapiunofficial.tech/images/posters/kp/85020.jpg', 16, 35, 40, 4),
(577, 'Фанни и Александр', 'История семьи Экдаль, увиденная глазами двух детей — сестры и брата Фанни и Александра. Пока семья едина и неразлучна, дети счастливы и без страха могут предаваться чудесным мечтам. С потерей близких людей в них растет чувство горечи и неприязни к миру. Но там, где Фанни пытается сохранить чистую душу, Александр замыкается в тёмном и жестоком внутреннем мирке.', 8.6, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1224674.jpg', 13, 49, 53, 4),
(578, 'Апокалипсис: Первая мировая война', 'Этот новый документальный сериал создан на основе более 500 часов восстановленных в цвете и озвученных архивных киноматериалов, большая часть которых ранее не показывалась. Мы перенесемся в эпицентр военных действий, от окопов северной Франции до менее известных фронтов в России, Сербии, Турции и Палестине, и также увидим повседневную жизнь гражданского населения в тылу.', 8.6, 'https://kinopoiskapiunofficial.tech/images/posters/kp/842865.jpg', 201, 5, 81, 4),
(579, 'The Beatles: Get Back', 'Фильм расскажет об атмосфере, царившей на студии во время записи знаменитого альбома «Let It Be», и завершится записью последнего живого концерта группы, который состоялся на крыше дома 3 на лондонской улице Сэвил-Роу 30 января 1969 года.', 8.6, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1355015.jpg', 260, 21, 82, 4),
(580, 'Враждебная планета', 'Исследование наиболее суровых для жизни уголков Земли - самых экстремальных зон жары, холода, влажности, сухости. ', 8.6, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1179101.jpg', 185, 8, 2, 4),
(581, 'Энн из Зеленых крыш: Продолжение', 'Энн прощается со своими приемными родителями из «Зеленых крыш» и уезжает в другой город, чтобы работать в престижном колледже для девочек. Еще недавно она сама была школьницей. Но теперь Энн вынуждена проявить все свое терпение и волю, чтобы заслужить авторитет среди воспитаниц. С другой стороны Энн повзрослела, в ее жизни появились трудности, которых она не знала в детстве.  Но открытое и доброе сердце юной девушки помогает ей принимать верные решения.', 8.6, 'https://kinopoiskapiunofficial.tech/images/posters/kp/325933.jpg', 268, 58, 5, 4),
(582, 'Учим географию вместе с Ам Нямом', 'Маленьким зрителям предстоит попутешествовать и узнать мир вместе с зеленым монстриком Ам Нямом.', 8.6, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4791607.jpg', 193, 16, 83, 4),
(583, 'BBC: Чудеса Солнечной системы', 'На протяжении тысячелетий люди зачарованно смотрели на звездное небо. Мы предлагаем Вам отправиться в захватывающее путешествие в глубины этого непознанного пространства, чтобы своими глазами увидеть истинную и удивительную красоту нашей Cолнечной системы.', 8.6, 'https://kinopoiskapiunofficial.tech/images/posters/kp/573738.jpg', 185, 19, 28, 4),
(584, 'Викторианская ферма', 'В рамках этого уникального проекта историк Рут Гудман и археологи Алекс Ланглэндс и Питер Джинн окунулись в жизнь викторианских фермеров и целый год прожили на эдаком застывшем во времени островке викторианской эпохи поместье Актон Скотт в английском графстве Шропшир. Весь год, от жаркого лета до глубокой зимы, они трудились, не покладая рук, используя при этом только старинные инструменты и технику из фамильной коллекции Актонов. \n\nС помощью экспертов по старинным ремеслам, герои программы заново открывают исчезнувший мир навыков и знаний эпохи королевы Виктории, и у нас на глазах восстанавливают поразительную картину этого поворотного момента в истории сельского хозяйства.', 8.6, 'https://kinopoiskapiunofficial.tech/images/posters/kp/480539.jpg', 206, 10, 28, 4),
(585, 'Сваты 6. За кадром', 'Проект покажет, как снимались самые яркие сцены сериала «Сваты 6». Главные герои документального фильма — актеры, авторы и другие члены съемочной группы — расскажут обо всех внештатных ситуациях, о комичных случаях и драматических эпизодах во время съемок.', 8.6, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4416343.jpg', 185, 17, 1, 4),
(586, 'Один литр слёз', 'Семья Икеучи владеет магазинчиком тофу и детям приходится постоянно помогать родителям в магазине, нужно рано вставать, чтобы помочь приготовить тофу до открытия, а иногда и за прилавком постоять вместо родителей. Но Айе это совсем не трудно, она успевает, и работать в магазине, и хорошо учиться. Айя поступает в престижную старшую школу, теперь родителям можно не беспокоиться за её будущее. Но жизнь готовит Айе страшный удар...', 8.6, 'https://kinopoiskapiunofficial.tech/images/posters/kp/453318.jpg', 77, 24, 9, 4),
(587, 'Голубая планета', 'Несмотря на то, что вода занимает две трети нашей планеты, о глубинах океана мы знаем меньше, чем о поверхности Луны. От известного до непознанного - новый документальный сериал «ГОЛУБАЯ ПЛАНЕТА» открывает нам всю красоту и очарование океана, поражая воображение многообразием его обитателей.\n\nСериал «ГОЛУБАЯ ПЛАНЕТА» - это всестороннее и наиболее полное исследование подводного мира. Использование новейших технологий и уникального оборудования для глубоководных съемок раскроют зрителю самые сокровенные тайны мирового океана и позволят увидеть редчайшие кадры из жизни его обитателей, о существовании которых мы могли ранее только догадываться.\n\nСериал состоит из 8 фильмов по 50 минут:\n1. Голубая планета \n2. Бездна\n3. Открытый океан \n4. Замерзшие моря\n5. Сезонные моря \n6. Коралловые моря \n7. Приливные моря \n8. Побережье \n', 8.6, 'https://kinopoiskapiunofficial.tech/images/posters/kp/252059.jpg', 185, 11, 84, 4),
(588, 'Жители океанов', 'Фильм о безграничности и свободе подводного мира, о королевстве живого разумного существа по имени Океан станет еще одной познавательной страницей в жизни нашего космоса.', 8.6, 'https://kinopoiskapiunofficial.tech/images/posters/kp/667809.jpg', 185, 7, 6, 4),
(589, 'В королевстве растений', 'В этом документальном цикле, снимавшемся в течение года, сэр Дэвид Аттенборо исследует жизнь растений и их увлекательный мир, от самых причудливых до самых прекрасных его обитателей. Используя превосходно снятые кадры в качестве наглядного сопровождения своего неповторимого стиля повествования, сэр Дэвид прослеживает историю растений от появления их на суше до наших дней, где они играют жизненно важную роль в природе. Перейдя к их временной шкале, он показывает истинную природу растений, которые не менее агрессивные и подвижные, чем животные. Всё это происходит в одном уникальном месте, мире растений в миниатюре, где представлено около 90% всех известных видов – королевских ботанических садах в Кью.', 8.6, 'https://kinopoiskapiunofficial.tech/images/posters/kp/732799.jpg', 185, 2, 28, 4),
(590, 'Время приключений: Фиона и Кейк', 'Фионна вместе со своей кошкой Кейк живет в альтернативной реальности, где нет магии. Она проводит дни в круговороте безделья, а по ночам мечтает о волшебном мире.', 8.6, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4540127.jpg', 269, 1, 2, 4),
(591, 'Долгий путь вокруг Земли', 'В 2004 году известные актёры и хорошие друзья Чарли Бурман и Юэн МакГрегор завершили кругосветное путешествие на своих BMW R 1150 GS Adventure, которые летом 2004 года обвезли их вокруг Земного шара.', 8.6, 'https://kinopoiskapiunofficial.tech/images/posters/kp/257333.jpg', 270, 23, 28, 4),
(592, 'BBC: Величайшие явления природы', 'Временами природа может удивить так, что любой самый талантливый кинорежиссёр лишь разведёт руками от зависти. Ни на одном экране вы не увидите такого безумства, такой любви и такого великолепия, которые встречаются в живой природе. И лишь она сама может открыть свои тайны. В нашей программе вы увидите как наиболее известные, так и малозаметные, но не менее интересные природные явления.', 8.6, 'https://kinopoiskapiunofficial.tech/images/posters/kp/491607.jpg', 185, 10, 8, 4),
(593, 'Вселенная Стивена Хокинга', 'Знаменитый физик и профессор, один из наиболее влиятельных и известных широкой общественности физиков-теоретиков нашего времени Стивен Хокинг делится мыслями о самых интригующих загадках Вселенной.', 8.6, 'https://kinopoiskapiunofficial.tech/images/posters/kp/635476.jpg', 185, 31, 28, 4),
(595, 'Моя Великая война. Воспоминания ветеранов', 'По статистике сегодня осталось около ста тысяч ветеранов Великой Отечественной войны. С каждым днем их, живых очевидцев, становится все меньше. Наши дети и внуки будут знать о той войне только по кинофильмам и историческим документам. Поэтому сегодня как никогда важно успеть зафиксировать живые свидетельства живых людей. Фильм Андрея Зайцева «Моя Великая война» состоит из четырех частей — четыре ветерана, четыре истории о том, что они пережили и что не могут забыть вот уже шесть десятилетий. Писатель Виктор Астафьев говорил: «Сколько солдат – столько и войн». У каждого из них – своя правда и своя война. Из этих историй, из этих разных правд, складывается большая картина, мозаика о том, какой была та война.', 8.6, 'https://kinopoiskapiunofficial.tech/images/posters/kp/745221.jpg', 185, 2, 1, 4),
(596, 'Гордость и предубеждение', 'Элизабет - одна из пяти дочерей небогатого провинциального помещика, мистера Беннета. К сожалению, в семействе нет ни одного сына, поэтому, в случае смерти мистера Беннета, все их имущество перейдет их дальнему родственнику по мужской линии. Когда по соседству появляется богатый мистер Бингли и его друг,  загадочный и еще более богатый мистер Дарси, миссис Беннет начинает питать большие надежды на скорое замужество одной из своих дочерей. Мистер Бингли обращает внимание на старшую сестру Беннет, красавицу Джейн. Но гордый мистер Дарси не одобряет увлечения друга и стремится положить ему конец, однако сам неожиданно увлекается Элизабет...', 8.8, 'https://kinopoiskapiunofficial.tech/images/posters/kp/89518.jpg', 77, 4, 28, 4),
(597, 'Михаил Горшенёв. Легенда о Короле и Шуте', 'Рассказ о российском рок-музыканте Михаиле Горшенёве, лидере культовой панк-группы «Король и шут».', 8.8, 'https://kinopoiskapiunofficial.tech/images/posters/kp/5274271.jpg', 260, 1, 1, 4),
(598, 'Крестный отец: Новелла для телевидения', 'Данный сериал представляет собой первые два фильма трилогии «Крестный отец», cмонтированные для телевидения в хронологическом порядке с добавлением дополнительных сцен.', 8.8, 'https://kinopoiskapiunofficial.tech/images/posters/kp/260992.jpg', 3, 43, 2, 4),
(599, 'История жизни', 'История Жизни, рассказанная Дэвидом Аттенборо, переносит нас в величайшее из всех приключений - путешествие по жизни. Любое животное, ведомое инстинктом, озабочено тем, чтобы оставить после себя потомство, передать свои гены последующим поколениям. Быть может для них это своеобразная, связующая нить между прошлым и будущим. \n\nПутешествие по бурным водам жизни полно страданий, трудностей и самоотверженности. Порой их поведение непредсказуемо, изысканно утончённо и исполнено нежности. Но несмотря на брошенный ими вызов стихиям природы, они борются и побеждают, передавая свою стойкость характера последующим поколениям.', 8.8, 'https://kinopoiskapiunofficial.tech/images/posters/kp/869545.jpg', 185, 5, 28, 4),
(600, 'Люди, сделавшие Землю круглой', 'Фильм посвящен главному триумфу отечественной авиации 30-х годов – сверхдальним трансполярным перелетам, которые совершили экипажи Героев Советского Союза В.П. Чкалова и М.М. Громова. В непереносимых условиях они совершили беспосадочный полет Москва - Северный полюс - Северная Америка. Рассказ построен на уникальных документах, о существовании которых ранее не было известно. Это дневники и рукописи летчика Георгия Байдукова, второго пилота экипажа Чкалова, недавно найденные членами его семьи. Именно они позволят пролить свет на достоверную историю судеб советских героев. Сейчас эти перелеты считаются главными событиями советской авиации тех лет.', 8.8, 'https://kinopoiskapiunofficial.tech/images/posters/kp/842259.jpg', 206, 13, 1, 4),
(601, 'Идеальная планета', 'О том, как силы природы — погода, океанские течения, солнечная энергия и вулканы — формируют и поддерживают огромное разнообразие жизни на планете.', 8.8, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4343547.jpg', 185, 21, 8, 4),
(602, 'Чернобыль', '26 апреля 1988 года химик Валерий Легасов, надёжно спрятав шесть аудиокассет со своими воспоминаниями, вешается у себя в квартире.\n\n26 апреля 1986 года в 1:23:45 во время проведения эксперимента по безопасности на Чернобыльской АЭС происходит взрыв реактора и пожар. Поднятые по тревоге пожарные без спецзащиты прибывают на место аварии, не подозревая, что оказались в эпицентре крупнейшей в истории человечества техногенной катастрофы. Руководство ЧАЭС уверяет Кремль, что ситуация под контролем, и радиационный фон в норме, но по настоянию академика Легасова его вместе с зампредседателя Совета Министров Борисом Щербиной отправляют разобраться в происходящем на месте.', 8.8, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1227803.jpg', 73, 8, 8, 4),
(603, 'Headspace: Руководство по медитации', 'Энди Пуддикомб, бывший буддистский монах, делится техниками медитации, а так же пользой и научными фактами, стоящими за этой осознанной практикой.', 8.8, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4316311.jpg', 272, 21, 2, 4),
(604, 'Крепость', '21 июня 1941 года, Брестская крепость. Лейтенант Андрей Кижеватов, майор Петр Гаврилов и комиссар Ефим Фомин занимались повседневными делами. Был еще мальчик-трубач Саша Акимов из полкового оркестра, который тайком покуривал и беззаветно любил девушку Веру. Никто из военнослужащих не знал, что следующим утром они станут командирами трех последних очагов сопротивления, а мальчишка — единственной связью между ними в каменном котле первого в СССР объекта нападения гитлеровских войск, Брестской крепости.', 8.7, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1378886.jpg', 91, 7, 52, 4),
(605, 'Дикая природа России', 'Совершите уникальное путешествие в самые отдаленные и неизведанные уголки России, поражающие богатством дикой природы, где можно побывать в огнедышащих кратерах вулканов и в ледовых пустынях, встретить белого медведя и амурского тигра.\n\nПростираясь на 11 часовых поясов и расположившись на территории двух континентов, от центра Европы до Тихого океана, эта огромная страна поражает своим размахом и нетронутыми природными богатствами, которые в их первозданной красоте таят необъятные Российские просторы, раскинувшиеся вдали от шумных и тесных мегаполисов - Москвы и Санкт-Петербурга. Получив уникальную возможность впервые показать Дикую природу России во всем ее многообразии, мы совершим кинопутешествие с востока на запад, через горы, пустыни, вулканы, озера, и арктические льды.  Наш удивительный шести серийный документальный фильм, снятый с использованием самой современной кинематографической техники, ярко и  красочно расскажет об уникальных природных богатствах и заповедниках этой огромной страны.', 8.7, 'https://kinopoiskapiunofficial.tech/images/posters/kp/477353.jpg', 185, 37, 41, 4),
(607, 'BBC: Планета людей', 'Люди - самые совершенные особи нашей планеты. От холодных льдов Арктики до жарких тропических джунглей они смогли приспособиться к окружающей среде и найти способы для выживания. Для этого им понадобилось проявить недюжинную изобретательность и отвагу. Они научился жить бок о бок с другими живыми существами и использовать их себе во благо.\n\n«Планета людей» - это компиляция из 80 поражающих воображение историй. Каждый эпизод рассказывает об одном из уголков нашей планеты и о тех способах и решениях, благодаря которым человек смог приспособится к зачастую самым экстремальным условиям жизни.', 8.7, 'https://kinopoiskapiunofficial.tech/images/posters/kp/591822.jpg', 185, 7, 28, 4),
(608, 'Апокалипсис: Вторая мировая война', 'Эпопея рассказывает об огромных внутренних конфликтах и трагических судьбах тех, кто вынужден был участвовать в войне, тех, кто пострадал и нес лишения из-за военных действий, и  всех тех, кто развязал и вел эту войну. \n\nВпервые в истории потери среди гражданского населения сравнялись с потерями среди военнослужащих. Перед зрителем предстанут рассекреченные кинокадры и любительская съемка эпизодов той страшной войны, которая унесла жизни 50-ти миллионов мужчин и женщин по всему миру.', 8.7, 'https://kinopoiskapiunofficial.tech/images/posters/kp/478013.jpg', 201, 10, 6, 4),
(609, 'BBC: Жизнь', 'Ошеломляющий и поражающий своей красотой, новыми открытиями и впечатлениями уникальный сериал о живой природе нашей планеты. Более 3000 съемочных дней, проведенных на каждом из земных континентов, беспрецедентная техника съемки, 130 невероятных и захватывающих дух историй из страниц животного мира, – все это и есть «Жизнь» -  история животного мира, какой Вы её еще не видели прежде!', 8.7, 'https://kinopoiskapiunofficial.tech/images/posters/kp/500289.jpg', 185, 10, 85, 4),
(611, 'Тайны Тихого океана', 'Один океан, двадцать тысяч островов, четверть общего количества воды в мире... Это южная часть Тихого океана. Его название общеизвестно, но и через 230 лет после эпического путешествия капитана Кука этот обширный океан остается малоизученным. В этой бескрайней синеве отдельные острова - приют для разнообразной редкой живности. И это один из самых чистых океанов. Бирюзовое море, острова как на открытках - похоже на земной рай. Но всё не так, как кажется...', 8.7, 'https://kinopoiskapiunofficial.tech/images/posters/kp/490455.jpg', 185, 10, 8, 4),
(612, 'Охотники', 'Настоящая драма дикой природы – поединок между хищником и жертвой. Этот новаторский документальный триллер передает накал, психологию и красоту охоты. Вместо привычных кровавых сцен здесь подробно показывают невероятные стратегии хищников и тактики, используемые жертвами ради спасения. Говорят, в природе выживает сильнейший... Сложно поверить, но чаще проигрывают хищники. Причины этих поражений и другие тонкости борьбы за выживание рассматриваются в каждом эпизоде с учетом особенностей среды обитания. Беспощадный климат севера, густые леса, опасный подводный мир, открытые просторы пустыни – каждая экосистема таит свои секреты и ловушки.', 8.7, 'https://kinopoiskapiunofficial.tech/images/posters/kp/957841.jpg', 185, 13, 28, 4),
(613, 'Кислород', 'Трое альпинистов, двое опытных восходителей и молодой новичок, отправляются в Пакистан — штурмовать высочайшие вершины мира Броуд Пик (8 051 м) и К2 (8 611 м). Они готовились к трудностям, но столкнутся с испытаниями, которые сложно было даже представить. На грани жизни и смерти, на высоте, где самое ценное — кислород.', 8.7, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4491516.jpg', 185, 3, 1, 4),
(614, 'Счастливые люди', 'Документальный фильм о трудах и днях охотников и их семей из посёлка Бахта в среднем течении реки Енисей в течение целого года.', 9.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/674243.jpg', 185, 37, 1, 4),
(615, 'Планета Земля 2', 'Дэвид Аттенборо демонстрирует невероятные по красоте пейзажи, заповедные и малоизученные уголки Земли.', 9.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1007472.jpg', 185, 50, 86, 4),
(616, 'Голубая планета 2', 'Несмотря на то, что вода занимает две трети планеты, о глубинах океана мы знаем меньше, чем о поверхности Луны. Сериал открывает всю красоту и очарование океана, поражая воображение многообразием его обитателей. Использование новейших технологий и уникального оборудования для глубоководных съёмок раскроют зрителю самые сокровенные тайны мирового океана и позволят увидеть редчайшие кадры из жизни его обитателей, о существовании которых ранее можно было только догадываться.', 9.1, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1073233.jpg', 185, 16, 86, 4),
(617, 'Astartes', 'После «Восстания Аргосы» в 482.M39, ордену Карателей Адептус Астартес поручено найти бежавших еретиков и свершить правосудие за преступления против Императора.', 9.1, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1368895.jpg', 273, 6, 87, 4),
(618, 'Космос: Пространство и время', 'Рассказ о научных открытиях, совершённых за последние столетия.', 9.1, 'https://kinopoiskapiunofficial.tech/images/posters/kp/762381.jpg', 185, 5, 2, 4),
(620, 'Зелёные животные', 'Растения — это такие же животные, у которых есть желания и воля. Растения страдают от нехватки питательных веществ, в то время как у них возникает потребность в половом размножении, чтобы распространять свою ДНК подобно животным. Растения должны более чутко реагировать на окружающую среду, потому что они не могут путешествовать; им нужно двигаться активнее, чтобы выжить. Они существуют в другом времени. Корень охотится за влагой и питательными веществами, а стебель выполняет функцию носа, отслеживающего запахи.', 9.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4913484.jpg', 185, 13, 61, 4),
(621, 'Последний танец', 'История о легенде баскетбола Майкле Джордане и команде «Чикаго Буллз» времен 1990-х годов.', 9.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1162628.jpg', 262, 14, 2, 4),
(622, 'Космос', 'Культовый учёный-астроном, астрофизик и выдающийся популяризатор науки Карл Саган ведёт рассказ, который посвящён различным научным темам от происхождения жизни до места человечества во Вселенной.', 8.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/420068.jpg', 185, 46, 8, 4),
(625, 'Семь миров, одна планета', 'Зрители отправятся в увлекательное путешествие по континентам и увидят своими глазами самобытный и уникальный мир живой природы. Миллионы лет назад невероятные силы разорвали земную кору, создав наши семь континентов — каждый со своим особенным климатом, своим ландшафтом и своей уникальной жизнью.', 8.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1288698.jpg', 185, 8, 86, 4),
(626, 'Планеты', 'Фильм из пяти эпизодов подробно рассматривает каждую планету, изучая научные теории и гипотезы о формировании и эволюции нашей солнечной системы, полученные беспилотными миссиями на планеты.', 8.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1272394.jpg', 185, 8, 28, 4),
(627, 'Евгений Гришковец: Предисловие', 'Спектакль о таинственном процессе возникновения литературы и литературного образа, который появляется из фактической биографии и из истории повседневности.', 8.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1363118.jpg', 13, 8, 1, 4),
(628, 'Ту-154. Моя легенда', 'Этот стремительный лайнер стал для нескольких поколений людей символом гражданской авиации. Огромная страна, аэропорты, вереницы огней взлетных полос и рулежных дорожек, объявления о вылетах и прилетах, задержках рейсов, а вместе с тем - тревоги ожидания, волнения встреч, радость путешествий… Все это незримо слилось c красивым пассажирским самолетом, ставшим самым популярным магистральным лайнером Советского Союза и России.', 8.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/891411.jpg', 185, 5, 1, 4),
(629, 'Антология The Beatles', 'Рассказ о жизни и творчестве великой ливерпульской четверки — The Beatles.', 8.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/383870.jpg', 274, 4, 28, 4),
(630, 'BBC: Планета Земля', 'Создатели сериала «Голубая планета» сняли новый фильм, показывающий Землю такой, какой ее еще никто не видел прежде. Невероятные по красоте пейзажи и самые заповедные и малоизученные уголки нашей планеты. Четыре года напряженной работы и беспрецедентный для документального фильма бюджет позволили создать уникальный по масштабности фильм. А революционные режимы сверхскоростной съемки и детализации картинки, сделали возможным показать великолепие нашей природы во всех подробностях.', 8.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/279548.jpg', 185, 9, 28, 4),
(631, 'Место встречи изменить нельзя', 'Убийства, засады, погони, перестрелки на фоне послевоенной Москвы. Сотрудники МУРа против таинственной и неуловимой банды «Чёрная кошка». Демобилизовавшийся офицер разведки Володя Шарапов начинает работать в отделе по борьбе с бандитизмом. Одно из первых дел, в расследовании которых он участвует, — убийство гражданки Ларисы Груздевой.', 8.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/77202.jpg', 275, 30, 40, 4),
(632, 'BBC: Замерзшая планета', 'Документальный сериал о самых отдалённых уголках нашей планеты, о местах, где экстремальные условия отрицают само существование жизни. Однако жизнь здесь не просто существует, она процветает. Приспосабливаясь и изменяясь, приобретая удивительные формы, находя неожиданные способы существования, жизнь еще раз доказывает величие и грандиозность эволюции. Вас ждут потрясающие съемки касаток во льдах, тюленей, пингвинов, полярных птиц и величественных айсбергов. И все это параллельно исследованию о меняющемся климате этих регионов.', 8.8, 'https://kinopoiskapiunofficial.tech/images/posters/kp/652564.jpg', 185, 7, 89, 4),
(633, 'Африка', 'Это новое представление ландшафтов и живых созданий дикой природы поведает в невиданном доселе ключе о горах и саваннах, вулканах и озерах, ледниках и джунглях Африки, населенных удивительными животными, пресмыкающимися, рыбами и насекомыми с необыкновенным поведением в естественной среде обитания, по-прежнему полной тайн и загадок...', 8.8, 'https://kinopoiskapiunofficial.tech/images/posters/kp/743965.jpg', 185, 17, 28, 4),
(636, 'Hot Wheels. Мегатрасса', 'Герои команды Хот Вилс построили для жителей города невероятную Мегатрассу для ежегодных городских Мегагонок. Но не обошлось без форс-мажора - на город напали дорожные пираты! Друзьям придется приложить огромные усилия, чтобы освободить Уайта и спасти жителей города от катастрофы.', 9.3, 'https://kinopoiskapiunofficial.tech/images/posters/kp/952236.jpg', 193, 13, 2, 1),
(637, 'Hot Wheels. За гранью воображения', 'В Хот Вилс появляется загадочный новый житель по имени Гарри. Он демонстрирует изобретение, которое может решить все дорожные проблемы. Новый дистанционно-управляемый радиокомплекс способен лишить жителей города всех забот и хлопот! Не все друзья уверены, что Гарри можно доверять… Оказывается, что у парнишки есть один секрет.', 9.3, 'https://kinopoiskapiunofficial.tech/images/posters/kp/962472.jpg', 193, 13, 2, 1),
(640, 'Жизнь человека. Последнее интервью', 'В марте 2018 года один из лучших хирургов-онкологов страны Андрей Павленко узнал, что у него рак желудка агрессивной формы. Как онколог, Андрей понимал, что скорее всего умрет, но решил лечиться и запустить в России публичный медиапроект «Жизнь человека» о том, как принять диагноз и бороться с онкологическими заболеваниями, что нужно делать и где искать помощь.\n\nВ ноябре 2019 года Андрей дал последнее интервью команде проекта «Жизнь человека». Этот фильм — своеобразное завещание Андрея. Послание всем, кто следил за его судьбой, онкологическим пациентам, их родственникам, и врачам.', 9.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/2500772.jpg', 185, 14, 1, 1),
(641, 'Жил-был пёс', 'Жил-был пёс. Верно служил, но выгнали его по старости. И решил он повеситься, да повстречал в лесу такого же старого волка...', 9.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/45319.jpg', 209, 57, 40, 1),
(642, 'Depeche Mode: Devotional', 'Выступление Depeche Mode 1993-го года.', 9.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/351771.jpg', 280, 26, 28, 5),
(643, 'Гамильтон', 'Рассказ о жизни американского государственного и политического деятеля Александра Гамильтона.', 9.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1003587.jpg', 281, 50, 2, 1),
(645, 'Энчантималс. Дом, милый дом', 'Юные волшебницы, обнаружив в Вандервуде потерявшуюся девочку-павлина и ее питомца, помогают им найти новый дом.', 9.1, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1101316.jpg', 189, 16, 2, 1),
(646, 'Минифорс. Новые герои', 'Приквел популярного сериала, повествующий  о создании суперкоманды Минифорс. Члены команды – очаровательные зверушки-пушистики, но за их милой внешностью скрываются настоящие отважные воины. Доктор Джереми из лаборатории Минифорс исследует «эллиниум» – неизвестное вещество, содержащее могучую силу. Зевс, капитан Армии Ящериц, рассматривает эллиниум с целью создания смертоносного оружия против человечества. Однажды он  атакует лабораторию и похищает эллиниум. Лаборатория Минифорс созывает суперкоманду – это наши знакомые Вольт, Сэмми, Макс и Люси. К ним присоединяется Анна, дочь доктора Джереми. Минифорс отправляются на борьбу с Армией Ящериц с целью вернуть эллиниум. Им предстоит множество испытаний, чтобы исполнить миссию.', 9.1, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1111028.jpg', 204, 50, 61, 1),
(648, 'Он вам не Димон', 'Рассказ о предполагаемом недвижимом имуществе председателя Правительства Российской Федерации Дмитрия Медведева.', 9.1, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1043713.jpg', 185, 16, 1, 1),
(649, 'Mylène Farmer: Stade de France', 'Грандиозное по масштабности концертное выступление французской поп дивы Милен Фармер прошедшее в Париже на стадионе Stade de France. Два завершающих турне концерта и 160 тысяч человек, которые пришли посмотреть на шоу с по настоящему голливудским размахом спецэффектов и с присуще французскому темпераменту накалу чувств. Огромная сцена располагающая на себе тонны света, звука и декораций. Звучание самых лучших песен за более чем 25 лет карьеры сопровождающихся великолепно поставленной хореографией и полной открытостью чувств самой скрытной французской певицы. Слезы и радость Милен Фармер вызывающие бурю эмоций в ответ от предано любящих ее поклонников.', 9.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/650479.jpg', 283, 10, 6, 5),
(650, 'Depeche Mode: Strange Too', 'Четвёртый видеорелиз британской группы Depeche Mode.', 9.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/328627.jpg', 276, 12, 28, 5),
(651, 'Ханс Циммер: Live on Tour', 'Известный кинокомпозитор Ханс Циммер и его первоклассные музыканты исполнили перед многотысячной публикой знаменитую музыку из голливудских блокбастеров. Это уникальный шанс увидеть художника во всем великолепии его музыкального дара и насладиться прекрасными мелодиями в кругу семьи и друзей.', 9.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1105410.jpg', 280, 16, 28, 5),
(652, 'Hullabaloo: Live at Le Zenith, Paris', 'Концертный фильм Muse.', 9.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/503097.jpg', 274, 25, 28, 5),
(655, 'Говорящий Том и друзья', 'Том - лидер группы друзей, энергичный и гениальный кот. Его идеи легендарны. Его мечты велики. Он далеко пойдет! Вместе с другом Беном в студии-гараже Том разрабатывает игры и надеется, что эта работа принесет ему мировую славу, успех и богатство. Им нужно лишь усердно трудиться и предложить миру одно крутое приложение или игру. У Тома все получится, ведь осуществить мечту ему помогают лучшие в мире друзья - Бен, Анджела, Джинджер и Хэнк.', 8.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1189947.jpg', 211, 5, 90, 2),
(656, 'Смешарики. Самые смешные серии', 'Жизнь Смешариков бьет ключом в любое время года. Зима — пора ледяных скульптур, веселых маскарадов и подарков, а летом можно играть в футбол или гонять на невероятных самоходных аппаратах. Иногда, правда, приходится бороться с гигантскими сорняками, лечить героические травмы или помогать подруге до изнеможения. Все эти истории объединяет одно — они совершенно уморительные.', 8.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4380870.jpg', 190, 21, 1, 1),
(659, 'Metallica: Live Shit - Binge & Purge, San Diego', 'Это видео с концертным материалом состоящий из трёх частей. Первая - выступление Metallica в Сиэтле 29 и 30 августа 1989 года в рамках тура «Damaged justice». Вторая - концертный материал записанный во время выступления в Сан-Диего 13 и 14 января 1992 года. Концертные записи начинаются с документального фильма «Metallimovie», снятого Адамом Дубиным . Третья часть - продолжение концерта в Сан-Диего 13 и 14 января 1992 года.', 8.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/451356.jpg', 274, 26, 2, 5),
(661, 'Ласточки Христовы', '27 декабря 2019 года парламент Черногории принял законопроект об изъятии всей церковной собственности у Сербской православной церкви. Сотни тысяч человек в Черногории встали на соборную молитву во главе с митрополитом Амфилохием (Радовичем). Митрополит вместе со своим народом за время своего служения построил и восстановил 700 храмов и монастырей. Неожиданно для всех от коронавируса умирает народный пастырь. Но его молитвы услышаны. На сороковой день после смерти владыки меняется правительство и вносит поправки в законопроект о церкви.', 8.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4756142.jpg', 185, 21, 1, 1),
(662, 'Birchpunk', 'Истории из разных городов России будущего, где технический прогресс гармонично сочетается с загадочной русской душой. Люди перемещаются на космопоездах, но на полустанках до сих пор продают жареную курицу в фольге. В городах развёрнута сверхбыстрая сеть 20G, но почтовые посылки теряются на просторах Солнечной системы. В мире будущего, где роботы стали обыденностью, Россия не готова отказаться от привычек прошлого.', 8.8, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1451274.jpg', 66, 14, 1, 2),
(663, 'А ты знаешь?', 'Сериал, который поможет ответить на самые важные для детей вопросы, которые подчас ставят в тупик самых умных родителей. А ты знаешь, как работает пожарная машина, почему рожки для мороженого в форме конуса и что происходит в стиральной машине, когда мы закрываем дверцу?', 8.8, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1186147.jpg', 286, 50, 28, 2),
(664, 'Друзья: Ещё один эпизод перед последним — Десять лет Друзей', 'Набор роликов из прошлых эпизодов перед заключительным сезоном.', 8.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/982493.jpg', 1, 23, 2, 1),
(665, 'Я — жуткая кракозябра!', 'Кракозябры — это противные, скользкие, мелкие букашки-вредители. Ну, или мы так о них думаем. А им есть что сказать в свою защиту! В каждой серии новое насекомое расскажет о себе интересные и забавные факты. Насекомые поделятся тем, как и где они живут, какие функции они выполняют, как им удаётся выживать в этом сложном мире, и как мы, люди, всё изначально неправильно о них поняли!', 8.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1167449.jpg', 193, 17, 91, 2),
(667, 'Avant que l\'ombre... à Bercy', 'Четвертый концертный тур Милен Фармер.', 8.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/487825.jpg', 283, 9, 6, 5),
(676, 'Космос: Пространство и время', 'Рассказ о научных открытиях, совершённых за последние столетия.', 9.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/762381.jpg', 185, 5, 2, 4),
(678, 'Минифорс. Новые герои', 'Приквел популярного сериала, повествующий  о создании суперкоманды Минифорс. Члены команды – очаровательные зверушки-пушистики, но за их милой внешностью скрываются настоящие отважные воины. Доктор Джереми из лаборатории Минифорс исследует «эллиниум» – неизвестное вещество, содержащее могучую силу. Зевс, капитан Армии Ящериц, рассматривает эллиниум с целью создания смертоносного оружия против человечества. Однажды он  атакует лабораторию и похищает эллиниум. Лаборатория Минифорс созывает суперкоманду – это наши знакомые Вольт, Сэмми, Макс и Люси. К ним присоединяется Анна, дочь доктора Джереми. Минифорс отправляются на борьбу с Армией Ящериц с целью вернуть эллиниум. Им предстоит множество испытаний, чтобы исполнить миссию.', 9.2, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1111028.jpg', 204, 50, 61, 1),
(683, 'Серафим — рожденный пламенным', 'Четыре раза он мог умереть. Но смерть оказывалась бессильна. Пять лет никто не видел его лица. И еще пять лет никто не слышал его голоса. А когда он заговорил, первый посетитель исцелился от неизлечимой болезни. Он мог стать богатым и знаменитым, но выбрал нищету. Он всю жизнь называл себя «убогим». Но к нему, как к последней надежде, стекались тысячи людей со всей России. Он избегал почестей и славы, но прославился на весь мир. Он жил во имя Господа. И Господь не предал Его забвению.', 9.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/542577.jpg', 287, 9, 1, 1),
(684, 'Зелёные животные', 'Растения — это такие же животные, у которых есть желания и воля. Растения страдают от нехватки питательных веществ, в то время как у них возникает потребность в половом размножении, чтобы распространять свою ДНК подобно животным. Растения должны более чутко реагировать на окружающую среду, потому что они не могут путешествовать; им нужно двигаться активнее, чтобы выжить. Они существуют в другом времени. Корень охотится за влагой и питательными веществами, а стебель выполняет функцию носа, отслеживающего запахи.', 8.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/4913484.jpg', 185, 13, 61, 4),
(685, 'Игра престолов', 'К концу подходит время благоденствия, и лето, длившееся почти десятилетие, угасает. Вокруг средоточия власти Семи королевств, Железного трона, зреет заговор, и в это непростое время король решает искать поддержки у друга юности Эддарда Старка. В мире, где все — от короля до наемника — рвутся к власти, плетут интриги и готовы вонзить нож в спину, есть место и благородству, состраданию и любви. Между тем никто не замечает пробуждение тьмы из легенд далеко на Севере — и лишь Стена защищает живых к югу от нее.', 9.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/464963.jpg', 288, 7, 8, 2),
(687, 'Моцарт. Рок-опера', 'Судьба Моцарта преподносит ему испытание: Коллоредо сменяет принца-архиепископа Зальцбурга. Новый правитель - строгий и авторитарный человек, не воспринимающий музыку молодого композитора и не терпящий его пыл и дерзость. Жизнь в Зальцбурге становится для двадцатилетнего юноши невыносимой. Он решает оставить свой родной город и уехать с матерью на поиски лучшего будущего в европейских столицах.', 8.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/647823.jpg', 289, 10, 6, 5),
(688, 'Таинственные золотые города', 'Десять тысяч лет назад народ Му населял Землю. Их научные познания были необычайно развиты. Император Му предвидел конец своего мира. Он построил семь городов в четырех углах мира, где скрывал семь величайших секретов цивилизации в надежде, что однажды будущие цивилизации начнутся там, где его народ остановился. Ученые Му решили, что только двое детей, достойных этого наследия, могут иметь к ним доступ.', 8.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/727222.jpg', 96, 2, 20, 2),
(689, 'Колобанга. Только для пользователей интернета', 'В городке Колобанга живут всем известные смайлы-колобки. Они отвечают за электронную переписку Антона и передают в сообщениях его эмоции. Жизнь колобков вполне можно было бы назвать веселой и беззаботной, если бы не одно происшествие: однажды из Колобанги похищают почтовую собачку Атоса. Пока Сыщик устраивает допросы и ищет свидетелей, смелые друзья Колобок, Умник и Чёлка пускаются в невероятную интернет-авантюру.', 8.8, 'https://kinopoiskapiunofficial.tech/images/posters/kp/940678.jpg', 203, 13, 1, 2),
(690, 'Музыкальный патруль. Сказочные песни', 'В своих песнях персонажи расскажут, о чем мечтают и грустят, чему радуются.', 8.8, 'https://kinopoiskapiunofficial.tech/images/posters/kp/5301073.jpg', 193, 21, 1, 2),
(694, 'Бунтарки', 'Портреты 30 женщин, каждая из которых по-своему революционерка. 30 женщин, которые сами написали свою судьбу и изменили мир: воительница апачей, голливудская звезда, смотрительница маяка, женщина-космонавт, императрица. Кем бы они ни были и откуда бы ни пришли, эти амбициозные дамы стремились разрушить предрассудки.', 8.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/1318977.jpg', 290, 14, 6, 2),
(708, 'Время не терпит', 'История агента Трумана Блэка, секретного сотрудника, который должен защитить правительство и корпоративные интересы в миссии, ставки в которой чрезвычайно высоки.', 9.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/734128.jpg', 13, 50, 2, 1),
(710, 'Собор Парижской Богоматери', 'Юная девушка-цыганка по имени Эсмеральда своей красотой привлекает к себе внимание мужчин. Среди них - архидьякон Собора Парижской Богоматери Фролло, молодой красавец - капитан королевских стрелков Феб и уродливый звонарь Квазимодо, воспитанник Фролло. Эсмеральда без памяти влюбляется в самого красивого из них - Феба. Он не против воспользоваться этим, несмотря на то, что у него есть невеста - Флер-де-Лис...', 8.9, 'https://kinopoiskapiunofficial.tech/images/posters/kp/367456.jpg', 291, 44, 6, 1),
(711, 'Кубокот — в школу без забот', 'Кот Кубокот рассказывает, что и как надо подготовить к школе, чем в школе занимаются, какие необычные школы бывают и многое другое.', 9.0, 'https://kinopoiskapiunofficial.tech/images/posters/kp/5366407.jpg', 193, 1, 1, 2),
(713, 'Кунг-фу кролик', 'Молодой аниматор Винсент нарисовал кролика, оживающего на страницах его альбома. Зверек оказался умным, смелым и довольно своенравным, что ставит художника в затруднительные ситуации. Разочарованный и раздраженный, Винсент решает нарисовать собаку, чтобы перехитрить кролика и поставить его на место. Однако, к разочарованию создателя, ловкому пушистику каждый раз удается перехитрить пса. Таким образом три «заклятых друга» живут вместе, превращая свою обычную жизнь в хаос, приключения, а главное — в бесконечное веселье.', 8.8, 'https://kinopoiskapiunofficial.tech/images/posters/kp/5217900.jpg', 67, 5, 37, 2);
